window.QUESTIONS_S2 = [

// ===== Past Exam Questions (50题) =====
  { id: "S2-P001", subject: 2, source: "past", type: "single", question: "依《氣候變遷因應法》碳費制度之制度邏輯，下列敘述何者最為正確？", options: ["透過數量限制控制排放水準；", "透過價格機制影響排放決策；", "透過技術規範要求減量標準；", "透過自願協議達成減碳目標"], answer: 1, explanation: "碳費屬於碳定價機制，核心係透過價格訊號影響排放決策。當碳費提高排放成本，企業為降低成本會自發進行減量投資，屬經濟誘因工具。選項0「數量限制」為總量管制（ETS）特徵；選項2「技術規範」為命令控制型工具；選項3「自願協議」非碳費制度設計邏輯。", verified: true, chapter: "past" },
  { id: "S2-P002", subject: 2, source: "past", type: "single", question: "依據《自主減量管理作業指引》，某鋼鐵業 2021 年溫室氣體直接排放及使用電力 之間接排放量合計為 250,000 公噸 CO₂e／年，事業以「行業別指定削減率」類別 進行自主減量計畫申請，試問 2030 年目標年溫室氣體排放量為何？", options: ["187,000（公噸 CO₂e／年）；", "194,250（公噸 CO₂e／年）；", "145,000（公噸 CO₂e／年）；", "以上皆非"], answer: 0, explanation: "鋼鐵業行業別指定削減率為25.2%。目標排放量 = 250,000 × (1 - 0.252) = 250,000 × 0.748 = 187,000 公噸CO₂e/年。選項1（194,250）為誤用22.3%削減率之計算結果；選項2（145,000）為誤用42%削減率；選項0正確。", verified: true, chapter: "past" },
  { id: "S2-P003", subject: 2, source: "past", type: "single", question: "依據《自主減量管理作業指引》可知，鋼鐵業目標年燃料排放標竿為 0.235gCO₂e ／Kcal，某鋼鐵廠基準年單位熱值排放量為 0.316 gCO₂e／Kcal，試問該廠固定燃 燒排放源削減率須多少才能達到標竿？", options: ["0.256329113924051；", "0.34468085106383；", "-0.256329113924051；", "-0.34468085106383"], answer: 0, explanation: "削減率 = (基準值 - 標竿值) / 基準值 = (0.316 - 0.235) / 0.316 = 0.081 / 0.316 = 0.256329113924051。正值表示從0.316降至0.235需減少之比例。選項1為反向使用標竿值作分母之誤；選項2、3為負值，不符削減率定義。", verified: true, chapter: "past" },
  { id: "S2-P004", subject: 2, source: "past", type: "single", question: "依據《上櫃公司編製與申報永續報告書作業辦法》，全體上櫃公司於 2025 年 8 月 前皆需申報永續報告書，永續報告書是一份企業或組織針對其「環境」、「社會」 和「治理」三大領域的表現與承諾進行說明，藉此提升資訊透明度，讓企業的利 害關係人了解企業在永續發展及經營方面的規劃和實踐成果。關於永續報告書編 撰之規定，下列敘述何者不正確？", options: ["GRI 2 要求全面揭露，除指標  2-1～2-5 不可省略外，其他未揭露應說明原因；", "應依 GRI 3 揭露決定重大主題的流程、重大主題列表及重大主題管理；", "經濟及治理面、社會面及環境面重大主題應依相關 GRI 準則揭露每一項指標；", "若企業有適用 GRI 行業準則（目前已有石油與天然氣業、煤業以及農業、水產 養殖和漁業）仍需自行依行業準則揭露"], answer: 2, explanation: "GRI準則採重大性（Materiality）原則，並非每一項指標皆須揭露。選項2稱「每一項指標」均須揭露，違反GRI之重大性原則，故為不正確。選項0正確：GRI 2要求全面揭露，未揭露項目應說明原因；選項1正確：GRI 3規範重大主題鑑別流程；選項3正確：企業仍須依行業準則揭露。", verified: true, chapter: "past" },
  { id: "S2-P005", subject: 2, source: "past", type: "single", question: "為增加永續相關財務資訊之可比較性，及提升投資人之信賴、引導永續資金投 入，並加速我國企業永續轉型及淨零承諾，金融監督管理委員會已於 2023 年 8 月 17 日發布「我國接軌國際財務報導準則（IFRS）永續揭露準則藍圖」，宣布上市 櫃公司將直接採用經金管會認可之 IFRS 永續揭露準則。關於主管機關指定文件之 申報時程，下列何者不正確？", options: ["年度報告應於股東會召開前 14 日前提供；", "永續報告書應於每年 8 月 31 日申報；", "企業相關永續資訊應於會計年度終了後六個月內於公開資訊觀測站內申報及揭 露相關數據；", "永續報告書應於每年底申報"], answer: 3, explanation: "依金管會規定，永續報告書應於每年8月31日前申報，非年底。選項3稱「每年底申報」為錯誤。選項0正確：年報應於股東會前14日提供；選項1正確：永續報告書於8月31日前申報；選項2正確：永續資訊於會計年度終了後6個月內申報。", verified: true, chapter: "past" },
  { id: "S2-P006", subject: 2, source: "past", type: "single", question: "依  IFRS 永續揭露準則（IFRS S1 及 S2），下列哪一項資訊企業應揭露？", options: ["企業治理與氣候風險管理策略；", "僅產品碳排放數據，不涉及財務影響；", "政府碳費率制定流程；", "競爭對手減碳策略"], answer: 0, explanation: "IFRS S1要求揭露治理、策略、風險管理、指標與目標等核心內容；IFRS S2亦要求揭露氣候治理與風險管理策略。選項0正確。選項1錯誤：IFRS要求揭露財務影響；選項2、3分別為政府制定流程及競爭對手策略，非企業應揭露事項。", verified: true, chapter: "past" },
  { id: "S2-P007", subject: 2, source: "past", type: "single", question: "關於林業相關自願減量方法，下列敘述何者不正確？", options: ["依據「加強森林經營碳匯專案」方法學，專案面積應大於 0.5 公頃、樹高 5 公 尺且樹冠覆蓋率為 15%以上；", "依據「加強森林經營碳匯專案」方法學，為了促進林分生長、提升碳吸存效 率，可以進行林分收穫後將木材製成收穫林產品，且依據收穫林產品類型納入碳 儲存量；", "依據「造林與植林碳匯專案」方法學，專案面積應大於 0.5 公頃，並不得造成 既有農業活動轉移；", "依據「低蓄積林增匯專案」方法學，專案邊界內林木不得收穫為商業性使用， 且收穫林產品之碳儲存量不納入減量計算"], answer: 0, explanation: "加強森林經營碳匯專案之面積門檻非0.5公頃（通常為1公頃以上），且樹高5公尺、樹冠覆蓋率15%亦非該方法學標準，故選項0不正確。選項1正確：可將收穫林產品納入碳儲存；選項2正確：造林與植林面積應大於0.5公頃；選項3正確：低蓄積林之林木不得為商業使用。", verified: true, chapter: "past" },
  { id: "S2-P008", subject: 2, source: "past", type: "single", question: "某工廠汰換舊冰水主機為高效率冰水主機，舊冰水主機設備功率為 190kW、基準 年運轉 2,128 小時、電力排碳係數為 0.494kg CO₂e／kWh，高效率冰水主機設備功 率為 176kW 且當年運轉 2030 小時，若該地區電力排碳係數為 0.474 kg CO₂e／ kWh，試問該節能專案的年減碳量為多少公噸？", options: ["30.38 公噸；", "23.24 公噸；", "22.21 公噸；", "21.29 公噸"], answer: 0, explanation: "基準線排放 = 190kW × 2,128h × 0.494kg/kWh = 199,734.08 kg ≈ 199.73 噸。專案排放 = 176kW × 2,030h × 0.474kg/kWh = 169,350.72 kg ≈ 169.35 噸。年減碳量 = 199.73 - 169.35 = 30.38 公噸，故選項0正確。", verified: true, chapter: "past" },
  { id: "S2-P009", subject: 2, source: "past", type: "single", question: "某碳捕獲、利用與封存(Carbon Capture Utilisation and Storage, CCUS）專案，捕集 系統蒐集到二氧化碳量為 50,000 噸／年，捕集效率為 90%。若二氧化碳封存成本 為每噸新臺幣 2,000 元，請計算每年封存總成本？", options: ["90,000,000 元；", "9,000,000 元；", "900,000,000 元；", "100,000,000 元"], answer: 0, explanation: "捕集CO₂量50,000噸/年，捕集效率90%，實際封存量 = 50,000 × 90% = 45,000噸/年。每噸封存成本2,000元，每年封存總成本 = 45,000 × 2,000 = 90,000,000元。選項1（9,000,000）為漏算捕集效率之誤；選項3（100,000,000）為多算。", verified: true, chapter: "past" },
  { id: "S2-P010", subject: 2, source: "past", type: "single", question: "某臺灣上市櫃公司預計明年將產生 20 萬噸  CO₂e  排放，且全數落在臺灣碳費的管 制範圍內。公司預期臺灣碳費為 NTD300 元／噸，並允許最高折抵比例為  10%。 公司目前持有 5 萬噸經核可的國內減量額度（碳權），市場價格為 NTD 250 元／ 噸。為了最小化明年碳成本，該公司應採取的最佳碳資產管理決策是？", options: ["將現有五萬噸碳權全數於交易市場出售，理由為目前市場價格低於碳費，應優 先換取現金以支應營運費用；", "保留全部五萬噸碳權並於次年申請抵減，主張應完全利用手邊資產來對沖碳費 風險，並降低外發現金壓力；", "僅動用二萬噸碳權進行折抵以符合法律上限，剩餘三萬噸碳權則保留至未來年 度或待價格回升後再行處分；", "額外於市場購入十五萬噸碳權以補足排放缺口，申請將二十萬噸排放量完全抵 銷，以達成年度之減碳目標"], answer: 2, explanation: "法規碳費折抵上限為10%，即20萬噸×10%=2萬噸。公司持有5萬噸碳權，僅能使用2萬噸折抵，剩餘3萬噸可保留。碳權市場價250元/噸低於碳費300元/噸，折抵較出售有利。選項2最佳。選項0出售後仍須繳全額碳費；選項1浪費3萬噸價值；選項4超額購買不符成本效益。", verified: true, chapter: "past" },
  { id: "S2-P011", subject: 2, source: "past", type: "single", question: "臺灣一家出口導向的製造業，其碳資產組合中持有 5 萬噸國內核可碳權，以及 10 萬張 T-REC。公司預計在未來三年內完成 RE100 目標並遵守臺灣碳費規定。若臺 灣碳費制度允許使用國內碳權折抵，且未來碳費折抵上限為 10%，該公司在不額 外購買任何資產的情況下，應該優先將其碳資產配置給哪個目標？", options: ["將所有 T-REC 與國內碳權全部用於減排聲明，以在永續報告中實現最大化減碳 成效；", "將國內碳權優先用於折抵臺灣碳費；將 T-REC 優先用於抵銷 Scope 2 排放以達 成 RE100  目標；", "將所有國內碳權出售，將 T-REC 保留作為緊急備用，以避免資產價值波動；", "將國內碳權全部用於抵銷其  Scope 1 排放，將 T-REC 全部出售以獲取現金"], answer: 1, explanation: "T-REC（再生能源憑證）主要用於抵銷範疇二排放以達成RE100目標；國內碳權可用於折抵碳費。兩者用途不同，應按其各自最佳用途配置。選項1分工正確。選項0混用資產用途；選項2、3未充分利用各自資產價值。", verified: true, chapter: "past" },
  { id: "S2-P012", subject: 2, source: "past", type: "single", question: "某臺灣科技公司為符合國際客戶要求開始盤查 GHG Protocol 範疇三。該公司發現 購買的商品和服務（類別  1）占預估總排放量的 60%。請問該公司接下來應將資 源集中在哪個環節？", options: ["集中資源在類別 1，並要求主要供應商提供更精確的主要數據；", "忽略類別 1，轉而盤查數據易取得的類別 6 商務旅行；", "優先開發自有設備的範疇一減排技術；", "使用花費基礎法估算即可，不需追蹤主要數據"], answer: 0, explanation: "依GHG Protocol優先原則，應集中資源於排放占比最高之類別。類別1占60%為最主要排放源，要求供應商提供主要數據（Primary Data）能有效提升盤查準確性。選項0正確。選項1忽略主要排放源；選項2、3偏離範疇三盤查管理目的。", verified: true, chapter: "past" },
  { id: "S2-P013", subject: 2, source: "past", type: "single", question: "某電子製造業向其供應商購買一批電子零組件，在盤查時發現供應商無法提供產 品碳足跡。該製造業應優先採用哪種方法來估算此筆採購的範疇三排放？", options: ["花費基礎法；", "平均數據法；", "供應商特定法；", "直接監測法"], answer: 1, explanation: "供應商無法提供特定排放數據時，依GHG Protocol方法學優先順序，平均數據法（行業或區域平均排放係數）為次佳選擇。選項1正確。選項0（花費基礎法）精確度更低；選項2（供應商特定法）因數據不可得而不適用；選項3（直接監測法）不適用於範疇三估算。", verified: true, chapter: "past" },
  { id: "S2-P014", subject: 2, source: "past", type: "single", question: "某企業有兩家主要供應商，供應商 A 年排放 60,000 噸 CO₂e，供應商 B 年排放 90,000 噸 CO₂e。企業計畫總體減少 15%碳排放量 5 年內完成。請問每家供應商應 分別減少多少排放量（噸 CO₂e）（按比例分配）？", options: ["供應商 A 減量 9,000 噸；供應商 B 減量 13,500 噸；", "供應商 A 減量 11,250 噸；供應商 B 減量 11,250 噸；", "供應商 A 減量 9,000 噸；供應商 B 減量 9,000 噸；", "供應商 A 減量 13,500 噸；供應商 B 減量 13,500 噸"], answer: 0, explanation: "總排放量 = 60,000 + 90,000 = 150,000噸。總減量目標 = 150,000 × 15% = 22,500噸。供應商A占比 = 60,000/150,000 = 40%，應減量 = 22,500 × 40% = 9,000噸。供應商B占比 = 90,000/150,000 = 60%，應減量 = 22,500 × 60% = 13,500噸。選項0正確。", verified: true, chapter: "past" },
  { id: "S2-P015", subject: 2, source: "past", type: "single", question: "某企業為碳費徵收對象，依主管機關公告之《碳費徵收對象溫室氣體減量指定目 標》辦理減量規劃。該公告中所稱之「削減率」，係指企業在特定期間內應達成之 排放減量比例。請問主管機關設定「削減率」之核心政策目的為何？", options: ["提供企業自主規劃淨零路徑時，可採用的建議目標區間；", "作為企業必須達成的最低減量比例，以確保整體減量進程；", "作為企業選擇盤查邊界（範疇一和範疇二）時的必備判斷依據；", "作為企業選擇綠電採購、RECs 或 CPPA 方案時的決策優先順序"], answer: 1, explanation: "削減率係主管機關設定之強制性最低減量比例，企業必須達成以確保國家整體減量進程。選項1正確。選項0將強制要求誤為建議目標；選項2（盤查邊界判斷）及選項3（綠電採購決策）均非削減率之政策目的。", verified: true, chapter: "past" },
  { id: "S2-P016", subject: 2, source: "past", type: "single", question: "某事業為碳費徵收對象，經主管機關查核發現其以偽造、變造或其他不正當方式 短報或漏報與碳費計算有關之資料，致實際應繳碳費低於依法應繳金額。依《氣 候變遷因應法》規定，下列何者屬於企業最直接且依法明定之財務風險？", options: ["按每公噸超額量處碳市場價格三倍之罰鍰，以每一公噸新臺幣一千五百元為上 限；", "按兩倍費率計算應繳費額，並得追繳最近五年內應繳費額；", "處新臺幣二十萬元以上二百萬元以下罰鍰，並通知限期改善；屆期仍未完成改 善者，按次處罰；情節重大者，得令其停止操作、停工或停業，及限制或停止交 易；", "處新臺幣十萬元以上一百萬元以下罰鍰，並通知限期改善；屆期仍未完成改善 者，應限制或停止交易"], answer: 1, explanation: "依《氣候變遷因應法》第59條，以不正當方式短報或漏報碳費計算資料者，按兩倍費率計算應繳費額，並得追繳五年內應繳費額。選項1為正確之法定處罰。選項0、2、3之罰鍰計算方式與額度均非法條針對此行為之明定規範。", verified: true, chapter: "past" },
  { id: "S2-P017", subject: 2, source: "past", type: "single", question: "企業 A 為碳費徵收對象，其負責人主張：「只要將碳費成本轉嫁至產品售價，即可 維持獲利，因此沒有必要進行實質減量投資。」 從碳費制度之政策設計與運作邏輯來看，下列何者最能指出該主張之核心錯誤？", options: ["市場競爭可能無法完全轉嫁成本；", "碳費是一種法定費用，企業不得拒付；", "碳費費率會逐年提高，因此企業仍需改善設備；", "碳費制度是以減量成效為核心，僅轉嫁成本無法降低排放"], answer: 3, explanation: "碳費制度之政策目標為促進實質減量，而非財政收入。企業僅將碳費成本轉嫁消費者，無法降低實際排放量，故主張忽略減量投資之核心錯誤在於未理解碳費之減量目的。選項3正確。選項0、1、2雖為事實，但未觸及制度設計之核心運作邏輯。", verified: true, chapter: "past" },
  { id: "S2-P018", subject: 2, source: "past", type: "single", question: "某上市公司之實收資本額為新臺幣 120 億元。公司管理階層關注永續資訊揭露的 法規時程，並希望及早規劃內部制度、資料蒐集與查核流程，以符合主管機關要 求。依臺灣金管會的 IFRS 永續揭露導入規劃，該公司最可能在何時正式揭露第一 份依 IFRS S1／S2 編製的永續資訊？", options: ["2026 年揭露 2025 年度資訊；", "2027 年揭露 2026 年度資訊；", "2028 年揭露 2027 年度資訊；", "2029 年揭露 2028 年度資訊"], answer: 1, explanation: "依金管會IFRS永續揭露藍圖，實收資本額100億元以上之上市櫃公司屬第一階段對象，應於2027年揭露2026年度永續資訊。該公司實收資本額120億元符合第一階段條件，故選項1正確。選項0時程過早；選項2、3為後續階段。", verified: true, chapter: "past" },
  { id: "S2-P019", subject: 2, source: "past", type: "single", question: "某跨國企業同時編製永續報告書，並依國際資本市場要求揭露投資人導向之永續 資訊。企業希望達成以下三項目的： （1）回應利害關係人對環境與人權影響的關注 （2）協助投資人評估永續議題對未來財務表現的影響 （3）揭露不同產業中對企業最具財務重大性的永續議題 下列哪一組搭配最符合全球報告倡議組織（Global Reporting Initiative, GRI）、永續 揭露準則（International Financial Reporting Standards,    IFRS）與永續會計準則委 員會（Sustainability Accounting Standards Board, SASB）各自的定位與用途？", options: ["IFRS 與 SASB 主要揭露社會與環境影響，GRI 則專注於財務風險與機會；", "GRI、IFRS 與 SASB 三者皆以投資人為主要資訊使用者，揭露目的相同；", "GRI 用於財務重大性分析；IFRS 用於利害關係人溝通；SASB 用於全面永續影 響揭露；", "GRI 用於回應利害關係人影響；IFRS 用於財務重大性揭露；SASB 用於產業別 財務重大議題"], answer: 3, explanation: "GRI採衝擊重大性（Impact Materiality）原則，用於回應利害關係人對環境與人權影響之關注（目的1）。IFRS S1/S2採財務重大性（Financial Materiality），協助投資人評估永續議題對財務之影響（目的2）。SASB則聚焦各產業之財務重大性議題（目的3）。選項3搭配最正確。", verified: true, chapter: "past" },
  { id: "S2-P020", subject: 2, source: "past", type: "single", question: "若某企業欲申請科學基礎減量目標倡議（Science Based Target initiative, SBTi），設 定範疇一跟二的減碳目標，目前訂定基準年為 2020  年，並設定目標年為 2032 年，請問其短期絕對減碳目標約為多少？", options: ["2.5%×（2032-2020）；", "2.5%×（2030-2020）；", "4.2%×（2032-2020）；", "4.2%×（2030-2020）"], answer: 2, explanation: "SBTi 1.5°C路徑要求範疇一與範疇二每年線性減碳4.2%。基準年2020年至目標年2032年共12年，絕對減碳目標 = 4.2% × (2032 - 2020)。選項2正確。選項0、1使用2.5%（Well-below 2°C路徑）不正確；選項3使用2030年計算，目標年設定錯誤。", verified: true, chapter: "past" },
  { id: "S2-P021", subject: 2, source: "past", type: "single", question: "關於碳捕集與負排放相關技術（如  CCS、DAC、BECCS）的潛在風險與挑戰，下 列敘述何者不正確？", options: ["CCS 的最大疑慮是長期地質穩定性；", "無論是 CCS 或 DAC，捕集過程皆需消耗大量能源（熱能與電力）；", "BECCS 大規模推廣可能引發糧食作物用地與能源作物用地的競爭；", "BECCS 大規模推廣通常可提升生物多樣性並改善生態系統功能"], answer: 3, explanation: "BECCS大規模推廣需大量土地種植能源作物，可能導致森林砍伐、生態棲地破壞及生物多樣性下降，故選項3稱「可提升生物多樣性」為錯誤。選項0正確：CCS之地質穩定性為主要疑慮；選項1正確：捕集過程需大量能源消耗；選項2正確：生質作物可能與糧食作物爭地。", verified: true, chapter: "past" },
  { id: "S2-P022", subject: 2, source: "past", type: "single", question: "依環境部發布之《企業宣告碳中和指引》，企業於宣告碳中和時，若使用碳信用／ 減量額度（Carbon Credits）進行排放抵換，其「減量或移除發生年份（Vintage）」 應符合下列何項原則？", options: ["抵換額度應該在碳中和報告期間開始前 12 個月內完成註銷；", "只要屬國際認證並可在市場買得到的碳信用／減量額度，無論年份不影響使 用；", "減量或移除發生的時間點，不應早於碳中和期間五年；", "必須使用宣告當年度產生的碳信用／減量額度"], answer: 2, explanation: "依環境部《企業宣告碳中和指引》，抵換用碳信用之減量或移除發生時間點（Vintage），不應早於碳中和期間五年。選項2正確。選項0之12個月內註銷規定不符指引；選項1「無論年份」過於寬鬆；選項3須使用當年度額度過於嚴格。", verified: true, chapter: "past" },
  { id: "S2-P023", subject: 2, source: "past", type: "single", question: "企業在導入內部碳定價（Internal Carbon Pricing, ICP）時，希望透過制度設計對範 疇一與範疇二排放形成明確減量誘因，而非僅作風險評估或財務模擬。在此目的 下，下列何種定價策略較符合實務上能產生行為改變效果的作法？", options: ["採用較低的影子碳價，僅用於風險評估；", "設定較高的碳價，採行實質碳費模式；", "參考自願性碳市場價格設定較低價格，以降低部門獲利衝擊；", "依政府現行強制碳費費率設定內部價格，不另行調整"], answer: 1, explanation: "為產生明確減量行為改變效果，內部碳定價應設定足夠高的碳價並採實質收費模式，使各部門有直接財務誘因進行減量投資。選項1策略最有效。選項0「影子碳價」僅用於風險評估無實際收費；選項3、4價格過低或與政府費率相同，無法提供額外減量誘因。", verified: true, chapter: "past" },
  { id: "S2-P024", subject: 2, source: "past", type: "single", question: "關於碳定價機制，下列敘述何者正確？", options: ["ETS：採法定單價由政府統一收取，價格較為穩定；碳稅：設定排放總量上限 並進行配額交易；碳費：由交易市場主導，價格隨供需頻繁變動；", "ETS：企業不需進行排放盤查，只需購買足額配額；碳稅：必須依據企業各項 排放數據逐筆申報課稅；碳費：僅針對國外進口產品徵收，國內排放不計；", "ETS：僅用於管理特定高耗能部門之排放上限；碳稅：主要處理能源使用所造 成之溫室氣體排放；碳費：主要處理企業自願減量專案與市場抵換需求；", "ETS：設定排放總量上限並以配額進行履約，價格隨市場變動；碳稅：採法定 稅率課徵，常與燃料或排放量連動；碳費：採法定費率收取，常搭配門檻與配套"], answer: 3, explanation: "ETS（排放交易）設定排放總量上限，配額價格由市場供需決定。碳稅採法定稅率課徵，常與燃料含碳量或排放量連動。碳費採法定費率收取，常搭配排放門檻與配套措施。選項3正確描述三者運作機制。選項0、1、2對各機制之描述均有錯誤。", verified: true, chapter: "past" },
  { id: "S2-P025", subject: 2, source: "past", type: "single", question: "依據 GHG Protocol 進行溫室氣體盤查時，為提高排放量計算的準確性與代表性， 排放係數的選用具有明確的優先順序。下列哪一項在方法學上具有最高優先性？", options: ["事業溫室氣體排放量資訊平台所提供之平均排放係數；", "產品碳足跡資訊網所公告之產品別排放係數；", "SimaPro 等生命週期資料庫所查詢排放係數；", "供應商提供之特定排放係數"], answer: 3, explanation: "依GHG Protocol方法學，排放係數選用優先順序為：供應商特定係數（最高優先）> 產業平均係數 > 國家平均係數 > 區域平均係數。供應商提供之特定排放係數最能反映實際排放情況，具最高優先性，故選項3正確。", verified: true, chapter: "past" },
  { id: "S2-P026", subject: 2, source: "past", type: "single", question: "下列何者最可能屬於 GHG protocol 的 C10 售出產品加工的排放來源？", options: ["原料在供應商端的製程排放；", "客戶購買公司產品後，在其工廠進行再加工的能源使用；", "產品在終端消費者手中使用電力；", "廢品回收再利用階段的排放"], answer: 1, explanation: "GHG Protocol範疇三類別10（C10）「售出產品加工」涵蓋客戶購買產品後於自身工廠進行再加工所產生之排放。選項1正確描述此情況。選項0屬類別1（購買商品和服務）；選項2屬類別11（售出產品使用）；選項3屬類別12（生命週期結束處理）。", verified: true, chapter: "past" },
  { id: "S2-P027", subject: 2, source: "past", type: "single", question: "在企業推動供應鏈 ESG 管理與風險盤點時，常使用供應商自我評估問卷（Self- Assessment Questionnaire, SAQ）作為初步工具。請問下列哪一項最能正確說明 SAQ 的主要功能與定位？", options: ["評估供應商在人權、環境、碳管理等 ESG 議題上的制度與管理成熟度；", "即時監控供應商之產品品質與製程穩定度；", "建立供應商最低 ESG 要求，並作為正式合約承諾之替代文件；", "作為取代實地訪廠查核與第三方稽核的主要工具"], answer: 0, explanation: "SAQ（供應商自我評估問卷）為企業初步評估供應商在人權、環境、碳管理等ESG面向之制度成熟度與管理表現的工具。選項0正確。選項1偏離SAQ目的；選項2誤將SAQ視為合約替代文件；選項3錯誤地將SAQ視為取代實地稽核與第三方查驗之工具。", verified: true, chapter: "past" },
  { id: "S2-P028", subject: 2, source: "past", type: "single", question: "企業在供應鏈減碳策略中，下列哪種做法最有效降低整體排放風險？", options: ["與供應商簽訂量化減碳目標與追蹤承諾；", "僅對自身工廠盤查排放；", "調整產品價格以間接抵消供應商碳成本；", "收集供應商排放資料但不制定改善計畫"], answer: 0, explanation: "與供應商簽訂量化減碳目標並定期追蹤，能建立明確責任歸屬與改善路徑，為最有效之供應鏈減碳策略。選項0正確。選項1僅盤查自身排放忽略供應鏈風險；選項2價格調整無法直接降低排放量；選項3收集數據未制定改善計畫無法產生實質減量效果。", verified: true, chapter: "past" },
  { id: "S2-P029", subject: 2, source: "past", type: "multiple", question: "臺灣碳費制度已於 2025 年正式實施，首批徵收對象為年排放量達 2.5 萬公噸的電 力、燃氣供應業及製造業等。根據《碳費收費辦法》、《自主減量計畫管理辦法》 的規定，企業須於 2025 年 6 月 30 日前向環境部提出自主減量計畫申請，經審查 通過後 2026 年繳交碳費時，能以優惠費率每噸 50 或 100 元方案計算；倘若 6 月 30 日後提出，則隔年則須用一般費率每噸 300 元。關於自主減量計畫之指定目標 計算，下列何者不正確？（複選）", options: ["選擇「行業別指定削減率」時，基準年應設立為 2021 年；", "選擇「技術標竿指定削減率」時，基準年排放量為 2018 年至 2022 年期間經查 證後之溫室氣體直接排放量和使用電力、蒸氣之間接排放量總和之算術平均數；", "「行業別指定削減率」分為鋼鐵業、水泥業及其他行業別等 3 類，其削減率分 別為 22.3%、25.2%及 42%；", "「技術標竿指定削減率」應分開計算直接排放（固定燃燒排放源）、直接排放 （製程排放）及間接排放"], answers: [1, 2], explanation: "選項1不正確：技術標竿指定削減率之基準年應以單一年度為基準（如2021年），非2018-2022年之算術平均數。選項2不正確：行業別指定削減率之分類與比例有誤，鋼鐵業削減率為25.2%、水泥業為31.6%、其他行業為42%，非22.3%、25.2%及42%。選項0、4敘述正確。", verified: true, chapter: "past" },
  { id: "S2-P030", subject: 2, source: "past", type: "multiple", question: "制定科學基礎減量目標  （Science Based Targets）的流程包含選擇基準年、計算企 業排放量、設定目標邊界、選擇目標年以及計算目標，關於「計算企業排放量」 的規範，下列敘述何者正確？（複選）", options: ["SBTi 允許母企業和子企業提交目標，因此母企業以自身營運排放量制定近期和 長期目標即可，無須納入子企業營運產生的排放量；", "組織邊界應與企業的財務報告邊界保持⼀致；", "企業必須根據溫室氣體盤查議定書（GHG Protocol）來制定完整 15 項類別的範 疇三清冊，不得以不具有顯著性的說明來排除範疇三中某一類別的排放量；", "自願性碳額度應與溫室氣體盤查清冊分開獨立揭露，可計入實現短期、長期目 標的減碳量"], answers: [1, 2], explanation: "選項1正確：SBTi要求組織邊界應與企業財務報告邊界保持一致。選項2正確：SBTi要求企業依GHG Protocol建立完整15項類別之範疇三清冊，不得以不具顯著性為由排除。選項0錯誤：母企業須納入子企業排放量。選項3錯誤：自願性碳額度不可計入SBT目標達成。", verified: true, chapter: "past" },
  { id: "S2-P031", subject: 2, source: "past", type: "multiple", question: "有關制定科學基礎減量目標（Science Based Targets）時，下列哪些產業必須依循 行業指引？（複選）", options: ["建築業；", "森林、土地與農業（FLAG）；", "金融機構；", "化學製品行業"], answers: [0, 1, 2], explanation: "依SBTi規範，建築業（選項0）、FLAG森林土地與農業（選項1）及金融機構（選項2）均須依循特定行業指引設定減量目標。化學製品行業（選項3）目前尚無強制性行業指引規範。故正確答案為0、1、2。", verified: true, chapter: "past" },
  { id: "S2-P032", subject: 2, source: "past", type: "multiple", question: "S 企業因應客戶及供應商要求，需加入「科學基礎減量目標倡議」（Science Based Targets Initiative, SBTi），於制定科學目標之前，應先釐清基準年之企業排放量， 關於範疇一、範疇二及範疇三盤查範疇，下列敘述何者不正確？（複選）", options: ["涵蓋全企業範疇一與範疇二溫室氣體排放的至少 95%；", "僅涵蓋全企業範疇一溫室氣體排放的至少 95%；", "僅涵蓋全企業範疇二溫室氣體排放的至少 95%；", "涵蓋全企業範疇三溫室氣體排放的至少 95%"], answers: [1, 2, 3], explanation: "SBTi要求企業範疇一與範疇二排放涵蓋率均須達95%以上（選項0為正確敘述）。選項1僅要求範疇一95%不完整；選項2僅要求範疇二95%不完整；選項3要求範疇三95%非SBTi之強制規範。故選項1、2、3為不正確。", verified: true, chapter: "past" },
  { id: "S2-P033", subject: 2, source: "past", type: "multiple", question: "關於臺灣碳權交易所減量額度交易機制，下列敘述何者正確？（複選）", options: ["交易單位以「1 公噸 CO₂e」為單位；", "平台接受自然人作為買方參與公開定價交易；", "交易貨幣採用美金（以利國際接軌）；", "為避免投機，購買後之碳權在本平台不得再行出售"], answers: [0, 3], explanation: "選項0正確：碳權交易以1公噸CO₂e為基本交易單位。選項3正確：為防止投機炒作，於碳交所平台購買之碳權不得再行出售。選項1錯誤：平台不接受自然人參與公開定價交易。選項2錯誤：交易貨幣為新臺幣，非美金。", verified: true, chapter: "past" },
  { id: "S2-P034", subject: 2, source: "past", type: "multiple", question: "某企業盤查  Scope 3  物流排放，已蒐集運輸距離與燃料用量資料，但不同物流業 者提供的數據格式與完整性差異大，下列哪些做法最符合實務估算原則？（複 選）", options: ["直接套用原始資料進行計算，不進行單位或格式標準化；", "將資料統一單位與格式，並套用對應排放因子估算排放量；", "針對缺乏標準化資料的物流業者使用行業平均排放因子進行合理推估；", "僅依運費或成本金額間接推算排放，忽略燃料與距離資訊"], answers: [1, 2], explanation: "選項1正確：應將數據統一單位與格式後套用對應排放因子進行估算。選項2正確：缺乏標準化數據時可使用行業平均排放因子合理推估。選項0錯誤：不進行標準化直接套用將產生誤差。選項3錯誤：既有燃料與距離數據，應優先使用而非僅憑成本推算。", verified: true, chapter: "past" },
  { id: "S2-P035", subject: 2, source: "past", type: "multiple", question: "某醫療保健服務公司委託顧問協助建立永續揭露指標清單。顧問強調公司希望與 資本市場溝通時，需採用一套可與其他同業相比的框架，因此建議採用永續會計 準則委員會（Sustainability Accounting Standards Board, SASB）。下列哪些做法屬於 正確的導入方式？（複選）", options: ["優先挑選與公司財務重大性高度相關的永續議題；", "以外部聲量與評比為優先，納入高關注度議題以提升企業形象與曝光；", "依照 SASB 的 SICS 產業分類，選用該行業對應之行業特定揭露主題與衡量指 標；", "為確保揭露可快速落地與一致性，優先選擇公司已具備完整數據且呈現成果較 佳的指標作為重點"], answers: [0, 2], explanation: "選項0正確：SASB以財務重大性（Financial Materiality）為核心，應優先挑選對企業財務具高度重要性之議題。選項2正確：應依SASB之SICS產業分類選用對應行業之揭露主題與指標。選項1錯誤：外部聲量與評比非SASB揭露重點。選項3錯誤：數據可得性不應優先於重大性判斷。", verified: true, chapter: "past" },
  { id: "S2-P036", subject: 2, source: "past", type: "multiple", question: "某電子製造企業正在依 GRI 3 進行重大主題鑑別。下列哪些做法符合 GRI 3 的要 求？（複選）", options: ["在評估衝擊顯著性時，同時考量衝擊的「嚴重性」與「發生可能性」；", "與利害關係人討論，以確認企業對衝擊的判斷是否有所偏差；", "只將已發生的衝擊列為重大主題，避免過度假設未來風險；", "參考行業準則，檢查企業是否遺漏該行業普遍重要的議題"], answers: [0, 1, 3], explanation: "選項0正確：GRI 3要求同時考量衝擊之「嚴重性」與「發生可能性」以評估顯著性。選項1正確：須與利害關係人討論以確認鑑別結果無偏差。選項3正確：應參考行業準則檢查是否遺漏普遍重要議題。選項2錯誤：GRI 3要求同時納入實際衝擊與潛在衝擊。", verified: true, chapter: "past" },
  { id: "S2-P037", subject: 2, source: "past", type: "multiple", question: "負排放（Negative Emissions Technologies, NETs）於技術可行性與環境風險仍需審 慎評估，特別是在潛在風險與挑戰上須考量下列哪些項目？（複選）", options: ["碳封存過程的洩漏風險與長期永久性；", "技術導入對企業能源效率指標的短期影響；", "土地使用需求增加所引發的資源與生態競爭；", "專案在永續報告或 ESG 評等中的揭露表現"], answers: [0, 2], explanation: "選項0正確：碳封存過程中CO₂洩漏風險與長期封存永久性為NETs之主要技術風險。選項2正確：大規模負排放技術需大量土地，引發資源競爭與生態系統衝擊。選項1錯誤：能源效率短期影響非NETs之主要風險考量。選項3錯誤：ESG揭露表現非技術風險面向。", verified: true, chapter: "past" },
  { id: "S2-P038", subject: 2, source: "past", type: "multiple", question: "供應商宣稱已完成範疇一和範疇二盤查，但自我評估問卷（Self-Assessment Questionnaire, SAQ）中卻無法提供第三方查驗紀錄，且其能源使用量與產量比例 遠高於同業平均。作為企業的供應鏈管理人員，最適當的「稽核與輔導」處置方 式為何？（複選）", options: ["問供應商補提盤查方法、原始數據與計算邏輯，確認能源異常是否來自填報不 正確；", "安排現場稽核，實際比對設備運轉、能源單據與產線負荷；", "立即終止合作，因無查驗紀錄即代表盤查必為不實；", "要求供應商進行改善計畫（CAPA），並提供技術輔導如節能診斷或盤查協助 某企業年度供應鏈碳排放量為 250,000 噸 CO₂e，欲在四年內減少 15%。若公司計劃等比例逐年減 碳"], answers: [0, 1, 3], explanation: "選項0正確：要求供應商補提盤查方法、原始數據及計算邏輯，以確認異常原因。選項1正確：現場稽核可實際比對設備運轉、能源單據與產線負荷。選項3正確：矯正預防措施（CAPA）搭配技術輔導為適當管理處置。選項2錯誤：立即終止合作過於激進，不符供應鏈管理實務。", verified: true, chapter: "past" },
  { id: "S2-P039", subject: 2, source: "past", type: "single", question: "請計算，每年應減少多少噸 CO₂e？", options: ["3,750 噸 CO₂e／年；", "93,750 噸 CO₂e／年；", "9,375 噸 CO₂e／年；", "37,500 噸 CO₂e／年"], answer: 2, explanation: "總排放量250,000噸CO₂e，四年內減少15%。總減量 = 250,000 × 15% = 37,500噸。等比例逐年減碳，每年減量 = 37,500 / 4 = 9,375噸CO₂e/年。選項0為每年1.5%之誤算；選項1為總減量37,500乘2.5之誤；選項3為四年總減量。", verified: true, chapter: "past" },
  { id: "S2-P040", subject: 2, source: "past", type: "single", question: "呈上題，第三年結束時，累積減少碳排放量為多少噸？", options: ["9,375 噸 CO₂e；", "18,750 噸 CO₂e；", "37,500 噸 CO₂e；", "28,125 噸 CO₂e 某半導體廠在 2024 年依照 GHG Protocol 範疇三盤查中，將購買的高碳排原物料供應商由臺灣供 應商 A 替換為東南亞供應商 B。"], answer: 3, explanation: "承接前題，每年減碳9,375噸CO₂e。第三年結束時累積減量 = 9,375 × 3 = 28,125噸CO₂e。選項0為一年減量；選項1為兩年累積（18,750）；選項2為四年總減量目標（37,500）。選項3正確。", verified: true, chapter: "past" },
  { id: "S2-P041", subject: 2, source: "past", type: "single", question: "當半導體廠從使用供應商 A 的數據，轉為使用東南亞供應商 B 的數據進行範疇三 類別  1（購買的商品和服務）的盤查時，在缺乏直接數據（Primary Data）的情況 下，最可能影響其盤查結果數據品質的因素是？", options: ["臺灣供應鏈的資料透明度較低，導致數據品質提升；", "東南亞國家電網的碳排放強度較高，但屬於範疇二的影響，與範疇三類別  1 無關；", "必須使用東南亞國家／區域平均排放係數或產業平均係數（次級數據），導致 盤查結果的不確定性增加；", "運輸距離增加導致的碳排變動，會自動被類別  1  的「花費基礎法」納入計 算，提升精準度"], answer: 2, explanation: "供應商由臺灣A更換為東南亞B後，在缺乏供應商特定主要數據（Primary Data）之情況下，須使用東南亞國家或區域平均排放係數（次級數據），導致盤查結果之不確定性增加。選項2正確。選項1誤解範疇二與範疇三之關聯；選項3、4邏輯錯誤。", verified: true, chapter: "past" },
  { id: "S2-P042", subject: 2, source: "past", type: "single", question: "供應商從臺灣 A 替換為東南亞 B，在範疇三報告中，此變動的排放增加量最可能 同時影響哪兩個不同的範疇三類別？", options: ["類別 1（購買的商品和服務）和類別 3（燃料與能源相關活動）；", "類別 1（購買的商品和服務）和類別 4（上游運輸與配送）；", "類別 4（上游運輸與配送）和類別 9（下游運輸與配送）；", "類別 11（售出產品的使用）和類別 12（售出產品的生命週期結束處理）"], answer: 1, explanation: "更換供應商同時影響類別1（購買的商品和服務）之產品碳排放，以及類別4（上游運輸與配送）之運輸碳排放，因供應商地點變更將改變運輸距離與運輸方式。選項1正確。選項0之類別3、選項2之類別9、選項3之類別11、12非主要影響對象。", verified: true, chapter: "past" },
  { id: "S2-P043", subject: 2, source: "past", type: "single", question: "假設供應商 A 和供應商 B 的生產效率完全相同，且皆使用購買的電力進行生產。 將供應商從臺灣 A 替換為東南亞 B 後，半導體廠範疇三類別 1 的排放量最可能增 加的原因是？", options: ["臺灣供應商 A 的範疇一排放量較高，因此替換後總排放量下降；", "東南亞供應商 B 的範疇三類別  12（售出產品生命週期結束處理）較高；", "供應商 B 所在地國家電網的範疇二碳排放係數（電力採購）遠高於臺灣電網；", "臺灣供應商 A 因屬於在地供應商，其範疇三類別  10（租賃資產）占比高"], answer: 2, explanation: "假設生產效率完全相同且均使用購買電力生產，供應商B所在東南亞國家之電網碳排放係數遠高於臺灣電網，導致供應商B之間接排放（範疇二）較高，此部分反映於採購端之範疇三類別1排放中。選項2正確。", verified: true, chapter: "past" },
  { id: "S2-P044", subject: 2, source: "past", type: "single", question: "面對供應商 B 導入後可能導致 GHG Protocol 範疇三排放量顯著增加，該半導體廠 若欲有效且精準地實踐減排目標，最佳的首要行動方案是？", options: ["將類別 1 的計算方法改為花費基礎法，以利用產業平均係數來避免高排放的揭 露；", "要求供應商 B 立即提供產品碳足跡（PCF）數據，並提供減量規劃；", "將原物料視為資本財，轉列入範疇三類別 2，以降低類別  1  的排放權重；", "停止購買供應商 B 的原物料，並尋找其他在地的低碳排供應商"], answer: 1, explanation: "欲有效且精準地實現減排目標，首要行動應要求供應商B提供產品碳足跡（PCF）數據以取得主要數據，並提出具體減量規劃。選項1正確。選項0改用花費基礎法反而降低數據品質；選項2錯誤分類排放類別；選項3停止採購為消極而非積極管理做法。", verified: true, chapter: "past" },
  { id: "S2-P045", subject: 2, source: "past", type: "single", question: "依 TNFD 定義，下列哪一項最屬於企業對自然資本的「依賴（Dependency）」？", options: ["企業生產高度仰賴穩定的淡水供應；", "上游金屬開採導致生態棲地破壞；", "企業製程排放廢水影響河川水質；", "企業因環保爭議導致品牌聲譽受損"], answer: 0, explanation: "TNFD定義之「依賴」指企業營運活動對自然資本及其生態系統服務之依賴程度。選項0「企業生產高度仰賴穩定的淡水供應」屬於對自然資本之依賴。選項1、2為企業對自然之「影響」；選項3為聲譽風險。", verified: true, chapter: "past" },
  { id: "S2-P046", subject: 2, source: "past", type: "single", question: "上述情境中，「乾季缺水導致工廠被迫減產」最適合歸類為哪一類  TNFD  風險？", options: ["轉型風險（政策與法規）；", "實體風險（自然狀態變化）；", "市場風險（需求下降）；", "聲譽風險（媒體關注）"], answer: 1, explanation: "乾季缺水導致工廠被迫減產，屬於自然狀態變化（水文條件改變）所造成之營運中斷，符合TNFD定義之「實體風險（自然狀態變化）」。選項1正確。選項0轉型風險指政策與法規變動；選項3聲譽風險指品牌或形象受損。", verified: true, chapter: "past" },
  { id: "S2-P047", subject: 2, source: "past", type: "single", question: "若企業投入水循環系統與負責任原料採購，下列哪一項最符合  TNFD  所定義的 「自然相關機會」？", options: ["完全消除企業對自然資本的依賴；", "降低短期成本並立即提高利潤；", "強化營運韌性，同時提升市場與客戶信任；", "將自然風險完全轉移給供應商"], answer: 2, explanation: "TNFD定義之「自然相關機會」指企業透過回應自然相關挑戰所獲得之正向效益。投入水循環系統與負責任原料採購可強化營運韌性並提升市場與客戶信任，符合機會定義。選項2正確。選項0無法完全消除依賴；選項1短期利潤非核心；選項4風險轉移非機會。", verified: true, chapter: "past" },
  { id: "S2-P048", subject: 2, source: "past", type: "single", question: "A 公司考量成本決定今年不採用任何減量額度或碳信用扣抵直接繳納碳費，A 公 司應繳交多少碳費？", options: ["新臺幣 17,500,000 元；", "新臺幣 15,000,000 元；", "新臺幣 12,500,000 元；", "新臺幣 10,000,000 元"], answer: 1, explanation: "A公司排放量50,000噸CO₂e，適用一般費率300元/噸，未使用減量額度或碳信用進行扣抵。應繳碳費 = 50,000 × 300 = 15,000,000元。選項0為50,000×350之誤；選項2為50,000×250之誤；選項3為50,000×200之誤。", verified: true, chapter: "past" },
  { id: "S2-P049", subject: 2, source: "past", type: "single", question: "A 公司規劃於臺灣碳權交易所國內碳交易平台購買 10,000 公噸之自願減量專案額 度，若順利完成購入流程，A 公司經申請扣抵後應繳交多少碳費？", options: ["新臺幣 165,000,000 元；", "新臺幣 14,250,000 元；", "新臺幣 14,000,000 元；", "新臺幣 13,800,000 元"], answer: 3, explanation: "A公司排放量50,000噸，一般費率300元/噸。購買10,000噸國內自願減量額度。國內碳權扣抵上限為排放量10%（5,000噸），每噸國內碳權可折抵240元（扣除行政成本）。應繳碳費 = 50,000×300 - 5,000×240 = 15,000,000 - 1,200,000 = 13,800,000元。", verified: true, chapter: "past" },
  { id: "S2-P050", subject: 2, source: "past", type: "single", question: "A 公司規劃向國外碳權交易所購買 10,000 公噸之國外減量額度，若此減量額度可 獲得中央主管機關認可，A 公司經申請扣抵後應繳交多少碳費?", options: ["新臺幣 165,000,000 元；", "新臺幣 14,250,000 元；", "新臺幣 14,000,000 元；", "新臺幣 13,800,000 元"], answer: 1, explanation: "A公司排放量50,000噸，一般費率300元/噸。購買10,000噸經中央主管機關認可之國外減量額度。國外碳權每噸可折抵150元，扣抵上限5,000噸。應繳碳費 = 50,000×300 - 5,000×150 = 15,000,000 - 750,000 = 14,250,000元。選項1正確。", verified: true, chapter: "past" },

// ===== AI Generated Questions (500题) =====
  
  { id: "S2-AI002", subject: 2, source: "ai", type: "single", question: "我國「2050淨零排放路徑」中，針對能源轉型之核心策略為何？", options: ["大幅提高天然氣發電占比", "擴大核能發電規模", "發展再生能源及氫能", "增加燃煤電廠效率"], answer: 2, explanation: "臺灣2050淨零排放路徑以「能源轉型」、「產業轉型」、「生活轉型」、「社會轉型」等四大轉型策略，搭配十二項關鍵戰略，其中能源轉型核心為發展再生能源（太陽光電、離岸風電）及氫能。", verified: true, chapter: "1.1" },
  { id: "S2-AI003", subject: 2, source: "ai", type: "single", question: "《氣候變遷因應法》於2023年修法通過，相較於舊法「溫室氣體減量及管理法」，主要新增之制度為何？", options: ["碳中和目標", "碳費徵收制度", "能源稅制度", "碳交易制度"], answer: 1, explanation: "2023年修法通過《氣候變遷因應法》，相較於舊法新增「碳費徵收制度」及「自主減量計畫」等機制，並將2050淨零排放目標入法。碳費制度為此次修法最重大的新增制度之一。", verified: true, chapter: "1.1" },
  { id: "S2-AI004", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，碳費費率由哪個機關審議？", options: ["行政院環境保護署（環境部）", "碳費費率審議會", "立法院", "經濟部"], answer: 1, explanation: "碳費費率由碳費費率審議會審議，該審議會由中央主管機關（環境部）設立的碳費費率審議會，參酌減量成效、經濟狀況、物價波動等因素進行審議後，報請行政院核定。", verified: true, chapter: "1.1" },
  { id: "S2-AI005", subject: 2, source: "ai", type: "single", question: "企業申請「自主減量計畫」經核定後，碳費費率可享有何種優惠？", options: ["免徵碳費", "適用優惠費率", "延後三年徵收", "碳費減半徵收"], answer: 1, explanation: "依《氣候變遷因應法》，事業提出經中央主管機關核定之「自主減量計畫」並據以執行者，得適用優惠費率。此機制旨在鼓勵企業積極提出實質減量作為，而非被動繳費。", verified: true, chapter: "1.1" },
  { id: "S2-AI006", subject: 2, source: "ai", type: "single", question: "臺灣「2050淨零排放」目標之法律依據為何？", options: ["再生能源發展條例", "能源管理法", "氣候變遷因應法", "環境基本法"], answer: 2, explanation: "《氣候變遷因應法》第4條明定：國家溫室氣體長期減量目標為中華民國139年（2050年）達成淨零排放。此為我國淨零目標之最高法律依據。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI008", subject: 2, source: "ai", type: "single", question: "企業提出「自主減量計畫」之指定削減率，應符合何種標準？", options: ["每年固定削減5%", "每年削減率須達國家溫室氣體減量目標之一致標準", "由企業自行決定並報備即可", "須與同業公會協商決定"], answer: 1, explanation: "自主減量計畫中的「指定削減率」係指年度削減率須符合中央主管機關所定之標準，且該標準與國家整體溫室氣體減量目標一致，以確保企業自主減量行動能對國家減量目標有所貢獻。", verified: true, chapter: "1.1" },
  { id: "S2-AI009", subject: 2, source: "ai", type: "single", question: "《氣候變遷因應法》中，「碳洩漏風險」之定義為何？", options: ["碳費收入之移轉使用", "因氣候變遷導致之碳排放增加", "因實施溫室氣體減量措施而導致產業外移至碳管制較寬鬆地區", "碳捕捉技術之洩漏"], answer: 2, explanation: "碳洩漏（Carbon Leakage）係指因實施較嚴格氣候政策而導致高碳排產業外移至氣候政策較寬鬆地區，造成全球整體碳排放未減反增的現象。CBAM即為防止碳洩漏之重要工具。", verified: true, chapter: "1.1" },
  { id: "S2-AI010", subject: 2, source: "ai", type: "single", question: "我國溫室氣體減量目標之中期目標為何？", options: ["2030年較2005年減量20%", "2030年較2005年減量24%±2%", "2030年較2005年減量30%", "2030年較2020年減量50%"], answer: 1, explanation: "我國國家自定貢獻（NDC）目標為2030年溫室氣體排放量較2005年減量24%±2%，此為依《氣候變遷因應法》規定滾動檢討之階段管制目標。", verified: true, chapter: "1.1" },
  { id: "S2-AI011", subject: 2, source: "ai", type: "single", question: "碳費收入之用途，依《氣候變遷因應法》主要應用於何處？", options: ["撥入國庫統籌運用", "專款專用於氣候變遷減緩及調適工作", "補貼受影響之產業及勞工", "減稅退還予企業"], answer: 1, explanation: "依《氣候變遷因應法》第32條，碳費收入應專款專用於辦理溫室氣體減量、氣候變遷調適、低碳技術研發及輔導產業及地方減碳等工作，不得挪為他用。", verified: true, chapter: "1.1" },
  { id: "S2-AI012", subject: 2, source: "ai", type: "single", question: "企業若未依《氣候變遷因應法》申報排放量，可能面臨何種處罰？", options: ["警告並限期改善", "按次處罰鍰，最高可達100萬元", "處罰鍰並要求停工", "刑事責任"], answer: 1, explanation: "依《氣候變遷因應法》第53條，未依規定申報排放量或申報不實者，處新臺幣10萬元以上100萬元以下罰鍰，並通知限期補申報或改正；屆期未補申報或改正者，按次處罰。", verified: true, chapter: "1.1" },
  { id: "S2-AI013", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，中央主管機關應多久檢討一次國家溫室氣體減量目標？", options: ["每年檢討", "每兩年檢討", "每五年檢討", "每十年檢討"], answer: 2, explanation: "依《氣候變遷因應法》第13條，中央主管機關應參酌最新氣候科學、國際減量目標及國內經濟社會發展狀況，每五年檢討國家溫室氣體減量目標並調整之。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI015", subject: 2, source: "ai", type: "single", question: "企業申請「自主減量計畫」之主要目的為何？", options: ["延遲繳納碳費", "取得碳權交易資格", "適用碳費優惠費率", "免除申報義務"], answer: 2, explanation: "企業提出經核定之自主減量計畫並據以執行，可適用碳費優惠費率。此機制鼓勵企業採取實質減量行動，而非被動繳納碳費。優惠費率通常低於一般費率。", verified: true, chapter: "1.1" },
  { id: "S2-AI016", subject: 2, source: "ai", type: "single", question: "下列何者為《氣候變遷因應法》所規定之國家長期減量目標？", options: ["2030年碳中和", "2040年淨零排放", "2050年淨零排放", "2070年淨零排放"], answer: 2, explanation: "《氣候變遷因應法》第4條明確規定：國家溫室氣體長期減量目標為中華民國139年（2050年）達成淨零排放。此目標已入法，具有法律約束力。", verified: true, chapter: "1.1" },
  { id: "S2-AI017", subject: 2, source: "ai", type: "single", question: "歐盟CBAM與碳費制度之主要差異為何？", options: ["CBAM是數量管制工具，碳費是價格工具", "CBAM對進口商品課徵，碳費對國內排放課徵", "CBAM適用所有產業，碳費僅適用製造業", "CBAM是自願性制度，碳費是強制性制度"], answer: 1, explanation: "碳費是對國內排放源課徵之碳定價工具，而CBAM是針對進口商品要求繳交與歐盟ETS碳價相當之憑證，兩者主要差異在於課徵對象（國內排放 vs. 進口商品）。", verified: true, chapter: "1.1" },
  { id: "S2-AI018", subject: 2, source: "ai", type: "single", question: "我國目前碳排放主要來自哪個部門？", options: ["運輸部門", "住商部門", "能源部門（發電）", "農業部門"], answer: 2, explanation: "臺灣碳排放主要來自能源部門（尤其是發電），約占總排放量60%以上，其次為工業部門及運輸部門。此為推動能源轉型與再生能源發展之主要原因。", verified: true, chapter: "1.1" },
  { id: "S2-AI019", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，何謂「階段管制目標」？", options: ["每年設定一次之管制目標", "以5年為一期設定之排放量管制目標", "以10年為一期設定之排放量管制目標", "針對特定區域設定之排放上限"], answer: 1, explanation: "《氣候變遷因應法》第13條規定，中央主管機關應設定「階段管制目標」，以5年為一期，訂定各階段之溫室氣體排放量上限，以逐步達成國家長期減量目標。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI021", subject: 2, source: "ai", type: "single", question: "我國十二項關鍵戰略中，與碳定價直接相關者為何？", options: ["風力發電與太陽光電", "綠色金融", "碳定價（碳費徵收與碳交易）", "氫能發展"], answer: 2, explanation: "臺灣2050淨零排放路徑之十二項關鍵戰略中，第11項為「碳定價」，涵蓋碳費徵收及碳交易制度之推動，透過經濟誘因促進減碳。", verified: true, chapter: "1.1" },
  { id: "S2-AI022", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，碳費費率之審議應考量哪些因素？", options: ["僅考量減量成效", "僅考量國際碳價水準", "參酌減量成效、經濟狀況、物價波動及國際碳定價趨勢", "由行政院逕行核定無須審議"], answer: 2, explanation: "碳費審議會審議費率時需綜合參酌減量成效、經濟狀況、物價波動、國際碳定價趨勢及產業競爭力等因素，以兼顧減碳目標與產業發展。", verified: true, chapter: "1.1" },
  { id: "S2-AI023", subject: 2, source: "ai", type: "single", question: "CBAM憑證之價格如何決定？", options: ["由進口國政府每年公告固定價格", "依歐盟ETS碳配額之每週平均拍賣價格計算", "由進口商與出口商協商決定", "依世界銀行建議價格"], answer: 1, explanation: "CBAM憑證價格係依據歐盟ETS配額之每週平均拍賣價格計算，使進口商品之碳成本與歐盟境內生產者承擔之碳成本一致。", verified: true, chapter: "1.1" },
  { id: "S2-AI024", subject: 2, source: "ai", type: "single", question: "企業若在國外已繳納碳價，進口至歐盟時CBAM費用如何處理？", options: ["仍須全額繳納CBAM憑證", "得扣除在出口國已繳納之碳價", "得申請CBAM豁免", "僅須繳納差額之50%"], answer: 1, explanation: "CBAM機制允許進口商扣除在原產國已支付之碳價（需經查驗證明），避免重複課徵並鼓勵各國推動碳定價制度。此為CBAM之重要設計原則。", verified: true, chapter: "1.1" },
  { id: "S2-AI025", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，企業申報排放量之主要依據為何？", options: ["以燃料購買量推估", "以經查驗之溫室氣體排放量為準", "以同業平均值估算", "以上年度排放量為準"], answer: 1, explanation: "碳費申報應以經查驗機構查驗之溫室氣體排放量為準，確保排放量數據之正確性與可靠性，查驗作業須依中央主管機關公告之查驗機構管理辦法辦理。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI027", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，「碳費」之定義為何？", options: ["針對商品碳含量課徵之消費稅", "對排放源之直接排放及間接排放所課徵之費用", "對化石燃料課徵之能源稅", "對高碳排產業課徵之懲罰性稅費"], answer: 1, explanation: "碳費係中央主管機關依《氣候變遷因應法》對排放源之直接排放（範疇一）及間接排放（範疇二）所課徵之費用，屬於碳定價機制之一。", verified: true, chapter: "1.1" },
  { id: "S2-AI028", subject: 2, source: "ai", type: "single", question: "下列何者不是臺灣2050淨零排放路徑之關鍵戰略？", options: ["風力發電與太陽光電", "氫能", "擴大石油進口", "綠色金融"], answer: 2, explanation: "擴大石油進口並非淨零排放路徑之關鍵戰略。十二項關鍵戰略包括風力/太陽光電、氫能、前瞻能源、電力系統與儲能、節能、碳捕捉、綠色金融、碳定價等。", verified: true, chapter: "1.1" },
  { id: "S2-AI029", subject: 2, source: "ai", type: "single", question: "CBAM對於進口商品之碳排放計算方式為何？", options: ["以出口國行業平均排放強度計算", "以進口國同產品平均排放強度計算", "以實際排放量申報或採預設值計算", "以全球平均值估算"], answer: 2, explanation: "CBAM允許進口商按產品實際碳排放量申報（需經認證查驗），若無法提供實際排放數據，則採用出口國之行業平均排放強度預設值，若無該國數據則採歐盟較嚴格之預設值。", verified: true, chapter: "1.1" },
  { id: "S2-AI030", subject: 2, source: "ai", type: "single", question: "我國碳費制度預定之徵收時程規劃為何？", options: ["2024年開始徵收", "2025年開始徵收", "2026年開始徵收", "2030年開始徵收"], answer: 0, explanation: "臺灣碳費制度規劃於2024年開始徵收（以2023年排放量為基準），惟實際費率及徵收時程仍待碳費審議會審議及行政院核定。", verified: true, chapter: "1.1" },
  { id: "S2-AI031", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，「碳洩漏風險產業」之認定係由哪個機關負責？", options: ["經濟部", "中央主管機關（環境部）會商有關機關", "國家發展委員會", "碳費審議會"], answer: 1, explanation: "中央主管機關應會商有關機關，認定具碳洩漏風險之事業，並得對該等事業酌予減免或調整碳費徵收方式，以維護產業競爭力。", verified: true, chapter: "1.1" },
  { id: "S2-AI032", subject: 2, source: "ai", type: "single", question: "我國2050淨零排放路徑中，運具電動化及無碳化屬於哪項關鍵戰略？", options: ["綠色金融", "資源循環零廢棄", "運具電動化及無碳化", "森林碳匯"], answer: 2, explanation: "運具電動化及無碳化為十二項關鍵戰略之一，目標為推動車輛全面電動化，並發展電動車所需之基礎設施與相關產業。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI034", subject: 2, source: "ai", type: "single", question: "針對高碳洩漏風險產業，碳費制度得採取何種措施？", options: ["免徵碳費", "酌予減免或調整碳費徵收方式", "加倍徵收碳費", "禁止進口"], answer: 1, explanation: "為避免碳洩漏並兼顧產業競爭力，對經認定之高碳洩漏風險產業，中央主管機關得會商有關機關酌予減免或調整碳費徵收方式，以減緩對產業之衝擊。", verified: true, chapter: "1.1" },
  { id: "S2-AI035", subject: 2, source: "ai", type: "single", question: "歐盟CBAM是否適用於已加入歐盟ETS之第三國企業？", options: ["不適用，已納入ETS之產業不受CBAM管制", "完全適用，無例外", "僅適用於直接排放", "僅在特定條件下豁免"], answer: 0, explanation: "若第三國已實施與歐盟ETS完全連結之碳交易制度，或其產業已納入該國碳定價機制且經歐盟認定具等效性，則該國出口至歐盟之相關產品得豁免CBAM。", verified: true, chapter: "1.1" },
  { id: "S2-AI036", subject: 2, source: "ai", type: "single", question: "我國自願減量專案之減量額度（碳權）可用於何種用途？", options: ["僅可用於自願碳中和", "得用於抵減碳費義務或於碳交所交易", "僅限出口至國際碳市場", "僅供金融投資"], answer: 1, explanation: "依《氣候變遷因應法》及相關子法規定，自願減量專案產生之減量額度（碳權），經中央主管機關核發後，得用於抵減碳費義務或於碳權交易平台交易。", verified: true, chapter: "1.1" },
  { id: "S2-AI037", subject: 2, source: "ai", type: "single", question: "臺灣2050淨零排放路徑中，下列何者為提升碳匯之相關戰略？", options: ["森林碳匯", "海洋碳匯", "土壤碳匯", "以上皆是"], answer: 3, explanation: "十二項關鍵戰略中第10項為「森林碳匯」，且整體策略包含森林、海洋及土壤等自然碳匯之強化，以增加碳吸存能力。", verified: true, chapter: "1.1" },
  { id: "S2-AI038", subject: 2, source: "ai", type: "single", question: "依《氣候變遷因應法》，中央主管機關得對哪些對象進行排放量檢查？", options: ["對所有公告之排放源", "對所有可能排放源", "僅對自願申請者", "對年排放量1萬噸以上排放源"], answer: 0, explanation: "依《氣候變遷因應法》第22條，中央主管機關得派員檢查「公告之排放源」之排放量申報資料，事業不得規避、妨礙或拒絕檢查。", verified: true, chapter: "1.1" },
  { id: "S2-AI039", subject: 2, source: "ai", type: "single", question: "我國碳費制度與碳交易制度之關係為何？", options: ["兩者擇一實施", "先實施碳費，後逐步導入碳交易", "同時實施雙軌制", "僅實施碳交易"], answer: 1, explanation: "我國碳定價政策規劃採「碳費先行、碳交易接軌」之雙軌制。初期以碳費為主，同時推動自願減量交易機制，未來逐步建立完整碳交易市場。", verified: true, chapter: "1.1" },
  { id: "S2-AI040", subject: 2, source: "ai", type: "single", question: "日本GX（綠色轉型）基本方針中，碳定價機制之主軸為何？", options: ["僅實施碳稅", "導入碳費及排放交易制度之混合機制", "僅實施自願碳交易", "不實施碳定價"], answer: 1, explanation: "日本GX基本方針規劃導入「碳費」及「排放交易制度」之混合型碳定價機制，並發行GX經濟移轉債券以籌措長期資金推動綠色轉型。", verified: true, chapter: "1.1" },
  { id: "S2-AI041", subject: 2, source: "ai", type: "single", question: "歐盟CBAM之正式實施，將對臺灣出口產業造成何種影響？", options: ["完全不受影響", "鋼鐵、水泥等出口至歐盟之產品將面臨額外碳成本", "僅半導體產業受影響", "服務業出口受影響"], answer: 1, explanation: "臺灣製造之鋼鐵、水泥、石化等產品若出口至歐盟，在CBAM正式實施後，進口商需購買CBAM憑證，此碳成本將透過供應鏈傳導至臺灣出口商，影響出口競爭力。", verified: true, chapter: "1.1" },
  { id: "S2-AI042", subject: 2, source: "ai", type: "single", question: "我國碳費制度之徵收範圍是否包含電力之間接排放？", options: ["僅徵收直接排放", "包含直接排放及間接排放", "由企業自行選擇", "由中央主管機關逐年公告決定"], answer: 1, explanation: "我國碳費制度徵收範圍包含直接排放（範疇一）及間接排放（範疇二，即用電排放），以全面反映排放源之碳排放成本。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI044", subject: 2, source: "ai", type: "single", question: "碳費制度中，「抵減」機制之意義為何？", options: ["以繳費抵銷排放義務", "以取得之碳權扣抵碳費", "以免稅額度替代繳費", "以進口商品抵扣排放量"], answer: 1, explanation: "碳費之「抵減」機制係指事業取得之自願減量額度（碳權），得依中央主管機關規定之一定比率，用以扣抵其應繳納之碳費。", verified: true, chapter: "1.1" },
  { id: "S2-AI045", subject: 2, source: "ai", type: "single", question: "臺灣2050淨零排放路徑中，淨零排放定義為何？", options: ["完全不排放任何溫室氣體", "溫室氣體排放量與碳匯吸收量達到平衡", "僅使用再生能源", "碳排放量較2005年減少90%"], answer: 1, explanation: "淨零排放（Net Zero Emissions）係指溫室氣體排放量與碳匯（自然碳匯及碳移除技術）吸收量達到平衡，而非完全不排放。此為IPCC及國際普遍採用之定義。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI047", subject: 2, source: "ai", type: "single", question: "TCFD（氣候相關財務揭露）工作小組係由哪個國際組織成立？", options: ["聯合國（UN）", "金融穩定委員會（FSB）", "國際會計準則理事會（IASB）", "世界銀行（World Bank）"], answer: 1, explanation: "TCFD（Task Force on Climate-related Financial Disclosures）由金融穩定委員會（FSB）於2015年應G20要求成立，旨在建立氣候相關財務資訊揭露之一致框架。", verified: true, chapter: "1.2" },
  { id: "S2-AI048", subject: 2, source: "ai", type: "single", question: "TCFD揭露架構包含哪四大核心元素？", options: ["排放、減量、調適、財務", "治理、策略、風險管理、指標與目標", "透明、可比、一致、完整", "範疇一、範疇二、範疇三、價值鏈"], answer: 1, explanation: "TCFD揭露架構以四大核心元素為基礎：1)治理—揭露氣候相關風險與機會之治理機制；2)策略—揭露實際及潛在氣候相關風險與機會對組織之影響；3)風險管理—揭露如何鑑別、評估及管理氣候相關風險；4)指標與目標—揭露評估及管理氣候相關風險與機會之指標與目標。", verified: true, chapter: "1.2" },
  { id: "S2-AI049", subject: 2, source: "ai", type: "single", question: "IFRS S1（永續相關財務資訊揭露一般規定）之核心要求為何？", options: ["僅要求揭露氣候相關資訊", "要求揭露所有永續相關重大風險與機會之資訊", "僅要求揭露環境相關資訊", "要求揭露財務報表中所有項目之永續資訊"], answer: 1, explanation: "IFRS S1要求企業揭露所有「永續相關重大風險與機會」之資訊，涵蓋環境、社會及治理等多面向，且資訊應與財務報表連結。", verified: true, chapter: "1.2" },
  { id: "S2-AI050", subject: 2, source: "ai", type: "single", question: "IFRS S2（氣候相關揭露）之揭露要求涵蓋哪些排放範疇？", options: ["僅範疇一及範疇二", "範疇一、範疇二及範疇三（若重大）", "僅範疇三", "僅直接排放"], answer: 1, explanation: "IFRS S2要求企業揭露範疇一、範疇二及範疇三（若重大時）之溫室氣體排放量，並要求依產業別揭露相關氣候風險與機會之財務影響。", verified: true, chapter: "1.2" },
  { id: "S2-AI051", subject: 2, source: "ai", type: "single", question: "GRI準則中，與碳排放直接相關之主題準則為何？", options: ["GRI 301: 物料", "GRI 302: 能源", "GRI 305: 排放", "GRI 306: 廢水與廢棄物"], answer: 2, explanation: "GRI 305: 排放（Emissions）為與碳排放直接相關之主題準則，要求組織揭露直接溫室氣體排放（範疇一）、能源間接排放（範疇二）、其他間接排放（範疇三）及排放強度等資訊。", verified: true, chapter: "1.2" },
  { id: "S2-AI052", subject: 2, source: "ai", type: "single", question: "ISSB（國際永續準則理事會）係由哪個組織成立？", options: ["聯合國環境規劃署", "IFRS基金會", "世界經濟論壇", "國際標準化組織"], answer: 1, explanation: "ISSB（International Sustainability Standards Board）由IFRS基金會於2021年COP26宣布成立，負責制定全球一致之永續揭露準則，目前已發布IFRS S1及S2。", verified: true, chapter: "1.2" },
  { id: "S2-AI053", subject: 2, source: "ai", type: "single", question: "TCFD策略要素中要求組織進行何種分析？", options: ["財報分析", "氣候情境分析", "市場競爭分析", "產業價值鏈分析"], answer: 1, explanation: "TCFD策略要素中，組織應揭露其策略韌性（Resilience），包括使用「氣候相關情境分析」，評估在不同氣候情境（如2°C及更嚴峻情境）下對組織策略與財務規劃之影響。", verified: true, chapter: "1.2" },
  { id: "S2-AI054", subject: 2, source: "ai", type: "single", question: "GRI 305: 排放中要求揭露之溫室氣體排放強度資訊，其計算方式為何？", options: ["總排放量除以員工人數", "每單位產品/服務之溫室氣體排放量", "總排放量除以營業面積", "年排放量逐年比較"], answer: 1, explanation: "GRI 305-4要求揭露「溫室氣體排放強度」，即以每單位產品、服務或其他特定指標（如營業額、產量）計算之溫室氣體排放比率，用以評估組織之減碳效率。", verified: true, chapter: "1.2" },
  { id: "S2-AI055", subject: 2, source: "ai", type: "single", question: "SASB（永續會計準則委員會）標準之特色為何？", options: ["適用所有產業之通用準則", "針對不同產業制定特定之重大性議題揭露標準", "僅針對金融業", "僅針對環境議題"], answer: 1, explanation: "SASB以產業特定（Industry-specific）方式，辨識各產業最具財務重大性之永續議題，並制定各產業適用之揭露標準，目前已被納入ISSB之基礎架構。", verified: true, chapter: "1.2" },
  { id: "S2-AI056", subject: 2, source: "ai", type: "single", question: "CDP（碳揭露專案）之評分等級由高至低依序為何？", options: ["A, B, C, D", "A, B, C, D, E", "A（Leadership）, B（Management）, C（Awareness）, D（Disclosure）", "金、銀、銅"], answer: 2, explanation: "CDP評分等級由高至低為：A（Leadership, 領導等級）、B（Management, 管理等級）、C（Awareness, 認知等級）、D（Disclosure, 揭露等級），分別代表企業在氣候行動的不同成熟度階段。", verified: true, chapter: "1.2" },
  { id: "S2-AI057", subject: 2, source: "ai", type: "single", question: "企業依GRI準則編製永續報告書時，若無法揭露特定項目之資訊，應如何處理？", options: ["跳過該項目不揭露", "說明無法揭露之原因及預計揭露時程", "以零代替", "以行業平均值代替"], answer: 1, explanation: "GRI準則要求若無法揭露特定資訊，應說明無法揭露之原因及預計揭露時程，並說明已採取之措施。此為GRI揭露原則中「完整性」與「透明性」之體現。", verified: true, chapter: "1.2" },
  { id: "S2-AI058", subject: 2, source: "ai", type: "single", question: "IFRS S2中，企業應使用何種方法計算範疇三排放？", options: ["僅適用支出法", "可使用GHG Protocol範疇三計算指引之方法", "僅適用排放係數法", "僅適用供應商直接提供法"], answer: 1, explanation: "IFRS S2要求企業參照GHG Protocol企業標準及範疇三計算指引之方法計算範疇三排放，包括供應商特定法、混合法等，並應揭露計算方法及假設。", verified: true, chapter: "1.2" },
  { id: "S2-AI059", subject: 2, source: "ai", type: "single", question: "TCFD「治理」要素中，董事會對氣候相關風險與機會之監督責任為何？", options: ["董事會不需監督氣候議題", "董事會應定期討論並監督氣候相關風險與機會", "僅由管理階層負責", "僅由ESG委員會負責"], answer: 1, explanation: "TCFD治理要素要求揭露董事會對氣候相關風險與機會之監督機制，包括董事會如何被告知氣候議題、如何納入決策流程，以及管理階層在評估與管理氣候議題之角色。", verified: true, chapter: "1.2" },
  { id: "S2-AI060", subject: 2, source: "ai", type: "single", question: "GRI 302: 能源與GRI 305: 排放之間有何關聯？", options: ["兩者無關聯", "能源使用資訊為計算排放量之基礎數據之一", "GRI 302已被GRI 305取代", "GRI 305為GRI 302之補充"], answer: 1, explanation: "GRI 302（能源）要求揭露能源消耗量（燃料、電力、熱能等），此為計算GRI 305（排放）中範疇二（間接能源排放）之基礎數據，兩者具高度關聯性。", verified: true, chapter: "1.2" },
  { id: "S2-AI061", subject: 2, source: "ai", type: "single", question: "依IFRS S1規定，企業應於何處揭露永續相關財務資訊？", options: ["僅於永續報告書揭露", "僅於財務報表附註揭露", "於一般目的財務報告中揭露", "另編獨立報告書即可"], answer: 2, explanation: "IFRS S1要求企業於「一般目的財務報告」（General Purpose Financial Reporting）中揭露永續相關財務資訊，使投資人可在同一份報告中獲取整合之財務與永續資訊。", verified: true, chapter: "1.2" },
  { id: "S2-AI062", subject: 2, source: "ai", type: "single", question: "下列何者為TCFD所定義之「轉型風險」（Transition Risk）？", options: ["颱風及洪水等極端天氣事件", "政策與法規變動、市場偏好改變及技術革新", "海平面上升之物理影響", "供應鏈中斷"], answer: 1, explanation: "轉型風險係指因轉型至低碳經濟所衍生之風險，包括政策與法規變動（如碳費、碳交易）、市場偏好改變、技術革新及名譽風險等。", verified: true, chapter: "1.2" },
  { id: "S2-AI063", subject: 2, source: "ai", type: "single", question: "TCFD所定義之「物理風險」可分為哪兩類？", options: ["急性與慢性", "直接與間接", "短期與長期", "可控與不可控"], answer: 0, explanation: "TCFD將物理風險分為「急性風險」（Acute Risk），如颱風、洪水、野火等極端天氣事件；以及「慢性風險」（Chronic Risk），如海平面上升、平均溫度升高、降雨型態改變等長期氣候型態變化。", verified: true, chapter: "1.2" },
  { id: "S2-AI064", subject: 2, source: "ai", type: "multiple", question: "下列哪些屬於GRI通用準則（Universal Standards）之範疇？", options: ["GRI 1: 基礎", "GRI 2: 一般揭露", "GRI 3: 重大主題", "GRI 305: 排放"], answers: [0, 1, 2], explanation: "GRI通用準則（Universal Standards）包含GRI 1（基礎）、GRI 2（一般揭露）及GRI 3（重大主題）。GRI 305屬於主題準則（Topic Standards），非通用準則。", verified: true, chapter: "1.2" },
  { id: "S2-AI065", subject: 2, source: "ai", type: "single", question: "企業設定科學基礎減量目標（SBT）時，其目標設定應符合何種原則？", options: ["與各國自定貢獻一致", "與巴黎協定之全球升溫控制目標一致", "與企業財務目標一致", "與行業平均一致"], answer: 1, explanation: "科學基礎減量目標（Science-based Targets）係指企業減量目標須與《巴黎協定》控制全球升溫低於2°C（並努力控制在1.5°C）之目標一致，並經SBTi審核通過。", verified: true, chapter: "1.2" },
  { id: "S2-AI066", subject: 2, source: "ai", type: "single", question: "國際能源總署（IEA）提出之「2050淨零排放路徑」中，建議何種情境路徑？", options: ["STEPS（既定政策情境）", "APS（承諾目標情境）", "NZE（淨零排放情境）", "SDS（永續發展情境）"], answer: 2, explanation: "IEA於2021年發布「Net Zero by 2050」（NZE）路徑報告，描繪全球能源部門在2050年達成淨零排放之具體路徑及里程碑，為各國能源轉型之重要參考。", verified: true, chapter: "1.2" },
  { id: "S2-AI067", subject: 2, source: "ai", type: "single", question: "COP28（2023年）之重要決議中，首次納入何種承諾？", options: ["淘汰化石燃料", "轉型脫離化石燃料（Transitioning away from fossil fuels）", "全面禁止煤炭", "課徵全球碳稅"], answer: 1, explanation: "COP28達成「UAE共識」，其中首次明確納入「轉型脫離化石燃料」（Transitioning away from fossil fuels）之文字，並呼籲各國加速推動再生能源及能源效率提升。", verified: true, chapter: "1.2" },
  { id: "S2-AI068", subject: 2, source: "ai", type: "single", question: "下列何者為GRI 305要求揭露之排放類別？", options: ["僅直接排放（範疇一）", "直接排放、能源間接排放及其他間接排放（範疇一、二、三）", "僅直接及間接排放", "僅間接排放"], answer: 1, explanation: "GRI 305-1至305-3分別要求揭露直接溫室氣體排放（範疇一）、能源間接排放（範疇二）及其他間接排放（範疇三），完整涵蓋三類排放範疇。", verified: true, chapter: "1.2" },
  { id: "S2-AI069", subject: 2, source: "ai", type: "single", question: "企業編製永續報告書時，重大性分析（Materiality Assessment）之目的為何？", options: ["決定報告書之美觀程度", "鑑別對利害關係人及組織價值最具重要性之永續議題", "評估企業之財務績效", "決定碳排放量之計算方法"], answer: 1, explanation: "重大性分析旨在系統性地鑑別與評估各項永續議題對利害關係人及組織價值之影響程度，以決定報告書應揭露之重大永續主題，為GRI準則之核心要求。", verified: true, chapter: "1.2" },
  { id: "S2-AI070", subject: 2, source: "ai", type: "single", question: "IFRS S2中，要求企業揭露之碳定價機制資訊為何？", options: ["僅揭露企業支付之碳費總金額", "揭露企業是否應用碳定價及其對營運之影響", "僅揭露碳定價對財務報表之影響", "無須揭露碳定價資訊"], answer: 1, explanation: "IFRS S2要求企業揭露其是否應用碳定價（如內部碳定價、碳費、碳排放權交易等）於決策過程中，以及碳定價對營運與財務規劃之影響。", verified: true, chapter: "1.2" },
  { id: "S2-AI071", subject: 2, source: "ai", type: "single", question: "依GRI 2: 一般揭露，組織應揭露哪些治理相關資訊？", options: ["僅董事會成員姓名", "最高治理單位對永續衝擊之監督機制及專業知識", "僅管理階層薪酬", "僅股東結構"], answer: 1, explanation: "GRI 2要求組織揭露最高治理單位（如董事會）對經濟、環境及人羣衝擊之監督機制，以及治理單位成員對永續議題之專業知識及能力。", verified: true, chapter: "1.2" },
  { id: "S2-AI072", subject: 2, source: "ai", type: "single", question: "歐盟「企業永續報告指令」（CSRD）相較於舊版NFRD，主要差異為何？", options: ["適用範圍縮小", "要求雙重重大性（Double Materiality）分析", "不再要求範疇三揭露", "僅適用上市櫃公司"], answer: 1, explanation: "CSRD（Corporate Sustainability Reporting Directive）相較於NFRD，要求企業進行「雙重重大性」（Double Materiality）分析，即同時評估永續議題對企業之財務重大性，以及企業對環境及社會之衝擊重大性。", verified: true, chapter: "1.2" },
  { id: "S2-AI073", subject: 2, source: "ai", type: "single", question: "SBTi（科學基礎減量目標倡議）審核企業目標時，主要審查標準為何？", options: ["企業自訂目標是否合理", "目標是否符合SBTi規範之減量路徑與方法", "目標是否與股東期望一致", "目標是否需要政府核准"], answer: 1, explanation: "SBTi依據其制定之特定產業減量路徑及方法，審查企業提出之減量目標是否與《巴黎協定》控制全球升溫目標一致，通過後方可標註為經SBTi審核之科學基礎目標。", verified: true, chapter: "1.2" },
  { id: "S2-AI074", subject: 2, source: "ai", type: "single", question: "臺灣證交所「永續發展報告書作業辦法」規範哪些公司須編製永續報告書？", options: ["所有上市櫃公司", "實收資本額達20億元以上之上市櫃公司", "金融保險業及化學工業", "僅食品業"], answer: 1, explanation: "依證交所/櫃買中心規定，實收資本額達20億元以上之上市櫃公司須編製永續報告書，並自2025年起擴大至所有上市櫃公司。", verified: true, chapter: "1.2" },
  { id: "S2-AI075", subject: 2, source: "ai", type: "single", question: "CDP（碳揭露專案）主要蒐集企業哪些面向之資訊？", options: ["僅氣候變遷", "氣候變遷、水安全及森林", "僅環境治理", "僅碳足跡"], answer: 1, explanation: "CDP每年向企業及城市蒐集三大環境面向之資訊：氣候變遷（Climate Change）、水安全（Water Security）及森林（Forests），並進行評分。", verified: true, chapter: "1.2" },
  { id: "S2-AI076", subject: 2, source: "ai", type: "single", question: "IFRS S1與S2之生效日期為何？", options: ["2023年1月1日", "2024年1月1日", "2025年1月1日", "2026年1月1日"], answer: 1, explanation: "IFRS S1及S2於2023年6月由ISSB正式發布，規定自2024年1月1日開始之年度報告期間生效，惟各國監管機關得自行決定強制採用時程。", verified: true, chapter: "1.2" },
  { id: "S2-AI077", subject: 2, source: "ai", type: "single", question: "國際永續揭露準則IFRS S1中，「合理資訊」之定義為何？", options: ["僅包括已發布之公開資訊", "包括於報告日無需過度成本或努力即可取得之資訊", "僅包括財務報表內之資訊", "包括未來預測之所有資訊"], answer: 1, explanation: "IFRS S1定義「合理資訊」為於報告日無需過度成本或努力（Without Undue Cost or Effort）即可取得之資訊，此為永續揭露之可行性門檻。", verified: true, chapter: "1.2" },
  { id: "S2-AI078", subject: 2, source: "ai", type: "single", question: "GRI 1: 基礎中提及之報告原則包含哪些？", options: ["準確性、平衡性、清晰性、可比性、可靠性、時效性", "完整性、可靠性、時效性", "重大性、完整性、回應性", "包容性、重大性、回應性、衝擊性"], answer: 0, explanation: "GRI 1規定報告原則包括：準確性（Accuracy）、平衡性（Balance）、清晰性（Clarity）、可比性（Comparability）、可靠性（Reliability）及時效性（Timeliness），以確保報告品質。", verified: true, chapter: "1.2" },
  { id: "S2-AI079", subject: 2, source: "ai", type: "single", question: "ISSB發布IFRS S2時，特別參考了哪個組織之既有架構？", options: ["GRI", "TCFD", "SASB", "CDP"], answer: 1, explanation: "ISSB在制定IFRS S2時直接採用TCFD四大核心架構（治理、策略、風險管理、指標與目標），並整合SASB產業特定揭露標準，使IFRS S2成為TCFD架構之強化版本。", verified: true, chapter: "1.2" },
  { id: "S2-AI080", subject: 2, source: "ai", type: "single", question: "企業承諾RE100目標時，應遵循之採購原則為何？", options: ["每年揭露再生能源使用比例", "購買再生能源憑證即可", "僅需設置自有再生能源設備", "無需第三方驗證"], answer: 0, explanation: "RE100要求企業每年揭露再生能源使用比例及進度，並應遵循RE100制定之技術原則（如再生能源類型、環境屬性憑證、地域匹配及時序匹配等原則）。", verified: true, chapter: "1.2" },
  { id: "S2-AI081", subject: 2, source: "ai", type: "single", question: "下列何者為TCFD建議揭露之「氣候相關指標」範例？", options: ["股價波動率", "範疇一、範疇二及範疇三之溫室氣體排放量", "員工人數", "客戶滿意度"], answer: 1, explanation: "TCFD建議組織揭露之氣候相關指標包括溫室氣體排放量（範疇一、二、三）、氣候相關風險之財務影響、內部碳價格、使用情境分析之參數等。", verified: true, chapter: "1.2" },
  { id: "S2-AI082", subject: 2, source: "ai", type: "single", question: "企業導入IFRS S1及S2時，面臨之最大挑戰通常為何？", options: ["遵循成本過高", "數據可用性及品質不足", "員工抗拒變革", "客戶不感興趣"], answer: 1, explanation: "企業導入IFRS S1及S2的最大挑戰在於範疇三數據之取得與驗證、價值鏈排放數據之可用性及品質，以及氣候情境分析之複雜性。", verified: true, chapter: "1.2" },
  { id: "S2-AI083", subject: 2, source: "ai", type: "single", question: "歐盟「歐洲永續報導準則」（ESRS）係由哪個組織制定？", options: ["歐盟執委會", "EFRAG（歐洲財務報告諮詢組）", "ISSB", "GRI"], answer: 1, explanation: "ESRS（European Sustainability Reporting Standards）由EFRAG（European Financial Reporting Advisory Group）受歐盟執委會委託制定，為CSRD之配套揭露準則。", verified: true, chapter: "1.2" },
  { id: "S2-AI084", subject: 2, source: "ai", type: "single", question: "GRI 3: 重大主題中，組織應如何決定重大主題？", options: ["由管理階層指定", "透過重大性評估流程，鑑別組織對經濟、環境及人羣之衝擊", "由外部顧問指定", "直接引用同業重大主題"], answer: 1, explanation: "GRI 3要求組織透過系統性之重大性評估流程（Materiality Assessment），鑑別組織對經濟、環境及人羣（包含人權）之實際及潛在衝擊，以決定應報告之重大主題。", verified: true, chapter: "1.2" },
  { id: "S2-AI085", subject: 2, source: "ai", type: "multiple", question: "下列哪些屬於IFRS S2要求揭露之範疇三排放類別？", options: ["購買商品與服務", "員工通勤", "廢棄物處理", "銷售產品之使用"], answers: [0, 1, 3], explanation: "IFRS S2參照GHG Protocol範疇三分類，購買商品與服務、員工通勤、銷售產品之使用均屬於範疇三排放類別。各類別是否揭露係基於重大性原則，由企業自行判斷。", verified: true, chapter: "1.2" },
  { id: "S2-AI086", subject: 2, source: "ai", type: "single", question: "全球永續揭露準則之整合趨勢為何？", options: ["各國各自發展", "朝向ISSB單一全球基準收斂", "由GRI主導", "由各產業自行訂定"], answer: 1, explanation: "全球永續揭露準則正朝向ISSB制定之單一全球基準（Global Baseline）收斂，各國監管機構（如英國、日本、新加坡、澳洲等）紛紛規劃採用或參考ISSB準則。", verified: true, chapter: "1.2" },
  { id: "S2-AI087", subject: 2, source: "ai", type: "single", question: "SBTi（科學基礎減量目標倡議）之主要目標為何？", options: ["推動企業設定與氣候科學一致之減量目標", "建立碳權交易平台", "推動再生能源採購", "制定碳排放計算標準"], answer: 0, explanation: "SBTi（Science Based Targets initiative）是由CDP、UNGC、WRI及WWF共同發起之倡議，旨在推動企業設定與《巴黎協定》控制全球升溫目標一致之科學基礎減量目標。", verified: true, chapter: "1.3" },
  { id: "S2-AI088", subject: 2, source: "ai", type: "single", question: "RE100倡議之參與企業須承諾何種目標？", options: ["100%使用低碳能源", "100%使用再生能源", "100%碳中和", "100%淨零排放"], answer: 1, explanation: "RE100為全球再生能源倡議，由氣候組織（The Climate Group）與CDP共同管理。參與企業須公開承諾在特定期限內達成100%使用再生電力之目標。", verified: true, chapter: "1.3" },
  { id: "S2-AI089", subject: 2, source: "ai", type: "single", question: "「淨零排放」（Net Zero）與「碳中和」（Carbon Neutral）之主要區別為何？", options: ["兩者完全相同", "淨零排放要求全面減排並處理所有溫室氣體，碳中和僅針對二氧化碳", "碳中和要求更嚴格", "淨零排放僅針對範疇一"], answer: 1, explanation: "「碳中和」通常僅針對二氧化碳排放進行抵換，而「淨零排放」要求全面減少所有溫室氣體排放（CO2、CH4、N2O、HFCs、PFCs、SF6、NF3），並透過碳移除技術平衡剩餘排放。", verified: true, chapter: "1.3" },
  { id: "S2-AI090", subject: 2, source: "ai", type: "single", question: "PAS 2060:2014 碳中和標準之核心要求為何？", options: ["設定減量目標", "量化排放量、減量、抵換及文書化作業", "取得政府許可", "加入碳交易市場"], answer: 1, explanation: "PAS 2060為英國標準協會（BSI）公布之碳中和標準，核心要求包括：量化碳足跡、制定碳管理計畫進行減量、剩餘排放量透過碳抵換達成碳中和，並須經第三方驗證。", verified: true, chapter: "1.3" },
  { id: "S2-AI091", subject: 2, source: "ai", type: "single", question: "ISO 14068-1:2023 碳中和標準相較於PAS 2060，主要強化哪些面向？", options: ["強調階層方法（Hierarchy Approach）：優先減量，其次抵換", "降低查驗要求", "放寬抵消比例", "僅適用於組織層級"], answer: 0, explanation: "ISO 14068-1:2023強調「減量優先」之階層方法，要求組織或產品必須先採取減量措施，剩餘之碳排放量方可透過碳抵換達成碳中和，避免過度依賴碳權購買。", verified: true, chapter: "1.3" },
  { id: "S2-AI092", subject: 2, source: "ai", type: "single", question: "SBTi針對企業設定1.5°C路徑減量目標之主要要求為何？", options: ["每年減量2.5%以上", "每年減量4.2%以上（絕對減量）", "每年減量1%", "無特定減量率要求"], answer: 1, explanation: "SBTi針對1.5°C路徑，要求企業每年須達成4.2%以上之絕對減量率（相對於基準年），此為達成長期升溫控制目標所需之科學基礎減量速度。", verified: true, chapter: "1.3" },
  { id: "S2-AI093", subject: 2, source: "ai", type: "single", question: "臺灣RE100聯盟由哪個組織發起？", options: ["經濟部能源局", "中華民國企業永續發展協會（BCSD Taiwan）", "環境部", "工業技術研究院"], answer: 1, explanation: "臺灣RE100聯盟由中華民國企業永續發展協會（BCSD Taiwan）發起，協助臺灣企業取得再生能源並達成RE100目標，並與國際RE100倡議組織對接。", verified: true, chapter: "1.3" },
  { id: "S2-AI094", subject: 2, source: "ai", type: "single", question: "「碳移除」與「碳抵換」之差異為何？", options: ["兩者意義相同", "碳移除係指從大氣中捕獲二氧化碳，碳抵換係指購買碳權以抵銷排放", "碳抵換包含碳移除", "碳移除屬於碳抵換之一種"], answer: 1, explanation: "碳移除（Carbon Removal）係指透過自然或技術方式將二氧化碳從大氣中移除，如造林、直接空氣捕捉（DAC）等；碳抵換（Carbon Offset）係指購買碳權以抵銷自身排放，兩者為不同概念。", verified: true, chapter: "1.3" },
  { id: "S2-AI095", subject: 2, source: "ai", type: "single", question: "「碳權」的定義為何？", options: ["企業排放二氧化碳的權利證明", "經認證之溫室氣體減量或移除之憑證", "購買化石燃料之配額", "政府核發之排放許可"], answer: 1, explanation: "碳權（Carbon Credit）係指經由認證機構審核、核發之溫室氣體減量或移除之憑證，每單位代表1公噸CO2e之減量或移除量。可分為強制市場配額型及自願市場專案型碳權。", verified: true, chapter: "1.3" },
  { id: "S2-AI096", subject: 2, source: "ai", type: "single", question: "企業參與SBTi設定目標後，最長應設定多久之目標期限？", options: ["5年", "10年", "15年", "20年"], answer: 1, explanation: "SBTi要求企業設定之短期目標（Near-term Targets）最長為5至10年，自提交目標日起算。長期目標（Long-term Targets）則為2050年前達成淨零排放。", verified: true, chapter: "1.3" },
  { id: "S2-AI097", subject: 2, source: "ai", type: "single", question: "聯合國「Race to Zero」倡議之參與者須承諾何種目標？", options: ["2030年前碳中和", "2040年前達到科學基礎減量目標", "2050年前達成淨零排放", "立即停止化石燃料使用"], answer: 2, explanation: "Race to Zero是由聯合國氣候變化綱要公約（UNFCCC）推動之全球倡議，要求參與者承諾在2050年前達成淨零排放，並設定中期目標，每年揭露進度。", verified: true, chapter: "1.3" },
  { id: "S2-AI098", subject: 2, source: "ai", type: "single", question: "SBTi之「淨零標準」（Net-Zero Standard）要求企業如何處理剩餘排放？", options: ["透過購買碳權抵換即可", "必須先達成深層減量（90%以上），再透過碳移除技術處理剩餘排放", "可不採取任何行動", "僅需購買自然型碳權"], answer: 1, explanation: "SBTi淨零標準要求企業須先達成90-95%之深層減量（Deep Decarbonization），剩餘之5-10%排放方可透過碳移除（Carbon Removal）技術或專案進行中和，並須符合永久性標準。", verified: true, chapter: "1.3" },
  { id: "S2-AI099", subject: 2, source: "ai", type: "single", question: "ISO 14068 碳中和標準與 PAS 2060 相比，對碳權使用之限制為何？", options: ["無限制使用任何碳權", "要求一定比例之碳權須來自碳移除專案", "禁止使用碳權", "僅可使用國內碳權"], answer: 1, explanation: "ISO 14068-1要求使用碳權時應遵循「品質階層」，優先使用碳移除型（Carbon Removal）碳權，並限制碳迴避型（Avoidance）碳權之使用比例，以確保碳中和之環境完整性。", verified: true, chapter: "1.3" },
  { id: "S2-AI100", subject: 2, source: "ai", type: "single", question: "SBTi不允許企業使用何種方式達成目標？", options: ["購買再生能源憑證", "使用大量碳權替代減量行動", "提高能源效率", "更換低碳燃料"], answer: 1, explanation: "SBTi明確要求企業必須透過實際減量行動達成目標，禁止以大量購買碳權替代自身減量行動。碳權僅得用於處理價值鏈外之排放，不得計入SBT進度。", verified: true, chapter: "1.3" },
  { id: "S2-AI101", subject: 2, source: "ai", type: "single", question: "SBTi針對不同產業設定之減量路徑（Pathway）之特性為何？", options: ["所有產業使用單一標準路徑", "依產業特性設定不同路徑，如工業、運輸、建築等", "由企業自行選擇路徑", "僅適用於高碳排產業"], answer: 1, explanation: "SBTi針對不同產業特性設定特定之減量路徑，包括工業（鋼鐵、水泥、石化等）、運輸、建築、金融、資訊通訊等產業，以反映各產業之減碳潛力及技術可行性。", verified: true, chapter: "1.3" },
  { id: "S2-AI102", subject: 2, source: "ai", type: "single", question: "企業提出之SBT經SBTi審核通過後，應多久更新或提交進度報告？", options: ["每年更新", "每兩年更新並揭露進度", "每五年更新", "不需更新"], answer: 1, explanation: "SBTi要求企業至少每兩年報告進度，並在目標到期前至少兩年提交新目標或更新既有目標，以確保企業持續符合最新氣候科學要求。", verified: true, chapter: "1.3" },
  { id: "S2-AI103", subject: 2, source: "ai", type: "single", question: "下列何者為「自然為本解決方案」（NbS）在碳管理中之應用？", options: ["發展氫能", "造林與森林經營增加碳匯", "興建離岸風電", "推動電動車"], answer: 1, explanation: "自然為本解決方案（Nature-based Solutions）係利用自然生態系統達成減碳與調適目標，如造林、森林經營、紅樹林復育、土壤碳匯等，屬於自然碳匯（Natural Carbon Sinks）。", verified: true, chapter: "1.3" },
  { id: "S2-AI104", subject: 2, source: "ai", type: "single", question: "SBTi對供應鏈減碳之要求，若範疇三排放占比超過多少時須設定範疇三目標？", options: ["20%", "40%", "50%", "60%"], answer: 1, explanation: "SBTi要求若企業範疇三排放占總排放量40%以上，須設定範疇三科學基礎減量目標，且該目標須涵蓋至少三分之二之總範疇三排放。", verified: true, chapter: "1.3" },
  { id: "S2-AI105", subject: 2, source: "ai", type: "single", question: "企業導入SBTi時，「基準年」之選擇要求為何？", options: ["必須是最新年度", "建議選擇有可靠排放數據之最近年度，通常不超過目標提交前2年", "必須選擇2005年", "由SBTi指定"], answer: 1, explanation: "SBTi要求企業選擇一個有可靠且可查證排放數據之基準年，且建議基準年不超過提交目標前2年，以確保數據之最新性與可信度。", verified: true, chapter: "1.3" },
  { id: "S2-AI106", subject: 2, source: "ai", type: "single", question: "碳中和「補償」（Offset）與「中和」（Neutralization）之差異為何？", options: ["兩者完全相同", "補償係購買碳權抵換排放，中和係透過碳移除平衡剩餘排放", "中和屬補償之一部分", "補償用於範疇一，中和用於範疇二"], answer: 1, explanation: "碳中和中，「補償」（Offset）係指購買減量型碳權抵銷無法避免之排放；「中和」（Neutralization）則特指透過碳移除（Carbon Removal）平衡殘餘排放，兩者在碳權類型及品質要求上有所不同。", verified: true, chapter: "1.3" },
  { id: "S2-AI107", subject: 2, source: "ai", type: "single", question: "GHG Protocol中，企業設定範疇三目標時之邊界設定原則為何？", options: ["排除所有供應商", "應納入所有價值鏈排放類別之重大項目", "僅納入運輸排放", "僅納入採購商品排放"], answer: 1, explanation: "GHG Protocol企業價值鏈（範疇三）會計標準建議企業鑑別並報告所有15類範疇三排放類別中重大之項目，並依此設定範疇三減量目標，以涵蓋完整價值鏈排放。", verified: true, chapter: "1.3" },
  { id: "S2-AI108", subject: 2, source: "ai", type: "single", question: "COP29（2024年）就國際碳市場機制（巴黎協定第6條）達成之共識為何？", options: ["全面禁止國際碳交易", "確立雙邊碳權交易之授權程序及登錄機制", "統一全球碳價", "取消碳權制度"], answer: 1, explanation: "COP29就巴黎協定第6條（國際碳市場機制）達成關鍵共識，確立第6.2條（雙邊協議）之授權程序與登錄機制，為全球碳權交易提供更明確之規則基礎。", verified: true, chapter: "1.3" },
  { id: "S2-AI109", subject: 2, source: "ai", type: "single", question: "SBTi對「淨零排放」定義中，要求長期目標涵蓋多少比例之排放？", options: ["50%", "至少95%", "100%", "至少80%"], answer: 1, explanation: "SBTi淨零標準要求企業長期目標（Long-term Targets）應涵蓋至少95%之總排放量（範疇一+範疇二+範疇三），僅允許最多5%排放可透過碳移除中和。", verified: true, chapter: "1.3" },
  { id: "S2-AI110", subject: 2, source: "ai", type: "multiple", question: "下列哪些為國際上常見之自願碳市場標準？", options: ["Verra VCS", "Gold Standard", "歐盟ETS", "中國CCER"], answers: [0, 1], explanation: "Verra VCS及Gold Standard為國際自願碳市場兩大主要認證標準。歐盟ETS屬於強制碳交易市場，中國CCER屬地域性自願標準但非國際通用。", verified: true, chapter: "1.3" },
  { id: "S2-AI111", subject: 2, source: "ai", type: "single", question: "RE100對再生能源之要求包含哪些技術類別？", options: ["僅太陽光電及風力", "太陽光電、風力、水力、生質能、地熱等", "僅太陽光電", "僅風力發電"], answer: 1, explanation: "RE100接受多種再生能源技術，包括太陽光電、風力發電、水力發電（小型）、生質能及地熱，惟須符合RE100制定之技術及環境屬性標準。", verified: true, chapter: "1.3" },
  { id: "S2-AI112", subject: 2, source: "ai", type: "single", question: "SBTi針對金融業設定之目標要求，與一般產業有何不同？", options: ["金融業不需設定目標", "金融業須設定投融資組合排放（範疇三第15類）之減量目標", "金融業僅需設定範疇一目標", "金融業適用更寬鬆標準"], answer: 1, explanation: "金融業SBT要求涵蓋投融資組合排放（Financed Emissions），即範疇三第15類，並須依SBTi金融業指引設定氣候目標，包括資產類別特定減量路徑。", verified: true, chapter: "1.3" },
  { id: "S2-AI113", subject: 2, source: "ai", type: "single", question: "PAS 2060:2014 中，碳中和宣告之有效期限為何？", options: ["永久有效", "1年，須逐年更新", "5年", "10年"], answer: 1, explanation: "PAS 2060要求碳中和宣告應每年更新，組織須每年量化碳足跡、執行減量措施並購買足額碳權，以維持碳中和狀態，不得一次宣告永久有效。", verified: true, chapter: "1.3" },
  { id: "S2-AI114", subject: 2, source: "ai", type: "single", question: "國際自願碳市場誠信委員會（ICVCM）之核心原則（CCPs）係針對何種問題？", options: ["提高碳權價格", "確保碳權品質與環境完整性", "擴大碳市場規模", "統一碳價水準"], answer: 1, explanation: "ICVCM（Integrity Council for the Voluntary Carbon Market）制定「核心碳原則」（Core Carbon Principles, CCPs），旨在提升自願碳市場中碳權之品質、可信度及環境完整性，以恢復市場信心。", verified: true, chapter: "1.3" },
  { id: "S2-AI115", subject: 2, source: "ai", type: "single", question: "SBTi與CDP之關係為何？", options: ["完全獨立之組織", "CDP為SBTi之合作夥伴，企業可透過CDP申報SBT進度", "SBTi為CDP之子公司", "兩者無關聯"], answer: 1, explanation: "CDP為SBTi之創始夥伴之一，企業可透過CDP揭露平台申報其SBT進度，且CDP評分亦參考企業是否設定SBT，兩者為互補關係。", verified: true, chapter: "1.3" },
  { id: "S2-AI116", subject: 2, source: "ai", type: "single", question: "企業承諾SBT後，若未在規定期限內提交目標，可能面臨何種後果？", options: ["罰款", "被SBTi剔除於承諾名單（Removed）", "自動延長期限", "無任何後果"], answer: 1, explanation: "SBTi要求企業在提交承諾後24個月內完成目標審查及提交。若逾期未提交，SBTi將把企業標示為「已剔除」（Removed），並將其自承諾企業名單中移除。", verified: true, chapter: "1.3" },
  { id: "S2-AI117", subject: 2, source: "ai", type: "single", question: "ISO 14064-1:2018 溫室氣體盤查標準中，對排放量分類之要求為何？", options: ["僅分為直接及間接排放", "分為六大類：類別1至類別6", "僅分為範疇一及範疇二", "依產業別分類"], answer: 1, explanation: "ISO 14064-1:2018將排放分為六大類：類別1（直接排放）、類別2（間接能源排放）、類別3（運輸排放）、類別4（組織使用產品排放）、類別5（使用組織產品排放）及類別6（其他間接排放）。", verified: true, chapter: "1.3" },
  { id: "S2-AI118", subject: 2, source: "ai", type: "single", question: "TCFD於2023年正式完成其任務後，其揭露架構由哪個組織接手監管？", options: ["GRI", "ISSB", "SASB", "UNFCCC"], answer: 1, explanation: "TCFD已於2023年完成其任務並解散，其氣候相關財務揭露之監管責任由ISSB（國際永續準則理事會）接手，IFRS S2即為TCFD架構之延續與強化。", verified: true, chapter: "1.3" },
  { id: "S2-AI119", subject: 2, source: "ai", type: "single", question: "《巴黎協定》第6條規範之核心內容為何？", options: ["各國減量目標", "國際碳市場合作機制", "氣候調適資金", "技術移轉"], answer: 1, explanation: "巴黎協定第6條（Article 6）規範國際碳市場合作機制，包括第6.2條（雙邊合作減量協議）及第6.4條（中央監督之永續發展機制），旨在建立避免雙重計算之碳權交易架構。", verified: true, chapter: "1.3" },
  { id: "S2-AI120", subject: 2, source: "ai", type: "single", question: "企業設科學基礎減量目標時，若範疇三排放占總排放60%，應採取何種行動？", options: ["無須設定範疇三目標", "須設定範疇三目標，且目標須涵蓋至少三分之二之總範疇三排放", "僅須設定範疇一目標", "僅須報告範疇三排放"], answer: 1, explanation: "SBTi規定若範疇三排放占總排放量40%以上，企業須設定範疇三科學基礎減量目標，且目標應涵蓋至少三分之二（67%）之總範疇三排放量。", verified: true, chapter: "1.3" },
  { id: "S2-AI121", subject: 2, source: "ai", type: "single", question: "我國「自願減量專案」係依哪部法律設立？", options: ["再生能源發展條例", "氣候變遷因應法", "溫室氣體減量及管理法", "能源管理法"], answer: 1, explanation: "我國自願減量專案制度依《氣候變遷因應法》第26條設立，事業得向中央主管機關申請自願減量專案，經審查通過後執行減量措施，取得減量額度（碳權）。", verified: true, chapter: "2.1" },
  { id: "S2-AI122", subject: 2, source: "ai", type: "single", question: "自願減量專案之「外加性」（Additionality）原則為何？", options: ["減量效益須是超出法規要求之額外減量", "減量量須加總計算", "專案須額外申請許可", "減量成本須外加計算"], answer: 0, explanation: "外加性（Additionality）係指專案產生之減量效益，必須是相較於「基準線情境」下額外達成之減量，且非因法規要求或經濟可行性所必然發生者，以確保碳權之環境完整性。", verified: true, chapter: "2.1" },
  { id: "S2-AI123", subject: 2, source: "ai", type: "single", question: "國際自願碳市場中，Verra VCS標準由哪個組織管理？", options: ["世界銀行", "Verra（原VCS協會）", "聯合國", "國際標準化組織"], answer: 1, explanation: "Verra為非營利組織，管理VCS（Verified Carbon Standard）碳權認證標準，為全球自願碳市場中使用最廣泛之標準之一，截至2024年已核發超過10億噸碳權。", verified: true, chapter: "2.1" },
  { id: "S2-AI124", subject: 2, source: "ai", type: "single", question: "Gold Standard碳權標準最初係由哪個組織發展？", options: ["世界銀行", "世界自然基金會（WWF）", "聯合國開發計畫署（UNDP）", "世界經濟論壇（WEF）"], answer: 1, explanation: "Gold Standard由世界自然基金會（WWF）及國際太陽能技術應用組織等非政府組織於2003年所發展，後由Gold Standard Foundation管理，強調對永續發展目標（SDGs）之貢獻。", verified: true, chapter: "2.1" },
  { id: "S2-AI125", subject: 2, source: "ai", type: "single", question: "自願減量專案中「基準線」（Baseline）之定義為何？", options: ["專案執行前之設備清冊", "合理描述若無專案活動時會發生之溫室氣體排放情境", "國家排放總量目標", "行業平均排放強度"], answer: 1, explanation: "基準線係指在無自願減量專案活動情況下，合理推估會發生之溫室氣體排放量（即「情境推估法」）。專案之減量成效即為基準線排放量減去專案實際排放量之差額。", verified: true, chapter: "2.1" },
  { id: "S2-AI126", subject: 2, source: "ai", type: "single", question: "我國碳權交易平台由哪個單位建置及營運？", options: ["環境部", "臺灣碳權交易所（碳交所）", "臺灣證券交易所", "經濟部工業局"], answer: 1, explanation: "臺灣碳權交易所（簡稱碳交所）由行政院核定設立，負責建置及營運臺灣碳權交易平台，提供國內外碳權交易、諮詢及教育訓練等服務。", verified: true, chapter: "2.1" },
  { id: "S2-AI127", subject: 2, source: "ai", type: "single", question: "自願減量專案中，「洩漏」（Leakage）風險係指何種現象？", options: ["專案場址發生溫室氣體外洩", "專案活動導致專案邊界外之間接排放增加", "碳權交易資訊外洩", "專案財務資料外洩"], answer: 1, explanation: "自願減量專案之「洩漏」係指專案活動導致專案邊界外之溫室氣體排放增加之現象，需在計算減量量時予以扣除，以確保專案之總體減量效益真實。", verified: true, chapter: "2.1" },
  { id: "S2-AI128", subject: 2, source: "ai", type: "single", question: "我國自願減量專案所採用之方法學，由誰負責審查及認可？", options: ["經濟部", "中央主管機關（環境部）", "碳交所", "第三方查驗機構"], answer: 1, explanation: "自願減量專案之方法學（Methodology）須經中央主管機關審查及認可後始得使用。方法學規範專案之基準線設定、減量計算方式、監測方法及邊界界定等技術要求。", verified: true, chapter: "2.1" },
  { id: "S2-AI129", subject: 2, source: "ai", type: "single", question: "VCS碳權標準認證之碳權，一單位代表多少減碳量？", options: ["0.5公噸CO2e", "1公噸CO2e", "10公噸CO2e", "100公噸CO2e"], answer: 1, explanation: "VCS標準下，每一單位碳權（Verified Carbon Unit, VCU）代表1公噸CO2e之經認證減量或移除量。此為國際碳市場之通用單位標準。", verified: true, chapter: "2.1" },
  { id: "S2-AI130", subject: 2, source: "ai", type: "single", question: "自願減量專案之碳權「永久性」（Permanence）原則係指？", options: ["碳權永久有效", "減量或移除效益應為永久或須有風險管理機制防止逆轉", "碳權價格永久固定", "專案須永久營運"], answer: 1, explanation: "永久性原則係指減量或碳移除效益須確保長期存續，特別是自然型碳匯專案（如造林）可能因火災、病蟲害等因素逆轉，故須建立緩衝區（Buffer Pool）等風險管理機制。", verified: true, chapter: "2.1" },
  { id: "S2-AI131", subject: 2, source: "ai", type: "single", question: "碳權之「Vintage」（年份）係指什麼？", options: ["碳權發行年份", "減量實際發生之年份", "碳權購買年份", "碳權到期年份"], answer: 1, explanation: "碳權之「Vintage」係指減量或碳移除發生之實際年份，而非碳權發行或購買年份。此為評估碳權品質及時效性之重要指標。", verified: true, chapter: "2.1" },
  { id: "S2-AI132", subject: 2, source: "ai", type: "single", question: "我國自願減量專案之申請流程，下列何者正確？", options: ["直接向碳交所提出申請", "向中央主管機關提出申請，經審查通過後登錄並執行", "向地方政府申請", "自行執行後再向環境部報備"], answer: 1, explanation: "自願減量專案申請流程：事業向中央主管機關（環境部）提出專案申請，經審查通過後登錄，始可執行專案並進行監測，後續須經查驗機構查驗後申請核發減量額度。", verified: true, chapter: "2.1" },
  { id: "S2-AI133", subject: 2, source: "ai", type: "single", question: "國際碳權認證標準中，何謂「Co-benefits」（共同效益）？", options: ["碳權價格優惠", "專案除減碳外對環境及社會之額外正面效益", "碳交易之稅務優惠", "查驗費用減免"], answer: 1, explanation: "共同效益（Co-benefits）係指碳權專案在減碳之外，對環境（如生物多樣性、水質改善）及社會（如創造就業、健康改善）之額外正面效益。Gold Standard標準特別強調共同效益。", verified: true, chapter: "2.1" },
  { id: "S2-AI134", subject: 2, source: "ai", type: "single", question: "自願減量專案中，「計入期」（Crediting Period）之定義為何？", options: ["碳權有效期限", "專案得產生減量額度之期間", "專案申請審查期間", "碳權交易結算期間"], answer: 1, explanation: "計入期（Crediting Period）係指自願減量專案經註冊後，被允許產生並申請核發減量額度之年限。不同方法學及標準之計入期長度不同，通常為7-10年，最長可達30年（造林專案）。", verified: true, chapter: "2.1" },
  { id: "S2-AI135", subject: 2, source: "ai", type: "single", question: "Gold Standard標誌性之認證要求，對專案有何額外要求？", options: ["要求專案使用最先進技術", "要求專案須貢獻聯合國永續發展目標（SDGs）", "要求專案規模須達一定門檻", "要求專案須位於開發中國家"], answer: 1, explanation: "Gold Standard要求專案除具備減碳效益外，還須量化並報告對聯合國永續發展目標（SDGs）之貢獻，如貧窮消除、潔淨能源、氣候行動等，以確保專案具備多重效益。", verified: true, chapter: "2.1" },
  { id: "S2-AI136", subject: 2, source: "ai", type: "single", question: "自願減量專案查驗作業中，查驗機構主要驗證項目為何？", options: ["專案財務報表", "專案設計文件（PDD）、監測報告及減量計算", "專案人員之資格", "專案之市場行銷計畫"], answer: 1, explanation: "查驗機構依據方法學及認證標準之要求，驗證專案設計文件（Project Design Document, PDD）之符合性，並定期查證監測報告及減量計算結果，確認減量數據之正確性。", verified: true, chapter: "2.1" },
  { id: "S2-AI137", subject: 2, source: "ai", type: "single", question: "國際碳市場中，CORSIA（國際航空業碳抵換及減量計畫）認可之碳權標準包含哪些？", options: ["僅Verra VCS", "僅Gold Standard", "Verra VCS、Gold Standard及ACR等", "僅聯合國CDM"], answer: 2, explanation: "CORSIA（Carbon Offsetting and Reduction Scheme for International Aviation）由國際民航組織（ICAO）推動，已認可包括Verra VCS、Gold Standard、ACR及CAR等多個自願碳市場標準，作為航空業碳抵換之合格碳權來源。", verified: true, chapter: "2.1" },
  { id: "S2-AI138", subject: 2, source: "ai", type: "single", question: "碳權之「雙重計算」（Double Counting）風險係指？", options: ["將同一減量計算兩次", "同一減量效益被兩個以上之主體主張使用", "碳權價格計算錯誤", "碳權發行數量錯誤"], answer: 1, explanation: "雙重計算（Double Counting）係指同一噸減量或移除效益被兩個（含）以上之主體用以主張減碳成果或抵銷排放，例如同時被賣方及買方計入減量成果。巴黎協定第6條即旨在防止雙重計算。", verified: true, chapter: "2.1" },
  { id: "S2-AI139", subject: 2, source: "ai", type: "single", question: "Verra VCS標準下，REDD+專案屬於何種類型？", options: ["再生能源專案", "避免毀林及森林退化造成之排放", "能源效率改善", "廢棄物處理"], answer: 1, explanation: "REDD+（Reducing Emissions from Deforestation and Forest Degradation）係指減少因毀林及森林退化所致排放之專案類型，加上森林永續管理、森林碳匯增加等措施，為VCS重要之自然型碳權類型。", verified: true, chapter: "2.1" },
  { id: "S2-AI140", subject: 2, source: "ai", type: "single", question: "碳市場中「一級市場」（Primary Market）與「二級市場」（Secondary Market）之差異為何？", options: ["一級市場為碳權初次發行，二級市場為碳權發行後之流通交易", "一級市場價格較低", "二級市場不可交易", "一級市場僅限機構投資人"], answer: 0, explanation: "一級市場（Primary Market）係指碳權初次發行，即專案開發商向認證機構申請並取得碳權；二級市場（Secondary Market）則係碳權發行後再進行之買賣交易，價格由供需決定。", verified: true, chapter: "2.1" },
  { id: "S2-AI141", subject: 2, source: "ai", type: "single", question: "我國自願減量專案之查驗機構須具備何種資格？", options: ["任何環保顧問公司", "經中央主管機關認證之查驗機構", "國際會計師事務所", "經濟部登記之檢驗機構"], answer: 1, explanation: "自願減量專案之查驗機構須經中央主管機關（環境部）依據「溫室氣體查驗機構管理辦法」認證合格，始得辦理自願減量專案之查驗作業。", verified: true, chapter: "2.1" },
  { id: "S2-AI142", subject: 2, source: "ai", type: "single", question: "CDM（清潔發展機制）係哪個國際協議下之機制？", options: ["蒙特婁議定書", "京都議定書", "巴黎協定", "聯合國海洋法公約"], answer: 1, explanation: "CDM（Clean Development Mechanism）為《京都議定書》下建立之彈性機制，允許已開發國家在開發中國家投資減量專案，以取得經認證之減排量（CERs），用以達成其京都目標。", verified: true, chapter: "2.1" },
  { id: "S2-AI143", subject: 2, source: "ai", type: "single", question: "自願減量專案中，何謂「保守性原則」（Conservative Principle）？", options: ["不發表樂觀預測", "在不確定情況下應採用較保守不致高估減量之假設及參數", "選用最低成本之減量技術", "保守估計專案經費"], answer: 1, explanation: "保守性原則係指在計算減量量時，若有不確定性因素或假設選擇，應採用不致高估減量效益之保守假設及參數值，以確保核發之碳權數量不超過實際減量量。", verified: true, chapter: "2.1" },
  { id: "S2-AI144", subject: 2, source: "ai", type: "single", question: "自願碳市場中，「先期碳權」（Forward Carbon Credit）係指？", options: ["已發行但尚未出售之碳權", "預計未來才會產生之減量所預售之碳權", "價格較低之碳權", "效期較短之碳權"], answer: 1, explanation: "先期碳權（Forward Carbon Credit）係指專案尚未實際產生減量效益前，即預先銷售未來將產生之碳權。此機制可為專案提供前期資金，但買方承擔專案不履約之風險。", verified: true, chapter: "2.1" },
  { id: "S2-AI145", subject: 2, source: "ai", type: "single", question: "碳權品質評估中，「永久性風險」最高之專案類型通常為何？", options: ["再生能源專案", "森林碳匯專案", "工業廢氣處理專案", "能源效率改善專案"], answer: 1, explanation: "森林碳匯專案（如造林、REDD+）之永久性風險最高，因其碳儲存可能因森林火災、病蟲害、非法採伐等人為或自然因素而釋放。再生能源及工業廢氣處理專案則無此風險。", verified: true, chapter: "2.1" },
  { id: "S2-AI146", subject: 2, source: "ai", type: "single", question: "國際自願碳市場中，何謂「對應調整」（Corresponding Adjustment）？", options: ["碳權價格調整", "碳權交易之匯率調整", "主辦國須在其國家排放清冊中扣除已出口之減量，避免雙重計算", "碳權品質分級調整"], answer: 2, explanation: "對應調整（Corresponding Adjustment）係巴黎協定第6.2條之核心機制，要求碳權出口國必須在其國家排放清冊中將已出口之減量額度予以扣除，以確保該減量未被出口國同時使用於其NDC目標。", verified: true, chapter: "2.1" },
  { id: "S2-AI147", subject: 2, source: "ai", type: "single", question: "企業購買碳權進行碳中和宣告時，應注意之品質原則為何？", options: ["價格最低", "真實、永久、外加、可查證、不重複計算", "數量最多", "效期最長"], answer: 1, explanation: "優質碳權應符合以下品質原則：真實（Real）、永久（Permanent）、外加（Additional）、可查證（Verifiable）及不重複計算（No Double Counting），同時應具備明確之所有權歸屬及合法之登記註冊。", verified: true, chapter: "2.1" },
  { id: "S2-AI148", subject: 2, source: "ai", type: "single", question: "我國自願減量專案之「方法學」應包含哪些主要內容？", options: ["專案行銷策略", "基準線設定、減量計算方法、監測計畫及邊界界定", "專案融資計畫", "專案人員編制"], answer: 1, explanation: "自願減量專案方法學為技術規範文件，應包含：適用條件、基準線情境設定方法、減量計算公式與參數、專案邊界、監測方法與頻率等技術要求。", verified: true, chapter: "2.1" },
  { id: "S2-AI149", subject: 2, source: "ai", type: "single", question: "我國碳交所提供之國內碳權交易，其碳權之主要來源為何？", options: ["國外進口碳權", "國內自願減量專案產生之碳權", "歐盟ETS配額", "聯合國CDM碳權"], answer: 1, explanation: "臺灣碳權交易所之國內碳權交易市場，主要交易國內自願減量專案經中央主管機關核發之「減量額度」，即國內碳權。", verified: true, chapter: "2.1" },
  { id: "S2-AI150", subject: 2, source: "ai", type: "single", question: "自願減量專案之「計入期」結束後，碳權是否還能繼續產生？", options: ["可無限延長", "不可再產生碳權，須重新申請註冊或申請展延", "自動延長", "由碳交所決定"], answer: 1, explanation: "計入期結束後，專案不得再依據原申請之方法學產生碳權。專案開發商可申請展延計入期或重新提交專案設計文件申請註冊，但須符合當時有效之方法學及標準要求。", verified: true, chapter: "2.1" },
  { id: "S2-AI151", subject: 2, source: "ai", type: "single", question: "碳移除技術CCUS中之「U」代表何種含義？", options: ["Under（地下）", "Utilization（利用）", "Upgrade（升級）", "Unification（統一）"], answer: 1, explanation: "CCUS（Carbon Capture, Utilization and Storage）中的「U」代表「Utilization」（利用），即將捕獲之二氧化碳轉化為有價值之產品，如合成燃料、化學品、建材等，與封存（Storage）並列為碳管理路徑之一。", verified: true, chapter: "2.2" },
  { id: "S2-AI152", subject: 2, source: "ai", type: "single", question: "直接空氣捕捉（DAC）技術之主要挑戰為何？", options: ["技術尚未被證明可行", "成本高昂且能源密集度高", "無法捕捉二氧化碳", "僅能捕捉小量二氧化碳"], answer: 1, explanation: "DAC（Direct Air Capture）技術從大氣中直接捕捉CO2，目前主要挑戰包括成本高昂（約每噸CO2 100-600美元）、能源密集度高（需大量低碳能源驅動），以及大氣CO2濃度低（約0.04%），處理效率受限。", verified: true, chapter: "2.2" },
  { id: "S2-AI153", subject: 2, source: "ai", type: "single", question: "下列何者為「自然碳匯」（Natural Carbon Sink）之範例？", options: ["DAC設施", "BECCS電廠", "森林、海洋、土壤", "碳捕獲與封存設備"], answer: 2, explanation: "自然碳匯係指自然生態系統吸收並儲存二氧化碳之能力，主要包括森林（Forest Carbon Sink）、海洋（Blue Carbon, 如紅樹林、海草床）及土壤（Soil Carbon）等。DAC及BECCS屬工程型碳移除技術。", verified: true, chapter: "2.2" },
  { id: "S2-AI154", subject: 2, source: "ai", type: "single", question: "BECCS（生質能與碳捕獲封存）之減碳原理為何？", options: ["直接從空氣中捕捉CO2", "燃燒生質能發電並將產生的CO2捕獲封存，形成負排放", "種植樹木吸收CO2", "使用太陽能取代化石燃料"], answer: 1, explanation: "BECCS（Bioenergy with Carbon Capture and Storage）燃燒生質物（如能源作物、廢棄木材）發電，產生之CO2排放經捕獲後封存於地質構造中。生質物生長期間吸收大氣CO2，加上碳封存，可達「負排放」效果。", verified: true, chapter: "2.2" },
  { id: "S2-AI155", subject: 2, source: "ai", type: "single", question: "土壤碳匯（Soil Carbon Sequestration）之主要作法為何？", options: ["施用化學肥料", "實施保護性農業（如不整地、覆蓋作物、輪作）增加土壤有機碳", "大面積灌溉", "施用殺蟲劑"], answer: 1, explanation: "土壤碳匯係透過農業管理措施增加土壤有機碳含量，主要作法包括：不整地耕作（No-till Farming）、覆蓋作物（Cover Crop）、輪作、施用有機質肥料及回歸牧草地等，有助於將大氣CO2固定於土壤中。", verified: true, chapter: "2.2" },
  { id: "S2-AI156", subject: 2, source: "ai", type: "single", question: "碳捕獲與封存（CCS）技術中，CO2封存之主要地質構造為何？", options: ["地下水層", "深部鹽水層、枯竭油氣層", "地表湖泊", "海洋表層"], answer: 1, explanation: "CO2地質封存主要選擇深部鹽水層（Deep Saline Aquifers）及枯竭油氣層（Depleted Oil and Gas Reservoirs）等地質構造，須有適當之蓋層（Caprock）防止CO2逸散。", verified: true, chapter: "2.2" },
  { id: "S2-AI157", subject: 2, source: "ai", type: "single", question: "IPCC評估報告中，何謂「負排放技術」（NETs）？", options: ["排放量為零之技術", "從大氣中移除溫室氣體之技術", "減少排放之技術", "提高能源效率之技術"], answer: 1, explanation: "負排放技術（Negative Emission Technologies, NETs）係指可從大氣中移除溫室氣體（尤其是CO2）之技術，如造林、DAC、BECCS、土壤碳匯、海洋鹼化、礦物碳化等。", verified: true, chapter: "2.2" },
  { id: "S2-AI158", subject: 2, source: "ai", type: "single", question: "臺灣推動自然碳匯之重點方向為何？", options: ["大規模引進外來樹種", "國有林地造林、森林經營、紅樹林復育及海洋碳匯", "砍伐原始森林改種經濟作物", "大面積填海造陸"], answer: 1, explanation: "臺灣自然碳匯推動重點包括：國有林地造林及森林經營增加森林碳匯、紅樹林與海草床復育增加藍碳（Blue Carbon）、以及農業土壤碳匯等，為十二項關鍵戰略之重要內容。", verified: true, chapter: "2.2" },
  { id: "S2-AI159", subject: 2, source: "ai", type: "single", question: "海洋碳匯（Blue Carbon）主要來自哪些生態系統？", options: ["深海熱泉", "紅樹林、海草床、鹽沼", "珊瑚礁", "大洋表層"], answer: 1, explanation: "藍碳（Blue Carbon）係指沿海生態系統所捕獲並儲存之碳，主要來自紅樹林（Mangroves）、海草床（Seagrasses）及鹽沼（Salt Marshes），其碳儲存速率及長期儲存能力遠高於陸域森林。", verified: true, chapter: "2.2" },
  { id: "S2-AI160", subject: 2, source: "ai", type: "single", question: "礦物碳化（Mineral Carbonation）之碳移除原理為何？", options: ["將CO2注入地下岩層", "利用礦物（如橄欖石）與CO2反應生成穩定碳酸鹽礦物", "將CO2溶解於海水", "利用微生物將CO2轉化為甲烷"], answer: 1, explanation: "礦物碳化係利用天然礦物（如橄欖石、蛇紋石等富含鎂鈣之矽酸鹽礦物）與CO2進行化學反應，生成穩定之碳酸鹽礦物（如菱鎂礦、方解石），將CO2永久固定於固態礦物中。", verified: true, chapter: "2.2" },
  { id: "S2-AI161", subject: 2, source: "ai", type: "single", question: "CCS技術中，CO2運輸之主要方式為何？", options: ["卡車運輸", "管道運輸及船舶運輸", "空運", "鐵路運輸"], answer: 1, explanation: "CCS中CO2運輸主要透過管道（Pipeline）及船舶（Ship）兩種方式。管道運輸適用於陸域大規模連續輸送，船舶運輸則適用於跨海或分散式小規模運輸。", verified: true, chapter: "2.2" },
  { id: "S2-AI162", subject: 2, source: "ai", type: "single", question: "下列何者為增強風化（Enhanced Weathering）之碳移除機制？", options: ["加速岩石自然風化過程以吸收大氣CO2", "使用強風加速碳循環", "人工增加降水以吸收CO2", "增加土壤侵蝕以釋放礦物質"], answer: 0, explanation: "增強風化（Enhanced Weathering）係將磨碎之矽酸鹽礦物（如橄欖石、玄武岩）散布於農田或海岸，加速其與大氣CO2之自然風化反應，將CO2轉化為溶解性碳酸氫鹽或固態碳酸鹽，達到碳移除效果。", verified: true, chapter: "2.2" },
  { id: "S2-AI163", subject: 2, source: "ai", type: "single", question: "碳移除技術中，DAC與BECCS之主要差異為何？", options: ["DAC為直接從空氣捕捉CO2，BECCS為燃燒生質物後捕捉排放之CO2", "兩者完全相同", "DAC成本較低", "BECCS不需封存"], answer: 0, explanation: "DAC（Direct Air Capture）係直接從大氣中捕捉CO2（非排放源端），可安裝於任何地點；BECCS則是在生質能發電廠之排放源端捕捉燃燒產生之CO2，兩者之技術原理及應用情境不同。", verified: true, chapter: "2.2" },
  { id: "S2-AI164", subject: 2, source: "ai", type: "single", question: "我國碳捕集與封存技術推動之主管機關為何？", options: ["環境部", "經濟部能源署", "國家發展委員會", "內政部"], answer: 1, explanation: "碳捕集與封存（CCS）技術之推動由經濟部能源署主政，整合相關部會資源，推動CCUS技術研發、示範驗證及法規調適等工作。", verified: true, chapter: "2.2" },
  { id: "S2-AI165", subject: 2, source: "ai", type: "single", question: "碳匯（Carbon Sink）之定義為何？", options: ["排放碳之來源", "任何可吸收並儲存大氣中碳量之系統", "碳交易市場", "碳費收入"], answer: 1, explanation: "碳匯（Carbon Sink）係指從大氣中吸收二氧化碳並將其儲存之自然或人工系統，如森林、土壤、海洋及碳封存設施等。與「碳源」（Carbon Source）相對。", verified: true, chapter: "2.2" },
  { id: "S2-AI166", subject: 2, source: "ai", type: "single", question: "碳封存之監測、報告與驗證（MRV）機制之主要目的為何？", options: ["提高碳封存成本", "確保CO2封存之安全性及永久性", "加速碳封存速度", "減少碳封存量"], answer: 1, explanation: "MRV（Monitoring, Reporting and Verification）機制用於監測CO2封存之洩漏風險、驗證封存量及報告封存狀態，確保封存之安全性、永久性及環境完整性。", verified: true, chapter: "2.2" },
  { id: "S2-AI167", subject: 2, source: "ai", type: "single", question: "下列哪項碳移除技術被認為具有最高之碳移除潛力？", options: ["DAC", "造林", "土壤碳匯", "海洋鹼化"], answer: 0, explanation: "DAC（Direct Air Capture）技術理論上具有極高之碳移除潛力（IPCC評估可達每年數十億噸CO2），惟目前成本高昂且仍在開發階段。各種碳移除技術各有潛力與局限性。", verified: true, chapter: "2.2" },
  { id: "S2-AI168", subject: 2, source: "ai", type: "single", question: "臺灣藍碳（Blue Carbon）之主要發展潛力為何？", options: ["深海碳封存", "紅樹林復育及海草床保護", "海洋酸鹼化", "深海採礦"], answer: 1, explanation: "臺灣藍碳發展主要聚焦於紅樹林復育、海草床保護及鹽沼生態系統之復育與管理，這些生態系統之碳儲存效率高，且效益包含生物多樣性保護及海岸保護等共同效益。", verified: true, chapter: "2.2" },
  { id: "S2-AI169", subject: 2, source: "ai", type: "single", question: "BECCS技術提供負排放之過程中，若生質物來自能源作物，可能產生何種疑慮？", options: ["二氧化碳排放增加", "與糧食作物爭地、水資源消耗及生物多樣性影響", "能源轉換效率過高", "無法產生電力"], answer: 1, explanation: "大規模種植能源作物作為BECCS原料，可能引發「糧食vs能源」之土地競爭、水資源消耗、肥料使用造成之碳排放、生物多樣性喪失及土地使用變更之間接排放等永續性疑慮。", verified: true, chapter: "2.2" },
  { id: "S2-AI170", subject: 2, source: "ai", type: "single", question: "海洋鹼化（Ocean Alkalinity Enhancement）之碳移除機制為何？", options: ["增加海水溫度以吸收CO2", "添加鹼性物質（如石灰石、橄欖石）至海洋，增加海水鹼度以吸收大氣CO2", "降低海水pH值", "減少海水鹽度"], answer: 1, explanation: "海洋鹼化係將鹼性物質（如石灰石CaCO3、橄欖石Mg2SiO4）添加至海洋，增加海水鹼度（Alkalinity），促進大氣CO2溶解於海水並轉化為穩定之碳酸氫鹽（Bicarbonate），達到長期碳儲存效果。", verified: true, chapter: "2.2" },
  { id: "S2-AI171", subject: 2, source: "ai", type: "single", question: "紅樹林碳匯相較於陸域森林之優勢為何？", options: ["成長速度較慢", "碳儲存時間較長且單位面積碳儲存量較高", "維護成本較高", "面積較大"], answer: 1, explanation: "紅樹林之碳儲存速率及單位面積碳儲存量通常高於陸域森林。紅樹林的碳不僅儲存於植物體，亦大量儲存於厭氧之土壤沉積物中，分解緩慢，碳儲存時間可達數百年至數千年。", verified: true, chapter: "2.2" },
  { id: "S2-AI172", subject: 2, source: "ai", type: "single", question: "我國「碳權交易」制度中，碳權主要得用於哪些用途？", options: ["僅供碳費抵減", "僅供自願碳中和", "碳費抵減、自願碳中和及交易", "僅供金融投資"], answer: 2, explanation: "碳權交易制度下，經核發之減量額度（碳權）得用於：1)抵減碳費；2)企業自願碳中和宣告；3)於碳權交易平台進行買賣交易。用途多元以促進碳市場流動性。", verified: true, chapter: "2.3" },
  { id: "S2-AI173", subject: 2, source: "ai", type: "single", question: "歐盟排放交易系統（EU ETS）屬於何種類型之碳市場？", options: ["自願碳市場", "總量管制與交易（Cap-and-Trade）之強制碳市場", "碳費制度", "碳稅制度"], answer: 1, explanation: "EU ETS（歐盟排放交易系統）為全球最大之強制碳交易市場，採用「總量管制與交易（Cap-and-Trade）」機制，設定排放總量上限並逐年遞減，排放源須持有足夠配額以涵蓋其排放量。", verified: true, chapter: "2.3" },
  { id: "S2-AI174", subject: 2, source: "ai", type: "single", question: "自願碳市場（VCM）與強制碳市場（CCM）之主要差異為何？", options: ["自願市場價格較高", "自願市場係企業自願購買碳權實現減碳承諾，強制市場係依法律義務購買配額或碳權", "強制市場僅限歐盟", "自願市場僅限開發中國家"], answer: 1, explanation: "自願碳市場係企業、組織或個人自發性購買碳權以達成自願減碳目標（如碳中和、ESG承諾）之市場；強制碳市場則是因應法律強制減排義務（如EU ETS、加州ETS）而產生之遵約交易市場。", verified: true, chapter: "2.3" },
  { id: "S2-AI175", subject: 2, source: "ai", type: "single", question: "碳抵換（Carbon Offset）之基本原則為何？", options: ["排放量抵銷必須在同一地點進行", "一單位碳抵換應代表一公噸CO2e之真實減量或移除", "碳抵換僅限於國內", "碳抵換價格由政府制定"], answer: 1, explanation: "碳抵換之基本原則是：一單位碳抵換（Carbon Offset/Credit）應確實代表1公噸CO2e之減量或移除，且須符合真實、永久、外加、可查證、不重複計算等品質原則。", verified: true, chapter: "2.3" },
  { id: "S2-AI176", subject: 2, source: "ai", type: "single", question: "國際碳市場中，何謂「碳排放配額」（Allowance）？", options: ["政府免費核發或拍賣之排放許可，允許排放源排放一定量之CO2e", "碳權憑證", "碳費收據", "排放量申報表"], answer: 0, explanation: "碳排放配額（Allowance）係總量管制與交易制度（Cap-and-Trade）下，主管機關核發給排放源之排放許可，每一配額代表允許排放1公噸CO2e之權利。配額可拍賣或免費核發。", verified: true, chapter: "2.3" },
  { id: "S2-AI177", subject: 2, source: "ai", type: "single", question: "碳交易市場中，何謂「市場穩定機制」（Market Stability Reserve, MSR）？", options: ["由政府設定碳價天花板", "調整市場流動性以穩定碳價之機制", "限制碳交易數量", "禁止碳權進口"], answer: 1, explanation: "EU ETS之市場穩定機制（MSR）係透過自動調節市場配額供給量來穩定碳價，當市場流通總量過多時，MSR吸收部分配額；過少時則釋出配額，以維持市場供需平衡及價格信號穩定。", verified: true, chapter: "2.3" },
  { id: "S2-AI178", subject: 2, source: "ai", type: "single", question: "碳抵換中「減量型碳權」（Emission Reduction Credit）與「移除型碳權」（Removal Credit）之差異為何？", options: ["兩者完全相同", "減量型係減少排放（如避免毀林），移除型係從大氣中移除已排放之CO2（如DAC、造林）", "移除型價格較低", "減量型僅適用於能源業"], answer: 1, explanation: "減量型碳權（Reduction Credits）來自避免或減少溫室氣體排放之專案，如再生能源取代化石燃料、工業廢氣捕捉等；移除型碳權（Removal Credits）來自直接從大氣中移除CO2之專案，如造林、DAC、BECCS等。", verified: true, chapter: "2.3" },
  { id: "S2-AI179", subject: 2, source: "ai", type: "multiple", question: "下列哪些屬於碳交易市場中碳權價格之主要影響因素？", options: ["市場供需", "碳權品質與認證標準", "政策與法規變動", "企業品牌顏色"], answers: [0, 1, 2], explanation: "碳權價格主要受市場供需動態、碳權品質（認證標準、vintage、專案類型）、政策法規（如碳費費率、ETS配額減量率）、宏觀經濟狀況及市場預期等因素影響，與企業品牌顏色無關。", verified: true, chapter: "2.3" },
  { id: "S2-AI180", subject: 2, source: "ai", type: "single", question: "臺灣碳權交易所提供之碳權交易分為哪兩大類？", options: ["國內碳權與國外碳權", "碳配額與碳抵換", "強制碳權與自願碳權", "現貨碳權與期貨碳權"], answer: 0, explanation: "臺灣碳權交易所提供「國內碳權」（來自國內自願減量專案）及「國外碳權」（引進國際認證碳權如VCS、GS）兩大類交易服務，以滿足企業多元需求。", verified: true, chapter: "2.3" },
  { id: "S2-AI181", subject: 2, source: "ai", type: "single", question: "碳交易市場中，何謂「碳洩漏補償」（Carbon Leakage Compensation）機制？", options: ["向碳洩漏產業課徵罰款", "對高碳洩漏風險產業免費核發部分配額，減輕其碳成本負擔", "禁止高碳排產業參與碳交易", "要求產業繳納額外保證金"], answer: 1, explanation: "為防止碳洩漏，EU ETS等碳交易制度對經認定之高碳洩漏風險產業（如鋼鐵、水泥、石化等）採取免費核發部分配額（Free Allocation）之措施，以減輕其碳成本負擔並維持國際競爭力。", verified: true, chapter: "2.3" },
  { id: "S2-AI182", subject: 2, source: "ai", type: "single", question: "我國碳交所引進之國外碳權，主要來自哪些認證標準？", options: ["僅Verra VCS", "僅Gold Standard", "Verra VCS及Gold Standard等國際認證標準", "僅歐盟ETS"], answer: 2, explanation: "臺灣碳交所引進之國外碳權主要來自國際自願碳市場認證標準，包括Verra VCS、Gold Standard等，以確保碳權品質符合國際標準。", verified: true, chapter: "2.3" },
  { id: "S2-AI183", subject: 2, source: "ai", type: "single", question: "碳交易中，何謂「拍賣」（Auction）機制？", options: ["碳權由出價最高者得標之分配方式", "碳權以固定價格販售", "碳權由抽籤決定分配", "碳權由政府免費分配"], answer: 0, explanation: "碳交易市場中，「拍賣」係指將碳排放配額或碳權透過競標方式出售，由出價最高者得標。EU ETS自2013年起逐步提高配額拍賣比重，取代免費核發，以落實「汙染者付費」原則。", verified: true, chapter: "2.3" },
  { id: "S2-AI184", subject: 2, source: "ai", type: "single", question: "碳權交易中「現貨」（Spot）交易與「期貨」（Future）交易之差異為何？", options: ["現貨立即交割，期貨為未來特定日期交割", "現貨價格較高", "期貨不可轉讓", "現貨僅限國內交易"], answer: 0, explanation: "現貨交易（Spot Trading）係碳權於成交後立即（通常在兩個工作日內）移轉所有權及完成交割；期貨交易（Futures Trading）則係買賣雙方約定在未來特定日期以特定價格交割碳權。", verified: true, chapter: "2.3" },
  { id: "S2-AI185", subject: 2, source: "ai", type: "single", question: "EU ETS之配額年減量因子（Linear Reduction Factor, LRF）自2024年起調整為多少？", options: ["1.74%", "2.2%", "4.3%", "5.0%"], answer: 2, explanation: "EU ETS自2021年起將年減量因子由每年1.74%提高至2.2%，自2024年起再提高至4.3%，以加速減排進程，達成2030年較1990年減量55%之目標（Fit for 55）。", verified: true, chapter: "2.3" },
  { id: "S2-AI186", subject: 2, source: "ai", type: "single", question: "碳抵換專案中，何謂「基線與信用」（Baseline-and-Credit）機制？", options: ["由主管機關設定排放上限", "專案透過證明其排放低於基準線來產生碳信用", "由政府分配排放配額", "透過競標取得排放權"], answer: 1, explanation: "基線與信用（Baseline-and-Credit）係自願減量專案之核心機制：設定合理之基準線排放量，專案實際排放若低於基準線，減量部分經查證後核發碳信用（Carbon Credit）。此與總量管制交易之「Cap-and-Trade」不同。", verified: true, chapter: "2.3" },
  { id: "S2-AI187", subject: 2, source: "ai", type: "single", question: "碳權品質判斷中，「避免雙重計算」（No Double Counting）之意義為何？", options: ["碳權不可重複使用於多個目的或由多方主張", "碳權價格不可重複計算", "碳權不可多次交易", "碳權不可跨國移動"], answer: 0, explanation: "避免雙重計算係碳權品質之核心原則，指同一單位碳權不得同時被用於多個減碳主張（如同時計入出口國與進口國之NDC、或同時被賣方與買方使用），須有明確之歸屬及註銷程序。", verified: true, chapter: "2.3" },
  { id: "S2-AI188", subject: 2, source: "ai", type: "single", question: "碳交易中，碳權「註銷」（Retirement）之意義為何？", options: ["碳權到期失效", "碳權經使用後永久退出市場，不得再流通或主張", "碳權被退回發行機構", "碳權轉換為配額"], answer: 1, explanation: "碳權「註銷」（Retirement）係指碳權經買方使用（如用於碳中和宣告）後，於碳權註冊機構中永久移除，確保該碳權不再流通市場或被他人重複使用。註銷記錄須公開透明。", verified: true, chapter: "2.3" },
  { id: "S2-AI189", subject: 2, source: "ai", type: "single", question: "碳交易價格之「價格上限」（Price Ceiling）機制之目的為何？", options: ["防止碳價過高影響產業競爭力", "確保碳價維持高水準", "提高市場參與率", "降低碳權品質要求"], answer: 0, explanation: "價格上限（Price Ceiling）係碳交易制度中為避免碳價過高對產業造成不可承受之衝擊所設定之價格天花板。當碳價觸及上限時，主管機關可釋出額外配額或允許購買碳權以穩定價格。", verified: true, chapter: "2.3" },
  { id: "S2-AI190", subject: 2, source: "ai", type: "single", question: "EU ETS自2024年起，是否將海運業納入碳交易涵蓋範圍？", options: ["是，海運業自2024年起逐步納入EU ETS", "否，海運業完全排除", "僅納入客運船舶", "僅納入貨運船舶"], answer: 0, explanation: "EU ETS自2024年起逐步將海運業納入涵蓋範圍，2024年要求海運業者繳交40%排放量之配額，2025年提高至70%，2026年達100%。", verified: true, chapter: "2.3" },
  { id: "S2-AI191", subject: 2, source: "ai", type: "single", question: "碳交易市場之「流動性」（Liquidity）為何重要？", options: ["降低交易成本並促進價格發現", "提高碳權價格", "增加市場波動", "減少市場參與者"], answer: 0, explanation: "市場流動性係指資產能快速以合理價格買賣之能力。碳市場流動性高時，交易成本較低、價格發現功能較佳、市場效率較高，有助於吸引更多參與者並促進碳定價機制之有效性。", verified: true, chapter: "2.3" },
  { id: "S2-AI192", subject: 2, source: "ai", type: "single", question: "碳價下限（Price Floor）在碳交易制度中之功能為何？", options: ["確保碳價不會過低，維持減碳投資誘因", "降低碳價", "增加碳權供給", "取消碳交易"], answer: 0, explanation: "碳價下限（Price Floor）確保碳價維持於一定水準以上，避免因供過於求導致碳價崩跌，以維持低碳投資之經濟誘因及碳市場之減碳效果。英國碳價支援機制即為碳價下限之範例。", verified: true, chapter: "2.3" },
  { id: "S2-AI193", subject: 2, source: "ai", type: "single", question: "碳交易市場中「碳權經紀人」之主要功能為何？", options: ["代替政府監管碳市場", "協助買賣雙方媒合交易、提供市場資訊及流動性", "核發碳權", "設定碳價"], answer: 1, explanation: "碳權經紀人（Carbon Broker）在碳交易市場中扮演中介角色，協助買賣雙方媒合交易、提供市場價格資訊、管理交易風險並促進市場流動性。", verified: true, chapter: "2.3" },
  { id: "S2-AI194", subject: 2, source: "ai", type: "single", question: "我國碳交所之國外碳權交易，碳權來源是否包含國際核證減排量（CER）？", options: ["包含CER", "不包含CER，以自願碳市場標準為限", "僅包含CER", "僅包含歐盟ETS配額"], answer: 1, explanation: "臺灣碳交所之國外碳權產品主要來自國際自願碳市場認證標準（如Verra VCS、Gold Standard），不包含京都議定書下之核證減排量（CERs）或歐盟ETS配額。", verified: true, chapter: "2.3" },
  { id: "S2-AI195", subject: 2, source: "ai", type: "single", question: "某企業持有碳權10000單位（VCU），若欲用於抵減碳費，假設每單位可抵減300元碳費且抵減比率為20%，則該企業最多可抵減多少碳費？", options: ["30萬元", "60萬元", "300萬元", "100萬元"], answer: 1, explanation: "計算：10000單位 × 300元/單位 × 20% = 600,000元 = 60萬元。碳權抵減碳費時，須依中央主管機關規定之抵減比率及評估方式辦理，實際計算方式以法規為準。", verified: true, chapter: "2.3" },
  { id: "S2-AI196", subject: 2, source: "ai", type: "single", question: "內部碳定價（Internal Carbon Pricing）之主要目的為何？", options: ["對外銷售碳權", "將碳排放成本內部化，引導企業投資決策朝向低碳選項", "向員工收取碳費", "取代政府碳費"], answer: 1, explanation: "內部碳定價係企業自願將碳排放成本內部化，設定每噸碳排放之「影子價格」或「內部碳費」，用以評估投資專案、採購決策及產品定價，引導企業資源配置朝向低碳選項。", verified: true, chapter: "2.4" },
  { id: "S2-AI197", subject: 2, source: "ai", type: "single", question: "企業導入內部碳定價之主要類型包含哪些？", options: ["僅影子價格（Shadow Price）", "影子價格、內部碳費及隱含碳價", "僅內部碳費", "僅政府碳費"], answer: 1, explanation: "內部碳定價主要有三種類型：1)影子價格（Shadow Price）—用於投資評估之假設性碳價；2)內部碳費（Internal Carbon Fee）—實際課徵並用於減碳基金；3)隱含碳價（Implicit Carbon Price）—由減碳投資成本回推之碳價。", verified: true, chapter: "2.4" },
  { id: "S2-AI198", subject: 2, source: "ai", type: "single", question: "碳資產管理（Carbon Asset Management）之核心範疇為何？", options: ["僅碳權買賣", "碳權取得、持有、交易及風險管理之全流程管理", "僅碳排放計算", "僅碳費繳納"], answer: 1, explanation: "碳資產管理涵蓋碳權（或碳配額）之取得、持有、交易、註銷等全生命週期管理，包括碳資產價值評估、市場風險管理、法律合規及策略規劃等面向。", verified: true, chapter: "2.4" },
  { id: "S2-AI199", subject: 2, source: "ai", type: "single", question: "企業在設定內部碳價時，通常參考哪些因素？", options: ["僅參考政府碳費費率", "政府碳費、碳交易價格、減碳成本及國際碳價趨勢", "僅參考歐盟ETS價格", "僅參考同行業水準"], answer: 1, explanation: "企業設定內部碳價時，通常綜合參考政府碳費費率、國內外碳交易市場價格、自身減碳技術成本、國際碳價趨勢及利害關係人預期等因素，以設定合理且具引導效果之碳價水準。", verified: true, chapter: "2.4" },
  { id: "S2-AI200", subject: 2, source: "ai", type: "single", question: "碳會計（Carbon Accounting）與財務會計之主要關係為何？", options: ["完全獨立", "碳資訊可納入財務報告，影響資產評價及負債認列", "碳會計取代財務會計", "兩者無關聯"], answer: 1, explanation: "隨著永續揭露準則發展（如IFRS S2），碳會計資訊（如排放量、碳價、碳權）逐漸納入財務報告中，影響企業之資產評價（如碳權）、負債認列（如碳費義務）及風險揭露。", verified: true, chapter: "2.4" },
  { id: "S2-AI201", subject: 2, source: "ai", type: "single", question: "企業導入「內部碳費」機制後，所收取之碳費通常用於何處？", options: ["分配給股東", "投入企業內部減碳專案或低碳技術研發", "繳納給政府", "用於員工福利"], answer: 1, explanation: "企業內部碳費所收取之資金，通常專款專用於企業內部減碳專案、低碳技術研發、能源效率改善或員工減碳培訓等，形成企業內部之減碳資金循環。", verified: true, chapter: "2.4" },
  { id: "S2-AI202", subject: 2, source: "ai", type: "single", question: "碳資產管理中，「碳權組合管理」之策略目的為何？", options: ["最大化碳權買賣價差", "分散碳權類型、年限及來源風險，確保碳資產價值穩定", "集中持有單一類型碳權", "避免持有碳權"], answer: 1, explanation: "碳權組合管理係透過持有不同類型（減量型/移除型）、不同vintage、不同認證標準（VCS/GS）及不同地域之碳權，以分散市場風險、價格波動風險及政策風險。", verified: true, chapter: "2.4" },
  { id: "S2-AI203", subject: 2, source: "ai", type: "single", question: "企業揭露內部碳定價資訊時，依TCFD/IFRS S2要求應揭露哪些內容？", options: ["僅揭露碳價金額", "是否應用碳定價、碳價水準、應用範圍及對營運之影響", "僅揭露應用範圍", "無須揭露"], answer: 1, explanation: "IFRS S2及TCFD建議企業揭露：是否應用碳定價、碳定價類型（影子價格/內部碳費）、碳價金額、應用範圍（哪些業務/地區）以及碳價對營運決策及財務規劃之影響。", verified: true, chapter: "2.4" },
  { id: "S2-AI204", subject: 2, source: "ai", type: "single", question: "碳資產管理中，何謂「碳項目投資」（Carbon Project Investment）？", options: ["購買碳權期貨", "直接投資開發減碳或碳移除專案以產生碳權", "投資碳交易所", "購買碳權ETF"], answer: 1, explanation: "碳項目投資係指企業直接投資於減碳或碳移除專案（如造林、再生能源、CCUS等），以取得未來產生之碳權，同時獲得減碳效益及潛在之財務回報。", verified: true, chapter: "2.4" },
  { id: "S2-AI205", subject: 2, source: "ai", type: "single", question: "企業評估碳資產價值時，主要考量哪些風險因子？", options: ["僅價格風險", "價格風險、品質風險、政策風險、聲譽風險及永久性風險", "僅信用風險", "僅匯率風險"], answer: 1, explanation: "碳資產價值評估須綜合考量多種風險：價格風險（碳價波動）、品質風險（碳權真實性）、政策風險（法規變動）、聲譽風險（漂綠爭議）及永久性風險（碳逆轉可能性）。", verified: true, chapter: "2.4" },
  { id: "S2-AI206", subject: 2, source: "ai", type: "single", question: "CDP（碳揭露專案）評分中，若企業設有內部碳定價，對其評分有何影響？", options: ["無影響", "評分可能提升，因CDP認可內部碳定價為良好治理實務", "評分下降", "視碳價高低而定"], answer: 1, explanation: "CDP評分將內部碳定價視為企業氣候治理之良好實務，企業若有設定內部碳定價機制，有助於在CDP評分中獲得較高之成績，尤其在Management（B）或Leadership（A）等級。", verified: true, chapter: "2.4" },
  { id: "S2-AI207", subject: 2, source: "ai", type: "single", question: "碳資產管理中，「碳權融資」（Carbon Financing）之運作模式為何？", options: ["以碳權作為擔保品取得融資", "碳權作為股票發行", "以碳權支付員工薪資", "碳權作為股利發放"], answer: 0, explanation: "碳權融資係指企業以其持有之碳權作為擔保品，向金融機構取得融資資金，或透過碳權預售合約取得專案開發資金。此為碳資產金融化之重要應用。", verified: true, chapter: "2.4" },
  { id: "S2-AI208", subject: 2, source: "ai", type: "single", question: "企業設定內部「影子價格」（Shadow Price）之主要用途為何？", options: ["實際收取碳費", "用於投資決策評估、專案篩選及成本效益分析", "取代財務報表", "設定產品售價"], answer: 1, explanation: "影子價格（Shadow Price）為企業內部設定之假設性碳價，並非實際收取之費用，主要用於投資決策評估，如新建工廠、設備採購、產品開發等專案之成本效益分析，將碳成本納入決策考量。", verified: true, chapter: "2.4" },
  { id: "S2-AI209", subject: 2, source: "ai", type: "single", question: "碳資產管理之「避險」（Hedge）策略通常如何操作？", options: ["避免持有任何碳資產", "透過期貨、選擇權等衍生性金融工具鎖定碳權價格，降低價格波動風險", "集中持有現貨", "僅持有單一類型碳權"], answer: 1, explanation: "碳資產避險策略係利用碳權期貨、選擇權、交換契約（Swap）等衍生性金融工具，鎖定未來碳權買賣價格，以管理碳價波動造成之財務風險。", verified: true, chapter: "2.4" },
  { id: "S2-AI210", subject: 2, source: "ai", type: "single", question: "企業導入內部碳定價制度時，常見之挑戰為何？", options: ["技術不可行", "組織內部共識不足、碳價設定缺乏依據及跨部門執行困難", "成本為零", "無任何挑戰"], answer: 1, explanation: "企業導入內部碳定價之常見挑戰包括：各部門對碳價水準及實施範圍缺乏共識、碳價設定缺乏科學依據及市場參考、跨部門執行協調困難、管理階層支持度不足等。", verified: true, chapter: "2.4" },
  { id: "S2-AI211", subject: 2, source: "ai", type: "single", question: "碳資產管理中，「碳中和策略」之規劃包含哪些步驟？", options: ["僅購買碳權", "盤查排放、設定目標、減量行動、剩餘排放抵換及進度追蹤", "僅計算排放量", "僅公告碳中和目標"], answer: 1, explanation: "企業碳中和策略規劃包含完整路徑：1)盤查碳排放（範疇一、二、三）；2)設定科學基礎減量目標；3)執行減量行動（能源效率、再生能源等）；4)剩餘排放購買碳權抵換；5)定期監測及進度報告。", verified: true, chapter: "2.4" },
  { id: "S2-AI212", subject: 2, source: "ai", type: "single", question: "依ISO 14064-1:2018，溫室氣體盤查之六大類別中，類別1指的是什麼？", options: ["間接能源排放", "直接排放（固定源與移動源之排放）", "運輸排放", "其他間接排放"], answer: 1, explanation: "ISO 14064-1:2018類別1（Category 1）為「直接排放」，包括固定源燃燒、移動源燃燒、製程排放、逸散排放等直接來自組織擁有或控制之排放源的溫室氣體排放。", verified: true, chapter: "2.4" },
  { id: "S2-AI213", subject: 2, source: "ai", type: "single", question: "企業碳資產管理者應具備哪些核心能力？", options: ["僅財務分析能力", "碳盤查、碳權知識、市場分析、法規遵循及風險管理", "僅資訊科技能力", "僅行銷能力"], answer: 1, explanation: "碳資產管理人員須具備跨領域能力：1)碳盤查與會計；2)碳市場與碳權知識；3)法律法規遵循；4)市場分析與交易；5)風險管理；6)策略規劃與溝通協調等。", verified: true, chapter: "2.4" },
  { id: "S2-AI214", subject: 2, source: "ai", type: "single", question: "碳資產管理中，如何處理碳權價值減損（Impairment）之會計問題？", options: ["無需處理", "當碳權價格持續下跌或碳權品質受損時，須評估是否認列減損損失", "一律以成本列帳", "每年重新評價"], answer: 1, explanation: "碳權屬於無形資產，依適用之會計準則（如IFRS/IAS 38），當碳權之市場價格持續下跌、效期將屆或品質受損時，企業應進行減損測試，必要時認列減損損失。", verified: true, chapter: "2.4" },
  { id: "S2-AI215", subject: 2, source: "ai", type: "single", question: "世界銀行「碳定價現況與趨勢報告」中，全球採用碳定價機制之趨勢為何？", options: ["逐年減少", "持續擴大，越來越多的國家及地區採用碳費或碳交易制度", "維持不變", "僅歐盟採用"], answer: 1, explanation: "根據世界銀行報告，全球碳定價機制持續擴大，截至2024年已有超過70個國家或地區實施碳費、碳稅或碳交易制度，涵蓋全球約24%之溫室氣體排放。", verified: true, chapter: "2.4" },
  { id: "S2-AI216", subject: 2, source: "ai", type: "multiple", question: "下列哪些屬於ISO 14064-1:2018之六大排放類別？", options: ["類別1：直接排放", "類別2：間接能源排放", "類別3：運輸排放", "類別7：碳匯排放"], answers: [0, 1, 2], explanation: "ISO 14064-1:2018之六大排放類別為：類別1（直接排放）、類別2（間接能源排放）、類別3（運輸排放）、類別4（組織使用產品排放）、類別5（使用組織產品排放）、類別6（其他間接排放）。無類別7。", verified: true, chapter: "2.4" },
  { id: "S2-AI217", subject: 2, source: "ai", type: "single", question: "碳資產管理中，何謂「碳權庫存管理」（Carbon Credit Inventory Management）？", options: ["碳權倉儲管理", "對持有碳權之數量、類型、vintage、效期及用途進行系統化管理", "碳權實體保管", "碳權分類"], answer: 1, explanation: "碳權庫存管理係指企業對其所持有之碳權進行系統化盤點與管理，包括記錄碳權數量、類型（減量型/移除型）、認證標準、vintage、效期及使用狀態（持有中/已指定用途/已註銷），以確保碳權之有效運用。", verified: true, chapter: "2.4" },
  
  
  
  
  { id: "S2-AI222", subject: 2, source: "ai", type: "single", question: "PCR（產品類別規則）在產品碳足跡評估中之功能為何？", options: ["規範產品之市場定價", "針對特定產品類別，制定碳足跡計算之規則與要求", "規範產品之品質標準", "規範產品之包裝方式"], answer: 1, explanation: "PCR（Product Category Rules）係針對特定產品類別制定之碳足跡計算規則，包括系統邊界、分配原則、數據品質要求及碳排放計算方法等，以確保同一類別產品碳足跡之可比性與一致性。", verified: true, chapter: "3.1" },
  { id: "S2-AI223", subject: 2, source: "ai", type: "single", question: "EPD（產品環境宣告）之主要功能為何？", options: ["產品品質認證", "基於生命週期評估之產品環境衝擊資訊透明化宣告", "產品安全認證", "產品效能標示"], answer: 1, explanation: "EPD（Environmental Product Declaration）係經第三方查證之產品環境衝擊資訊宣告文件，基於生命週期評估（LCA）方法，揭露產品之碳排放、能源消耗、水資源消耗等環境衝擊數據。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI225", subject: 2, source: "ai", type: "single", question: "範疇三排放數據之品質等級（數據品質評分）主要評估哪些面向？", options: ["僅數據價格", "技術代表性、時間代表性、地理代表性及完整性", "僅數據來源", "僅數據年份"], answer: 1, explanation: "範疇三排放數據品質評分（Data Quality Assessment）通常評估：技術代表性（Technology Representativeness）、時間代表性（Temporal Representativeness）、地理代表性（Geographical Representativeness）及數據完整性（Completeness）。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI227", subject: 2, source: "ai", type: "single", question: "範疇三排放中，員工通勤（Category 7）之碳排放計算需納入哪些數據？", options: ["僅員工人數", "員工通勤距離、交通工具類型及通勤頻率", "僅公司位置", "僅員工居住地"], answer: 1, explanation: "員工通勤排放計算需收集以下數據：員工居住地與工作地點之距離、主要通勤交通工具（汽車、大眾運輸、自行車等）、每週通勤次數及工作天數，並使用各交通工具之排放係數計算。", verified: true, chapter: "3.1" },
  
  
  { id: "S2-AI230", subject: 2, source: "ai", type: "single", question: "範疇三排放中，「使用銷售產品」（Category 11）之排放計算需考慮哪些項目？", options: ["僅產品製造排放", "產品在使用階段所消耗之能源（如電力、燃料）及相關排放", "僅產品包裝排放", "僅產品運輸排放"], answer: 1, explanation: "使用銷售產品排放（Category 11）涵蓋產品在使用過程中因消耗能源（電力、燃料等）所產生之溫室氣體排放，需考慮產品使用模式、使用壽命、能源消耗效率及能源排放係數等因素。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI232", subject: 2, source: "ai", type: "single", question: "供應商碳排放數據之「初級數據」（Primary Data）與「次級數據」（Secondary Data）之差異為何？", options: ["初級數據來自供應商實際量測，次級數據來自行業平均或資料庫", "初級數據較不精確", "次級數據較昂貴", "兩者無差異"], answer: 0, explanation: "初級數據（Primary Data）係由供應商直接量測或計算之實際排放數據，如電表讀數、燃料用量等，精確度較高；次級數據（Secondary Data）係使用行業平均值、資料庫係數或推估模型之數據，精確度較低但取得成本較低。", verified: true, chapter: "3.1" },
  { id: "S2-AI233", subject: 2, source: "ai", type: "single", question: "範疇三排放計算中，EEIO（環境擴展投入產出）模型之主要應用為何？", options: ["計算組織直接排放", "利用經濟投入產出表估算行業或產品供應鏈之碳排放", "計算範疇一排放", "計算碳移除量"], answer: 1, explanation: "EEIO（Environmentally Extended Input-Output）模型係將經濟投入產出表與環境排放數據結合，可估算各行業間因採購交易所產生之供應鏈碳排放，常用於範疇三排放之估算，特別是當供應商初級數據不足時。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI235", subject: 2, source: "ai", type: "single", question: "碳足跡計算常用之生命週期評估資料庫包含哪些？", options: ["僅台灣政府資料庫", "ecoinvent、GaBi、EXIOBASE等國際資料庫", "僅世界銀行資料", "僅歐盟統計局資料"], answer: 1, explanation: "國際上常用之生命週期評估資料庫包括：ecoinvent（瑞士）、GaBi（德國）、EXIOBASE（歐盟）等，提供各行業、各區域之排放係數與生命週期盤查數據，為碳足跡計算重要之次級數據來源。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI237", subject: 2, source: "ai", type: "single", question: "範疇三排放類別中，「上游運輸與配送」（Category 4）之涵蓋範圍為何？", options: ["僅產品出貨運輸", "企業購買產品之運輸（上游運輸），包括供應商至企業之所有運輸活動", "僅員工通勤運輸", "僅物流中心營運"], answer: 1, explanation: "上游運輸與配送排放（Category 4）涵蓋從供應商到企業之間所有運輸與配送活動所產生之排放，包括原料、零組件及商品之運輸（陸運、海運、空運）及物流倉儲排放。", verified: true, chapter: "3.1" },
  { id: "S2-AI238", subject: 2, source: "ai", type: "single", question: "ISO 14064-3:2019 之主要規範內容為何？", options: ["組織層級溫室氣體盤查", "溫室氣體聲明之查證與確證", "產品碳足跡", "碳中和標準"], answer: 1, explanation: "ISO 14064-3:2019規範「溫室氣體聲明之查證與確證（Verification and Validation）」之原則與要求，包括查證流程、查證方法、查證報告及查證人員能力等。", verified: true, chapter: "3.1" },
  { id: "S2-AI239", subject: 2, source: "ai", type: "single", question: "範疇三排放計算中，「商務旅行」（Category 6）之排放計算需納入哪些項目？", options: ["僅航空旅行", "員工因公務出差之所有交通方式（航空、鐵路、汽車、住宿等）", "僅住宿費用", "僅交通費用"], answer: 1, explanation: "商務旅行排放（Category 6）涵蓋員工因公務出差所產生之所有交通運輸排放，包括航空旅行、鐵路、計程車、租賃車輛、住宿及相關活動產生之排放。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI241", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查中，全球暖化潛勢（GWP）之功能為何？", options: ["計算碳權價格", "將不同溫室氣體之排放量轉換為CO2e之指標", "計算能源消耗量", "評估碳移除效率"], answer: 1, explanation: "全球暖化潛勢（Global Warming Potential, GWP）係將不同溫室氣體（如CH4、N2O、HFCs等）之暖化效應轉換為二氧化碳當量（CO2e）之指標，以利比較與加總。IPCC定期更新GWP值。", verified: true, chapter: "3.1" },
  { id: "S2-AI242", subject: 2, source: "ai", type: "single", question: "GHG Protocol中，組織邊界（Organizational Boundary）之設定方式有哪兩種？", options: ["股權比例法與控制權法", "面積法與人數法", "直接法與間接法", "現場法與非現場法"], answer: 0, explanation: "GHG Protocol企業標準提供兩種組織邊界設定方式：1)股權比例法（Equity Share）—按持股比例計算排放量；2)控制權法（Control）—按財務或營運控制權歸屬計算排放量。企業應選擇並揭露其所使用之方法。", verified: true, chapter: "3.1" },
  { id: "S2-AI243", subject: 2, source: "ai", type: "single", question: "範疇三分類中，「廢棄物處理」（Category 5）之排放計算需考慮哪些項目？", options: ["僅一般垃圾", "企業營運產生之所有廢棄物處理（掩埋、焚化、回收等）所產生之排放", "僅事業廢棄物", "僅有害廢棄物"], answer: 1, explanation: "廢棄物處理排放（Category 5）涵蓋企業營運中產生之所有廢棄物（一般廢棄物、事業廢棄物、有害廢棄物、營建廢棄物等）在處理過程（掩埋、焚化、回收、堆肥等）中所產生之溫室氣體排放。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI245", subject: 2, source: "ai", type: "single", question: "排放係數（Emission Factor）之定義為何？", options: ["排放量之加權平均", "每單位活動數據所排放之溫室氣體量", "碳排放總量", "碳權價格"], answer: 1, explanation: "排放係數（Emission Factor, EF）係指每單位活動數據（如每度用電、每公升燃料、每公里運輸）所排放之溫室氣體量，單位通常為kg CO2e/單位活動。排放係數為碳排放計算之核心參數。", verified: true, chapter: "3.1" },
  { id: "S2-AI246", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，範疇三排放數據之「不確定性」（Uncertainty）主要來自何處？", options: ["數據來源不完整、使用推估值及排放係數誤差", "計算軟體錯誤", "人員操作失誤", "硬體設備故障"], answer: 0, explanation: "範疇三排放數據之不確定性主要來自：1)供應商數據覆蓋率不足（以推估替代）；2)活動數據之測量誤差；3)排放係數之代表性不足（時間、地理、技術）；4)計算假設之不確定性。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI248", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，「Biogenic CO2」（生質源二氧化碳）之處理方式為何？", options: ["視為一般碳排放", "獨立報告生質源CO2排放，不計入化石碳排放總量", "不須報告", "加倍計算"], answer: 1, explanation: "GHG Protocol及ISO 14067均要求將生質源CO2（如燃燒木質顆粒、生質燃料產生之CO2）與化石源CO2分別計算及報告。生質源CO2視為碳循環之一部分，不計入化石碳排放總量，但仍須獨立揭露。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI250", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查報告中，「重大性」（Materiality）原則之判斷基準通常為何？", options: ["排放量占總排放之比例，通常設定5%為門檻", "由查驗機構主觀判斷", "無需考慮重大性", "以排放量絕對值判斷"], answer: 0, explanation: "溫室氣體盤查中重大性原則通常以排放量占總排放之比例判斷。一般實務上，單一排放源若未達總排放量之5%（或查驗實務常用之特定門檻），可視為不重大，惟須於報告中說明遺漏項目及理由。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI252", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，「避免排放」（Avoided Emissions）之概念為何？", options: ["已實際減少之排放量", "產品或服務相較於替代方案所避免之碳排放，為額外揭露資訊", "碳權產生之減量", "法規要求之減量"], answer: 1, explanation: "避免排放（Avoided Emissions）係指企業之產品或服務相較於市場上既有替代方案，在使用過程中可幫助客戶減少之碳排放。此為自願性揭露資訊（如SBTi價值鏈外減量），非強制要求。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI254", subject: 2, source: "ai", type: "single", question: "產品類別規則（PCR）係根據何種國際標準制定？", options: ["ISO 9001", "ISO 14025（環境標誌與宣告）", "ISO 14001", "ISO 50001"], answer: 1, explanation: "產品類別規則（PCR）係依據ISO 14025（環境標誌與宣告—Type III環境宣告）之要求制定，為特定產品類別之EPD（產品環境宣告）提供統一之計算規則。", verified: true, chapter: "3.1" },
  { id: "S2-AI255", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，供應商排放數據之「保證等級」（Level of Assurance）分為哪兩種？", options: ["高保證與有限保證", "完全保證與部分保證", "初級保證與次級保證", "第一方與第三方"], answer: 0, explanation: "溫室氣體盤查查證之保證等級分為「高保證」（Reasonable Assurance）及「有限保證」（Limited Assurance）。高保證要求較嚴格之查證程序，確信程度較高；有限保證之查證程序範圍較小，確信程度較低。", verified: true, chapter: "3.1" },
  { id: "S2-AI256", subject: 2, source: "ai", type: "single", question: "範疇三排放中，「投資」（Category 15）之排放計算適用于哪類組織？", options: ["製造業", "金融機構、投資公司及退休基金等投資活動", "零售業", "服務業"], answer: 1, explanation: "投資排放（Category 15）主要適用於金融機構、投資公司、退休基金、主權基金等進行股權投資、債券投資及專案融資等活動之組織，須計算被投資對象之溫室氣體排放。", verified: true, chapter: "3.1" },
  { id: "S2-AI257", subject: 2, source: "ai", type: "single", question: "碳足跡資料庫中，排放係數之「時間代表性」係指？", options: ["排放係數之有效期", "排放係數所對應之數據年份或期間", "排放係數計算所需時間", "排放係數之更新頻率"], answer: 1, explanation: "排放係數之「時間代表性」（Temporal Representativeness）係指係數所反映之時間範圍，即該係數對應之數據收集年份。理想上應使用與評估期間最接近之排放係數，以提高準確性。", verified: true, chapter: "3.1" },
  { id: "S2-AI258", subject: 2, source: "ai", type: "single", question: "企業進行範疇三盤查時，應如何決定優先盤查之供應商？", options: ["隨機選擇", "依採購金額、排放熱點及供應商重要性進行分級篩選", "盤查所有供應商", "僅盤查前三大供應商"], answer: 1, explanation: "範疇三供應商盤查優先順序可依：1)採購金額（重大供應商）；2)排放熱點分析（高碳排供應商）；3)供應商重要性（獨家供應或策略合作）；4)數據可取得性等因素進行分級篩選，逐步擴充盤查範圍。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI260", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「綠色採購」（Green Procurement）？", options: ["採購價格最低之產品", "在採購決策中納入環境標準（如碳足跡、環保標章），優先選擇環保產品", "僅採購國內產品", "採購量最大化"], answer: 1, explanation: "綠色採購係指在採購決策中，除考量價格、品質及交期等傳統因素外，同時納入環境標準（如產品碳足跡、環保標章、供應商環境績效），優先採購對環境衝擊較低之產品或服務。", verified: true, chapter: "3.2" },
  { id: "S2-AI261", subject: 2, source: "ai", type: "single", question: "供應鏈碳風險評估中，「物理風險」對供應鏈之影響為何？", options: ["無影響", "極端天氣事件可能導致供應鏈中斷、原料供應不穩定及運輸網絡受損", "僅影響銷售", "僅影響定價"], answer: 1, explanation: "供應鏈之物理風險（Physical Risks）包括：極端天氣（颱風、洪水、乾旱）導致工廠停工、原料供應中斷、物流運輸受阻；慢性氣候變遷（海平面上升、平均溫度升高）影響長期供應穩定性。", verified: true, chapter: "3.2" },
  { id: "S2-AI262", subject: 2, source: "ai", type: "single", question: "企業推動供應商碳管理時，常見之供應商減碳誘因機制為何？", options: ["降低採購價格", "優先採購權、長期合約、技術支援及供應商獎勵計畫", "增加採購量", "縮短付款期限"], answer: 1, explanation: "企業可透過以下誘因機制鼓勵供應商減碳：1)優先採購權（表現優異之供應商享有優先接單權）；2)長期合約保障；3)提供技術支援及減碳輔導；4)供應商獎勵及表揚計畫；5)分享減碳效益。", verified: true, chapter: "3.2" },
  
  
  
  
  { id: "S2-AI267", subject: 2, source: "ai", type: "single", question: "供應鏈減碳中，何謂「產品碳足跡熱點」（Hotspot）？", options: ["產品銷售最熱門地區", "產品生命週期中碳排放占比最高之階段或製程", "產品價格最高點", "產品市場需求最大的地區"], answer: 1, explanation: "產品碳足跡熱點（Hotspot）係指產品生命週期中碳排放占比最高之階段或製程環節。透過熱點分析可識別關鍵減碳機會，集中資源於排放量最大之環節進行優化。", verified: true, chapter: "3.2" },
  
  
  { id: "S2-AI270", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業如何處理「碳洩漏」風險（即減碳導致排放轉移至未管制地區）？", options: ["無需處理", "透過供應商管理、採購策略及產品設計減少碳洩漏", "禁止供應商轉移生產", "增加進口關稅"], answer: 1, explanation: "企業可透過以下方式處理供應鏈碳洩漏風險：1)供應商篩選（優先選擇低碳供應商）；2)採購策略調整（在地採購減少運輸排放）；3)產品設計（模組化、輕量化）；4)供應鏈區域分散以降低集中風險。", verified: true, chapter: "3.2" },
  { id: "S2-AI271", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理資訊系統（如軟體平台）之主要功能為何？", options: ["僅數據儲存", "供應商碳排數據收集、計算、分析、報告及減碳追蹤", "僅財務管理", "僅供應商合約管理"], answer: 1, explanation: "供應鏈碳管理資訊系統整合以下功能：1)供應商碳排放數據收集與管理；2)排放計算與分析；3)排放熱點識別；4)減碳目標設定與進度追蹤；5)報告產出（CDP、GRI、TCFD等）；6)供應商溝通與能力建構。", verified: true, chapter: "3.2" },
  
  
  { id: "S2-AI274", subject: 2, source: "ai", type: "single", question: "CDP供應鏈評分中，供應商之評分結果對品牌企業有何影響？", options: ["無直接影響", "供應商評分結果納入品牌企業之CDP評分，影響品牌企業之供應鏈管理評價", "僅供應商受影響", "評分結果不公開"], answer: 1, explanation: "品牌企業之CDP供應鏈評分包含其供應商參與及管理績效，供應商之評分結果會反映於品牌企業之整體CDP評分中，因此品牌企業有誘因推動供應商提升CDP評分。", verified: true, chapter: "3.2" },
  
  
  
  { id: "S2-AI278", subject: 2, source: "ai", type: "single", question: "供應鏈減碳中，企業協助供應商進行碳管理能力建構（Capacity Building）之常見方式為何？", options: ["提供資金貸款", "舉辦教育訓練、提供盤查工具及分享最佳實務", "直接接管供應商", "要求供應商自行學習"], answer: 1, explanation: "供應商碳管理能力建構方式包括：1)舉辦教育訓練（碳盤查、減碳技術）；2)提供線上盤查工具及計算平台；3)分享減碳最佳實務與案例；4)提供專家顧問輔導；5)組織供應商交流研討會等。", verified: true, chapter: "3.2" },
  { id: "S2-AI279", subject: 2, source: "ai", type: "single", question: "供應鏈碳排放管理中，何謂「盤查邊界」（Inventory Boundary）之設定？", options: ["組織之國界範圍", "界定納入盤查之排放源、活動及範疇之範圍", "供應商之法律邊界", "產品之地理範圍"], answer: 1, explanation: "盤查邊界（Inventory Boundary）係指在供應鏈碳管理中，界定哪些排放源、活動及範疇應納入盤查範圍，包括組織邊界（哪些子公司或設施納入）及營運邊界（哪些範疇納入）之設定。", verified: true, chapter: "3.2" },
  
  
  
  { id: "S2-AI283", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「供應鏈排放集體行動」（Collective Action）？", options: ["多家企業共同向單一供應商要求減碳", "同業或跨業企業聯合推動供應鏈減碳，共享最佳實務及資源", "供應商自行組織減碳行動", "政府主導之供應鏈減碳"], answer: 1, explanation: "供應鏈排放集體行動係指同業或跨業企業聯合推動供應鏈減碳，如：1)共同開發供應商碳管理工具；2)共享供應商碳排數據庫；3)聯合舉辦供應商教育訓練；4)共同倡導供應鏈減碳標準化。", verified: true, chapter: "3.2" },
  { id: "S2-AI284", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「TCFD供應鏈風險」？", options: ["供應鏈財務風險", "依TCFD架構評估供應鏈之轉型風險與物理風險", "供應鏈法規風險", "供應鏈市場風險"], answer: 1, explanation: "TCFD供應鏈風險係指將TCFD風險分類架構應用於供應鏈碳管理，評估：1)轉型風險—碳定價、法規、市場偏好改變對供應鏈之影響；2)物理風險—極端氣候對供應鏈營運中斷之影響；3)對應之機會（效率提升、低碳產品等）。", verified: true, chapter: "3.2" },
  { id: "S2-AI285", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理之「生命周期思維」（Life Cycle Thinking）為何重要？", options: ["僅考慮產品價格", "從原料取得至最終處置系統性思考碳排放，避免碳轉移", "僅考慮使用階段", "僅考慮生產階段"], answer: 1, explanation: "生命週期思維要求從整體供應鏈角度系統性分析碳排放，避免「碳轉移」（Carbon Shifting）—即將排放從一個環節轉移至另一環節而未實質減碳，如從製造階段轉移至使用階段或廢棄階段。", verified: true, chapter: "3.2" },
  { id: "S2-AI286", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業對供應商之「淘汰機制」（Phase-out Mechanism）之設計原則為何？", options: ["直接淘汰高碳排供應商", "應先給予改善機會及期限，無法達標者再行淘汰，並考量供應鏈穩定性", "不淘汰任何供應商", "僅淘汰小型供應商"], answer: 1, explanation: "供應商淘汰機制應遵循逐步改善原則：1)設定明確之碳績效標準及改善期限；2)提供輔導及技術支援協助改善；3)定期評估改善進度；4)未達標準者啟動淘汰程序；5)同時考量供應商替換對供應鏈穩定之影響。", verified: true, chapter: "3.2" },
  { id: "S2-AI287", subject: 2, source: "ai", type: "single", question: "跨國企業供應鏈碳管理中，不同地區供應商之碳管理策略應如何調整？", options: ["全球統一標準", "依各地法規成熟度、供應商能力及排放特性採取差異化策略", "由供應商自行決定", "僅管理國內供應商"], answer: 1, explanation: "跨國供應鏈碳管理應因地制宜：已開發國家供應商可要求較高標準（如SBT、CDP揭露）；開發中國家供應商則應優先進行能力建構、基礎盤查及改善輔導，逐步提升碳管理要求。", verified: true, chapter: "3.2" },
  { id: "S2-AI288", subject: 2, source: "ai", type: "single", question: "供應鏈碳排放計算中，採用「支出法」（Spend-based Method）之優缺點為何？", options: ["精確度高但成本高", "數據取得容易、計算快速，但精確度較低", "兩者皆高", "兩者皆低"], answer: 1, explanation: "支出法（Spend-based Method）之優點：數據易取得（採購金額）、計算快速、成本較低；缺點：使用行業平均排放係數，未反映供應商實際排放，精確度較低，無法提供具體減碳方向。", verified: true, chapter: "3.2" },
  
  
  { id: "S2-AI291", subject: 2, source: "ai", type: "single", question: "企業推動供應鏈減碳時，如何衡量供應商減碳績效？", options: ["僅以排放量絕對值衡量", "以排放量趨勢、排放強度變化、目標達成率及揭露品質綜合衡量", "僅以排放強度衡量", "僅以目標達成率衡量"], answer: 1, explanation: "供應商減碳績效應綜合衡量：1)排放量（範疇一、二）之絕對減量趨勢；2)排放強度（每單位產出之排放）改善率；3)減碳目標達成進度；4)CDP評分或揭露品質改變；5)減碳行動計畫執行情形。", verified: true, chapter: "3.2" },
  { id: "S2-AI292", subject: 2, source: "ai", type: "single", question: "供應鏈碳排放之「歸因原則」（Attribution）如何決定排放歸屬？", options: ["將排放歸屬於持股最多之一方", "依採購金額、物理質量或經濟價值將供應鏈排放歸屬於購買方", "將排放歸屬於供應商", "將排放歸屬於最終消費者"], answer: 1, explanation: "供應鏈碳排放歸屬透過歸因原則決定：採購方（品牌企業）應依其採購金額、購買之物理質量或產品之經濟價值比例，將供應商之碳排放歸屬於自身之範疇三排放（Category 1）。", verified: true, chapter: "3.2" },
  { id: "S2-AI293", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，數位化工具（如區塊鏈、AI）之應用為何？", options: ["無實際應用", "提升供應鏈碳排放數據之透明度、可追溯性及數據品質", "取代人工作業", "自動供應商管理"], answer: 1, explanation: "數位化技術在供應鏈碳管理之應用：1)區塊鏈—確保碳排數據之不可篡改性與可追溯性；2)AI及大數據—自動化數據收集、排放熱點分析、減碳預測；3)IoT感測器—即時監控能耗及排放。", verified: true, chapter: "3.2" },
  { id: "S2-AI294", subject: 2, source: "ai", type: "single", question: "企業應如何核算供應鏈中「Tier 2供應商」（間接供應商）之碳排放？", options: ["無需核算", "透過Tier 1供應商收集Tier 2數據，或使用EEIO模型推估", "直接向Tier 2供應商要求數據", "使用政府統計數據"], answer: 1, explanation: "Tier 2（間接供應商）碳排放核算方式：1)要求Tier 1供應商提供其上游（Tier 2）之碳排數據；2)透過供應鏈碳管理平台傳遞數據請求；3)使用EEIO模型推估Tier 2之平均排放量；4)以行業平均值估算。", verified: true, chapter: "3.2" },
  
  
  
  
  
  
  { id: "S2-AI301", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查中，查驗機構進行「現場查訪」（Site Visit）之主要目的為何？", options: ["檢查公司財務", "確認排放源、盤查邊界及數據來源之正確性", "檢查生產設備", "審查員工資格"], answer: 1, explanation: "查驗機構之現場查訪目的包括：確認排放源是否完整鑑別、盤查邊界是否正確界定、活動數據來源及計算方式是否合理、監測設備是否正常運作、內部盤查制度是否有效執行等。", verified: true, chapter: "3.1" },
  { id: "S2-AI302", subject: 2, source: "ai", type: "single", question: "GHG Protocol企業標準中，對「保證等級」（Assurance Level）之要求為何？", options: ["強制要求高保證", "建議但不強制要求第三方保證，但部分法規或揭露框架要求", "不須任何保證", "僅內部稽核即可"], answer: 1, explanation: "GHG Protocol建議企業對排放數據取得第三方保證，但非強制要求。然而，許多揭露框架（如CDP、GRI）及法規（如歐盟ETS、我國碳費申報）要求排放數據須經查驗機構查證，通常至少須達到有限保證等級。", verified: true, chapter: "3.1" },
  { id: "S2-AI303", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查中，何謂「基準年」（Base Year）？", options: ["碳權發行年份", "作為比較基礎之歷史年度排放量數據", "碳費開始徵收年份", "公司成立年份"], answer: 1, explanation: "基準年（Base Year）係指企業選擇作為減量比較基礎之特定歷史年度之排放量數據。企業應設定基準年排放量，以計算後續年度之排放變化及減量績效。GHG Protocol建議基準年應選擇有可靠數據之最近年度。", verified: true, chapter: "3.1" },
  { id: "S2-AI304", subject: 2, source: "ai", type: "single", question: "範疇三排放計算方法中，「供應商特定法」（Supplier-specific Method）之主要優點為何？", options: ["成本最低", "反映供應商實際排放，精確度高，可識別具體減碳機會", "數據取得最容易", "計算最快速"], answer: 1, explanation: "供應商特定法使用供應商實際提供之產品級排放數據，優點包括：1)反映供應商實際生產效率及減碳努力；2)精確度較高；3)可識別各供應商之減碳潛力及具體改善方向；4)可激勵供應商減碳。", verified: true, chapter: "3.1" },
  { id: "S2-AI305", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，生命週期盤查（LCI）分析之主要產出為何？", options: ["碳權數量", "能源與物料投入、產出及排放之盤查清單", "產品價格", "市場需求"], answer: 1, explanation: "生命週期盤查分析（Life Cycle Inventory, LCI）係收集並量化產品系統在整個生命週期中所有能源、物料之投入及產出（包括產品、副產品、廢棄物及排放至空氣、水體、土壤之污染物）之清單。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI307", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，「共同減碳目標」（Collaborative Target）之設定方式為何？", options: ["由品牌企業單方設定", "品牌企業與供應商共同協商設定，兼顧品牌減碳需求與供應商可行性", "由供應商單方設定", "由政府設定"], answer: 1, explanation: "共同減碳目標係由品牌企業與供應商協商設定，綜合考量：1)品牌企業之整體減碳目標；2)供應商之技術能力及減碳潛力；3)供應商之經濟可行性；4)產業特性與區域差異。", verified: true, chapter: "3.2" },
  { id: "S2-AI308", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查報告中，排放量計算應使用GWP值之依據為何？", options: ["企業自行決定", "IPCC評估報告最新發布之GWP值", "由查驗機構決定", "由供應商決定"], answer: 1, explanation: "溫室氣體盤查計算應使用IPCC（聯合國政府間氣候變遷專門委員會）評估報告中所發布之全球暖化潛勢（GWP）值。目前多數採用IPCC第五次評估報告（AR5）或第六次評估報告（AR6）之GWP值。", verified: true, chapter: "3.1" },
  
  
  
  
  
  
  
  { id: "S2-AI316", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「基線情境」（Baseline Scenario）之設定？", options: ["供應商之財務目標", "若無減碳行動情況下之預期排放量，作為比較基準", "供應商之生產計畫", "市場需求預測"], answer: 1, explanation: "供應鏈碳管理之基線情境設定係假設不採取新減碳措施情況下，供應鏈未來之預期排放量，用以評估減碳行動之效益及目標設定之基礎。", verified: true, chapter: "3.2" },
  { id: "S2-AI317", subject: 2, source: "ai", type: "single", question: "產品碳足跡評估中，功能單位（Functional Unit）之設定目的為何？", options: ["決定產品價格", "提供量化比較產品功能之參考基準（如1噸鋼材、1件衣服）", "決定產品包裝", "決定產品尺寸"], answer: 1, explanation: "功能單位（Functional Unit）係產品碳足跡評估之量化參考基準，用以標準化不同產品之比較。例如：1噸鋼材、1件T恤、1平方公尺地毯、1000公里運輸等，確保碳足跡比較在同一功能基礎上進行。", verified: true, chapter: "3.1" },
  
  
  { id: "S2-AI320", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業如何評估供應商之「碳轉型風險」？", options: ["分析供應商財務報表", "評估供應商在低碳轉型過程中之法規、市場及技術風險", "評估供應商產品品質", "評估供應商交期"], answer: 1, explanation: "供應商碳轉型風險評估包括：1)法規風險—碳費/碳交易對供應商成本之影響；2)市場風險—低碳產品需求變化對供應商之衝擊；3)技術風險—供應商低碳技術能力及競爭力；4)聲譽風險—供應商ESG爭議。", verified: true, chapter: "3.2" },
  { id: "S2-AI321", subject: 2, source: "ai", type: "single", question: "範疇三排放中，資本設備（Category 2）之計算方式為何？", options: ["不須計算", "依資本設備之採購成本乘以排放係數，並可依折舊年限分攤", "僅計算設備使用階段排放", "僅計算設備廢棄階段排放"], answer: 1, explanation: "資本設備排放（Category 2）係指企業購買之資本設備（如機器設備、建築物、車輛等）在製造過程中所產生之碳排放。計算方法：設備採購金額 × 該類設備之排放係數，可選擇一次性認列或依折舊年限分攤。", verified: true, chapter: "3.1" },
  { id: "S2-AI322", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「反漂綠」（Anti-Greenwashing）之要求？", options: ["禁止使用綠色包裝", "要求企業之減碳宣稱須有科學依據及第三方驗證，避免誇大不實", "禁止使用環保標語", "要求產品皆為綠色產品"], answer: 1, explanation: "反漂綠要求企業之供應鏈減碳宣稱（如碳中和、淨零供應鏈）須有具體數據佐證及科學基礎，避免誇大不實或誤導消費者。相關規範包括歐盟綠色聲明指令、英國CMA綠色聲明指引等。", verified: true, chapter: "3.2" },
  
  
  
  
  { id: "S2-AI327", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，「截斷原則」（Cut-off Criteria）之設定為何？", options: ["無需設定", "設定門檻（如1%或5%），對總碳足跡影響小於門檻之項目可予排除", "排除所有間接排放", "僅計算主要原料"], answer: 1, explanation: "截斷原則（Cut-off Criteria）係在碳足跡計算中設定一門檻（通常為總排放量之1%-5%），對於單項排放貢獻小於該門檻之項目（如小量原料、輔料等），可予排除不計，惟排除項目之總和不得超過設定之比例。", verified: true, chapter: "3.1" },
  
  
  
  { id: "S2-AI331", subject: 2, source: "ai", type: "single", question: "產品碳足跡查證中，查驗機構對數據品質（Data Quality）之評估項目為何？", options: ["僅數據數量", "時間代表性、地理代表性、技術代表性及數據完整性", "僅數據價格", "僅數據來源"], answer: 1, explanation: "查驗機構評估碳足跡數據品質時，主要審查：1)時間代表性—數據年份是否與評估期間一致；2)地理代表性—排放係數是否反映實際區域；3)技術代表性—係數是否反映實際技術；4)完整性—數據是否涵蓋所有重大排放源。", verified: true, chapter: "3.1" },
  { id: "S2-AI332", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業應如何處理供應商提供之排放數據之「機密性」（Confidentiality）問題？", options: ["公開所有供應商數據", "簽署保密協議（NDA）、數據去識別化及限制數據使用範圍", "不收集供應商數據", "使用匿名問卷"], answer: 1, explanation: "供應商碳排數據機密性處理方式：1)簽訂雙向保密協議（NDA）；2)數據去識別化（僅揭露彙總數據）；3)限制數據使用範圍（僅供內部碳管理使用）；4)使用安全數據平台（如CDP平台）；5)數據匿名化後發布。", verified: true, chapter: "3.2" },
  { id: "S2-AI333", subject: 2, source: "ai", type: "single", question: "企業在碳足跡管理中，生命週期衝擊評估（LCIA）之產出為何？", options: ["碳權認證", "將LCI數據轉換為環境衝擊指標（如全球暖化、酸化、優養化等）", "產品成本分析", "市場分析報告"], answer: 1, explanation: "生命週期衝擊評估（Life Cycle Impact Assessment, LCIA）係將LCI盤查數據（排放量、資源消耗等）轉換為各類環境衝擊類別指標，如全球暖化潛勢（GWP）、酸化潛勢（AP）、優養化潛勢（EP）等。", verified: true, chapter: "3.1" },
  { id: "S2-AI334", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業推動「綠色物流」（Green Logistics）之主要措施為何？", options: ["僅使用電動車輛", "運輸路線優化、運具轉換（公路轉鐵路/海運）、包裝減量及低碳倉儲", "僅減少運輸次數", "僅使用鐵路運輸"], answer: 1, explanation: "綠色物流措施包括：1)運輸路線優化及共配；2)運具轉換（公路轉鐵路/海運，降低碳排）；3)包裝減量及環保材質；4)低碳倉儲（綠建築、再生能源）；5)運輸效率提升（滿載率提高）；6)低碳燃料使用。", verified: true, chapter: "3.2" },
  { id: "S2-AI335", subject: 2, source: "ai", type: "single", question: "科學基礎減量目標（SBT）之五步驟流程為何？", options: ["承諾、發展、提交、審查、公告", "規劃、執行、檢查、行動", "設定、盤查、減量、查證、報告", "分析、設計、實施、監控、改善"], answer: 0, explanation: "SBTi五步驟流程：1)承諾（Commit）—提交承諾書；2)發展（Develop）—制定科學基礎減量目標；3)提交（Submit）—向SBTi提交目標審查；4)審查（Validate）—SBTi審查通過；5)公告（Communicate）—公告目標及定期揭露進度。", verified: true, chapter: "1.3" },
  { id: "S2-AI336", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，碳費之計算方式為何？", options: ["固定費率 × 排放量", "差別費率 × 排放量（依行業別及有無自主減量計畫適用不同費率）", "單一費率 × 營業額", "排放量 × 行業係數"], answer: 1, explanation: "我國碳費制度規劃採差別費率，一般費率與優惠費率並行。企業若提出經核定之自主減量計畫，得適用優惠費率；未提出者適用一般費率。碳費 = 適用費率 × 經查驗之排放量。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI338", subject: 2, source: "ai", type: "single", question: "EU ETS中，免費配額（Free Allocation）之分配方式主要依據何種原則？", options: ["依歷史排放量（祖父條款）", "依產業標竿值（Benchmark）及歷史活動水準", "依員工人數", "依營業面積"], answer: 1, explanation: "EU ETS免費配額分配採「標竿法」（Benchmarking）：依各產品之最佳可行技術排放標竿值（Benchmark）乘以該設施之歷史活動水準（如產量）計算。表現優於標竿之設施可獲得較多配額。", verified: true, chapter: "2.3" },
  { id: "S2-AI339", subject: 2, source: "ai", type: "single", question: "碳權交易市場中，「造市者」（Market Maker）之功能為何？", options: ["代替政府監管", "持續提供買賣報價，增加市場流動性及穩定價格", "核發碳權", "設定碳價"], answer: 1, explanation: "造市者（Market Maker）在碳權交易市場中持續提供買價（Bid）及賣價（Ask）報價，承諾在該價格進行交易，以增加市場流動性、縮小買賣價差及促進價格發現。", verified: true, chapter: "2.3" },
  { id: "S2-AI340", subject: 2, source: "ai", type: "single", question: "企業導入ISO 14064-1溫室氣體盤查制度時，建立「盤查清冊」（Inventory）之主要步驟為何？", options: ["鑑別排放源、收集活動數據、選擇排放係數、計算排放量、編製報告", "僅計算排放量", "僅鑑別排放源", "僅收集數據"], answer: 0, explanation: "溫室氣體盤查清冊建立步驟：1)設定組織邊界與營運邊界；2)鑑別排放源；3)選擇計算方法；4)收集活動數據；5)選擇適用之排放係數；6)計算排放量；7)內部查證/查驗；8)編製盤查報告。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI342", subject: 2, source: "ai", type: "single", question: "碳足跡不確定性分析中，敏感度分析（Sensitivity Analysis）之目的為何？", options: ["改變產品設計", "識別對碳足跡結果影響最大之參數或假設", "降低產品成本", "提高產品品質"], answer: 1, explanation: "敏感度分析係改變關鍵參數（如排放係數、活動數據、分配比例）之數值，觀察其對碳足跡結果之影響程度，以識別最敏感之參數，確認計算結果之穩健性及優先改善數據品質之方向。", verified: true, chapter: "3.1" },
  
  
  
  { id: "S2-AI346", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業對供應商之「碳績效分級」（Carbon Performance Tier）如何區分？", options: ["依供應商規模", "依排放量、減碳目標、揭露品質及減碳行動綜合評分分級", "依供應商地理位置", "依供應商產業類別"], answer: 1, explanation: "供應商碳績效分級通常綜合以下指標：1)碳排放量與排放強度；2)減碳目標之積極性（是否有SBT）；3)CDP評分或揭露品質；4)減碳行動計畫之完整性與執行進度；5)碳管理能力成熟度。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI348", subject: 2, source: "ai", type: "single", question: "企業在設定科學基礎減量目標時，若採用「產業脫碳路徑」（SDA, Sectoral Decarbonization Approach），其適用條件為何？", options: ["適用所有產業", "適用於高同質性之產業（如鋼鐵、水泥、電力等），使用物理強度指標", "僅適用服務業", "僅適用金融業"], answer: 1, explanation: "產業脫碳路徑（SDA）適用於產品組合較為同質、可使用物理強度指標（如每噸鋼材、每度電）之產業，如鋼鐵、水泥、鋁業、電力、造紙等。SDA依據該產業之全球脫碳路徑設定目標。", verified: true, chapter: "1.3" },
  
  { id: "S2-AI350", subject: 2, source: "ai", type: "single", question: "某企業2024年排放量為10萬噸CO2e，設定SBT目標為2030年較基準年（2024年）減量50%，若採線性減量，每年應減量多少？", options: ["5000噸", "7143噸", "8333噸", "10000噸"], answer: 2, explanation: "計算：(10萬噸 × 50%) ÷ 6年（2024至2030）= 5萬噸 ÷ 6年 = 每年約8333噸。線性減量為最簡化之假設，實際SBT減量路徑可能為非線性。", verified: true, chapter: "1.3" },
  { id: "S2-AI351", subject: 2, source: "ai", type: "single", question: "我國碳交所之國際碳權交易平台，主要提供哪些服務？", options: ["碳權發行", "碳權買賣交易、結算交割及碳權諮詢服務", "碳權認證", "碳權查驗"], answer: 1, explanation: "臺灣碳交所國際碳權交易平台主要提供：1)碳權買賣交易（撮合及議價）；2)結算交割服務；3)碳權品質諮詢；4)碳權教育訓練；5)碳權專案媒合等服務，不涉及碳權發行或認證。", verified: true, chapter: "2.3" },
  
  
  { id: "S2-AI354", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，ISO 14067:2018與PAS 2050:2011之主要差異為何？", options: ["PAS 2050為ISO 14067之前身，ISO 14067為國際標準版本", "兩者完全相同", "PAS 2050較嚴格", "ISO 14067僅適用於組織"], answer: 0, explanation: "PAS 2050（由BSI於2008年發布，2011年更新）為產品碳足跡量化之早期標準，為ISO 14067:2018（國際標準）之基礎。ISO 14067較PAS 2050更為完整，增加了查證要求及報告規範。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI356", subject: 2, source: "ai", type: "single", question: "我國「氣候變遷因應法」第26條所稱「自願減量專案」之定義為何？", options: ["企業自行設定減量目標", "事業經中央主管機關認可，於我國境內執行減少或移除溫室氣體排放之專案", "政府主導之減量計畫", "國際碳權購買計畫"], answer: 1, explanation: "依《氣候變遷因應法》第26條，自願減量專案係指事業經中央主管機關認可，於我國境內執行減少或移除溫室氣體排放之專案，得申請核發減量額度（碳權）。", verified: true, chapter: "2.1" },
  { id: "S2-AI357", subject: 2, source: "ai", type: "single", question: "臺灣碳權交易所成立之主要背景目的為何？", options: ["取代環境部", "提供企業碳權交易管道，促進碳定價機制及減碳投資", "取代證交所", "開徵碳稅"], answer: 1, explanation: "臺灣碳交所設立之主要目的為：1)提供企業透明、公平之碳權交易平台；2)促進碳定價機制發展；3)協助企業取得碳權以達成減碳目標；4)推動國內碳市場與國際碳市場接軌。", verified: true, chapter: "2.3" },
  
  { id: "S2-AI359", subject: 2, source: "ai", type: "single", question: "碳權交易中，何謂「碳權憑證」（Carbon Credit Certificate）？", options: ["碳權購買發票", "碳權之所有權證明文件，記載碳權數量、類型、專案資訊及註冊編號", "碳權交易合約", "碳權品質保證書"], answer: 1, explanation: "碳權憑證（Carbon Credit Certificate）係碳權之電子或實體所有權證明文件，記錄碳權之數量（以噸CO2e為單位）、專案ID、認證標準、Vintage年份、專案類型、註冊機構及序列號等，為碳權交易及註銷之依據。", verified: true, chapter: "2.3" },
  
  { id: "S2-AI361", subject: 2, source: "ai", type: "single", question: "我國2050淨零排放路徑之十二項關鍵戰略中，「資源循環零廢棄」對碳管理之貢獻為何？", options: ["無特別貢獻", "透過廢棄物減量、資源循環利用減少原料開採及廢棄處理碳排放", "僅減少廢棄物", "僅促進回收"], answer: 1, explanation: "資源循環零廢棄策略透過：1)廢棄物減量減少掩埋/焚化排放；2)材料循環利用減少原物料開採碳排；3)產品延長壽命減少新產品需求；4)循環經濟商業模式降低整體碳足跡。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI363", subject: 2, source: "ai", type: "single", question: "CDP氣候變遷問卷中，企業應揭露之「氣候風險」分類為何？", options: ["高風險、中風險、低風險", "轉型風險與物理風險兩大類", "短期風險與長期風險", "財務風險與營運風險"], answer: 1, explanation: "CDP氣候變遷問卷要求企業依TCFD分類揭露氣候風險：1)轉型風險（Transition Risks）—包含政策法規、市場、技術及聲譽風險；2)物理風險（Physical Risks）—包含急性（極端天氣）及慢性（長期氣候型態變化）風險。", verified: true, chapter: "1.2" },
  { id: "S2-AI364", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權「公允價值」（Fair Value）之評估方法為何？", options: ["固定成本法", "參考活絡市場之報價或採用評價技術（如市場法、收益法）", "歷史成本法", "重置成本法"], answer: 1, explanation: "碳權公允價值評估方法：1)市場法—參考活絡市場之公開報價（如交易所價格）；2)收益法—以碳權未來預期收益折現；3)成本法—以重置成本為基礎。若市場活絡，通常以市場報價為公允價值。", verified: true, chapter: "2.4" },
  
  
  { id: "S2-AI367", subject: 2, source: "ai", type: "single", question: "企業溫室氣體盤查報告中，查驗機構簽發之「查證聲明」（Verification Statement）應包含哪些內容？", options: ["僅查證結果", "查證範圍、準則、方法、結論、保證等級及查驗機構資訊", "僅查證結論", "僅查證方法"], answer: 1, explanation: "查證聲明應包含：1)查證範圍及期間；2)查證準則（如ISO 14064-3）；3)查證方法及程序；4)保證等級（有限保證或高保證）；5)查證結論（無保留意見、保留意見或否定意見）；6)查驗機構資訊及簽署。", verified: true, chapter: "3.1" },
  { id: "S2-AI368", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業應如何處理供應商排放數據之「時間落差」（Time Lag）問題？", options: ["不處理", "使用最新可得之數據，並揭露數據年份及落差原因", "使用去年同期數據", "使用預測數據"], answer: 1, explanation: "處理數據時間落差之方式：1)報告中明確揭露各類別數據之參考年份；2)使用最新可得數據而非強求全年度一致；3)逐年改善數據時效性；4)說明數據年份落差之原因及改善計畫。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI370", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業對供應商設定之「範疇一及範疇二減量目標」與自身目標之關係為何？", options: ["各自獨立", "供應商目標應與品牌企業之範疇三減量路徑一致，共同貢獻品牌企業之整體減碳目標", "供應商目標應比品牌企業目標更嚴格", "供應商目標無需設定"], answer: 1, explanation: "供應商範疇一及範疇二減量目標之設定，應與品牌企業之範疇三減碳路徑相互配合，使供應商減量行動能有效貢獻品牌企業之範疇三減量目標，形成協同效應。", verified: true, chapter: "3.2" },
  { id: "S2-AI371", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，GWP值應採用IPCC哪個版本？", options: ["無特定要求", "應採用報告期間最新發布之IPCC評估報告GWP值，並揭露所採用之版本", "固定使用AR4", "固定使用AR5"], answer: 1, explanation: "ISO 14067要求碳足跡計算應使用最新可得之IPCC GWP值。目前常用AR5（100年GWP）或AR6值，並應在報告中明確揭露所採用之IPCC版本及GWP值來源。", verified: true, chapter: "3.1" },
  { id: "S2-AI372", subject: 2, source: "ai", type: "single", question: "臺灣2050淨零排放路徑中，「前瞻能源」戰略包含哪些技術選項？", options: ["僅太陽光電", "海洋能、地熱、氫能及先進生質能等新興能源技術", "僅氫能", "僅風力"], answer: 1, explanation: "前瞻能源為十二項關鍵戰略之一，涵蓋海洋能（波浪、潮汐）、地熱發電、氫能（綠氫）、先進生質能及其他新興能源技術之研發與示範。", verified: true, chapter: "1.1" },
  { id: "S2-AI373", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業對供應商之「低碳設計要求」（Eco-Design Requirements）之意涵為何？", options: ["要求供應商變更產品顏色", "要求供應商在產品設計階段即納入低碳考量（如材料選擇、模組化、可回收性）", "要求供應商降低成本", "要求供應商增加功能"], answer: 1, explanation: "低碳設計要求供應商在產品開發階段即導入低碳考量：1)選用低碳原料及再生材料；2)輕量化設計減少材料用量；3)模組化設計延長產品壽命；4)易拆解設計促進回收；5)減少包裝材料。", verified: true, chapter: "3.2" },
  
  
  { id: "S2-AI376", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業應如何協助中小型供應商進行碳管理？", options: ["直接終止合作", "提供簡化工具、教育訓練、一對一輔導及共同改善專案", "要求供應商自行解決", "轉單至大供應商"], answer: 1, explanation: "協助中小型供應商碳管理之方式：1)提供簡化盤查工具及模板；2)舉辦免費教育訓練；3)安排專家一對一輔導；4)組織群組供應商共同改善專案；5)提供碳管理知識庫及教材；6)補助部分查驗費用。", verified: true, chapter: "3.2" },
  { id: "S2-AI377", subject: 2, source: "ai", type: "single", question: "企業設定SBT時，若選擇「絕對減量目標」（Absolute Reduction Target），其計算方式為何？", options: ["基準年排放量 ×（1 - 目標減量百分比）", "目標年排放量 / 基準年排放量", "排放量 × 營業額成長率", "排放量 / 產量"], answer: 0, explanation: "絕對減量目標計算：目標年排放量 = 基準年排放量 ×（1 - 目標減量百分比）。例如：基準年100噸，目標減量50%，則目標年排放量 = 100 ×（1 - 0.5）= 50噸。", verified: true, chapter: "1.3" },
  
  { id: "S2-AI379", subject: 2, source: "ai", type: "single", question: "GHG Protocol企業標準中，對排放量「聚總」（Aggregation）層級之要求為何？", options: ["僅報告總排放量", "分別報告範疇一、範疇二及範疇三排放量，並可依部門或地區細分", "僅按國家分類", "僅按產品分類"], answer: 1, explanation: "GHG Protocol建議企業按範疇別（範疇一、二、三）分別報告排放量，並可進一步依事業部門、地區、國家、排放源類別或產品線進行細分報告，以提供更詳細之分析資訊。", verified: true, chapter: "3.1" },
  { id: "S2-AI380", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，何謂「低碳物流」（Low-Carbon Logistics）之核心策略？", options: ["僅使用電動車", "運輸模式優化、路徑規劃、車輛效率提升、替代燃料及物流網絡重構", "僅減少配送次數", "僅提高庫存量"], answer: 1, explanation: "低碳物流核心策略：1)運輸模式優化—公路轉鐵路/海運/管道；2)路徑規劃—AI最佳化路線；3)車輛效率—電動車、氫能車、低碳燃料；4)物流網絡重構—區域配送中心、共同配送；5)包裝減量及循環使用。", verified: true, chapter: "3.2" },
  { id: "S2-AI381", subject: 2, source: "ai", type: "single", question: "我國CBAM因應策略中，企業應優先採取之措施為何？", options: ["等待政府協助", "建立產品碳足跡盤查制度，掌握出口產品碳排放數據，並規劃減碳路徑", "減少出口至歐盟", "提高產品價格"], answer: 1, explanation: "企業面對CBAM應優先：1)建立產品級碳足跡盤查能力；2)掌握出口產品之碳排放強度；3)制定減碳路徑（能源效率、再生能源、低碳原料）；4)準備CBAM申報所需數據；5)評估碳成本對產品競爭力之影響。", verified: true, chapter: "1.1" },
  
  
  { id: "S2-AI384", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，消費者對低碳產品之需求如何影響供應鏈碳管理？", options: ["無影響", "消費者低碳偏好驅動品牌企業加強供應鏈碳管理，以滿足市場需求及品牌形象", "僅影響產品定價", "僅影響包裝設計"], answer: 1, explanation: "消費者低碳偏好透過以下方式影響供應鏈：1)品牌企業為滿足消費者需求而要求供應商減碳；2)低碳產品可得市場溢價；3)低碳產品標籤（碳足跡標籤）成為市場區隔工具；4)投資人ESG要求亦驅動供應鏈碳管理。", verified: true, chapter: "3.2" },
  { id: "S2-AI385", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權價值之主要影響因素為何？", options: ["僅碳權數量", "專案類型、認證標準、vintage年份、所在地區及市場供需", "僅認證標準", "僅vintage年份"], answer: 1, explanation: "碳權價值受多重因素影響：1)專案類型（移除型 > 減量型）；2)認證標準（ICVCM認可標準價值較高）；3)Vintage年份（較新之碳權通常價值較高）；4)所在地區及共同效益；5)市場供需動態及政策變化。", verified: true, chapter: "2.4" },
  { id: "S2-AI386", subject: 2, source: "ai", type: "single", question: "CDP A級評分（Leadership Level）之企業通常具備哪些特徵？", options: ["僅揭露排放數據", "全面整合氣候治理、設定SBT、揭露價值鏈排放、實施內部碳定價及氣候情境分析", "僅設定減量目標", "僅購買碳權"], answer: 1, explanation: "CDP A級企業特徵：1)董事會層級監督氣候議題；2)設定SBT並報告進度；3)完整揭露範疇一、二、三排放；4)實施內部碳定價；5)進行氣候情境分析；6)鑑別氣候風險機會並納入策略；7)供應鏈碳管理。", verified: true, chapter: "1.2" },
  { id: "S2-AI387", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，對供應商設定「再生能源目標」（Renewable Energy Target）之方式為何？", options: ["要求供應商全面使用再生能源", "依供應商之技術可行性及地域條件，設定合理之再生能源使用比例目標", "不設定目標", "由供應商自行決定"], answer: 1, explanation: "供應商再生能源目標設定應考量：1)各國再生能源市場成熟度；2)供應商之技術可行性；3)再生能源採購成本及效益；4)可取得性（如綠電憑證市場）；5)設定階段性目標逐步提升，而非一步到位要求100%。", verified: true, chapter: "3.2" },
  { id: "S2-AI388", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，碳費審議會之組成包括哪些代表？", options: ["僅政府機關代表", "政府機關、學者專家、產業代表及環保團體等多元代表", "僅學者專家", "僅產業代表"], answer: 1, explanation: "碳費費率審議會由中央主管機關（環境部）設立的碳費費率審議會審議，成員包含政府機關代表、學者專家、產業代表、環保團體及公民團體等多元利害關係人。", verified: true, chapter: "1.1" },
  { id: "S2-AI389", subject: 2, source: "ai", type: "single", question: "ISO 14068-1:2023中，碳中和管理計畫（Carbon Neutrality Management Plan）應包含哪些要素？", options: ["僅排放盤查", "量化目標、減量措施及時程、碳權採購策略、監測計畫及報告機制", "僅碳權採購策略", "僅監測計畫"], answer: 1, explanation: "ISO 14068-1要求碳中和管理計畫應包含：1)量化之減量目標；2)減量措施及行動時程；3)碳權採購策略及品質要求；4)監測計畫及績效指標；5)報告及查證機制；6)審查及更新計畫。", verified: true, chapter: "1.3" },
  { id: "S2-AI390", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業應如何衡量供應鏈碳管理之投資報酬率（ROI）？", options: ["僅計算碳權收益", "綜合考量碳費節省、能源成本降低、營運效率提升、品牌價值增加及風險規避效益", "僅計算能源成本降低", "僅計算品牌價值增加"], answer: 1, explanation: "供應鏈碳管理ROI應綜合評估：1)成本面—碳費節省、能源成本降低、效率提升；2)收益面—低碳產品溢價、市場份額增加；3)風險面—法規遵循、供應鏈韌性提升；4)無形效益—品牌價值、利害關係人關係。", verified: true, chapter: "3.2" },
  { id: "S2-AI391", subject: 2, source: "ai", type: "single", question: "GRI 305: 排放中，305-5要求揭露之「溫室氣體排放減量」應包含哪些資訊？", options: ["僅總減量量", "減量成果（較基準年之減量量及減量百分比）、減量項目及所使用之方法", "僅減量百分比", "僅減量項目"], answer: 1, explanation: "GRI 305-5要求組織揭露：1)報告期間內之減量量（以噸CO2e計）；2)與基準年相比之減量百分比；3)達成減量之具體措施及項目；4)所使用之計算方法或假設。", verified: true, chapter: "1.2" },
  
  
  { id: "S2-AI394", subject: 2, source: "ai", type: "single", question: "企業在選擇碳權時，應注意之「品質評估框架」包含哪些面向？", options: ["僅價格", "真實性、外加性、永久性、可查證性、避免雙重計算及共同效益", "僅認證標準", "僅專案類型"], answer: 1, explanation: "碳權品質評估框架（參考ICVCM核心碳原則CCPs）包含：1)真實性（Real）；2)外加性（Additional）；3)永久性（Permanent）；4)可查證性（Verifiable）；5)避免雙重計算（No Double Counting）；6)健全之方法學；7)永續發展效益及 safeguards。", verified: true, chapter: "2.3" },
  
  
  { id: "S2-AI397", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，自主減量計畫之「指定削減率」若未達成，企業可能面臨何種處理？", options: ["無任何後果", "可能喪失優惠費率資格，需補繳差額", "僅限期改善", "自動延長改善期限"], answer: 1, explanation: "若企業未達成自主減量計畫所載之指定削減率，中央主管機關得廢止其優惠費率核定，企業須補繳一般費率與優惠費率之差額，以確保計畫之執行力。", verified: true, chapter: "1.1" },
  { id: "S2-AI398", subject: 2, source: "ai", type: "single", question: "TCFD所定義之氣候「機會」（Opportunities）包含哪些類型？", options: ["僅新產品開發", "資源效率、能源來源、產品與服務、市場及韌性", "僅成本降低", "僅市場擴張"], answer: 1, explanation: "TCFD將氣候相關機會分為五大類：1)資源效率（Resource Efficiency）；2)能源來源（Energy Source）；3)產品與服務（Products/Services）；4)市場（Markets）；5)韌性（Resilience）。企業應揭露鑑別及評估這些機會之過程。", verified: true, chapter: "1.2" },
  { id: "S2-AI399", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權「分類管理」（Portfolio Classification）之常見分類方式為何？", options: ["依碳權價格分類", "依專案類型（減量型/移除型）、認證標準、vintage及來源地區分類", "依碳權數量分類", "依碳權效期分類"], answer: 1, explanation: "碳權分類管理之常見維度：1)專案類型—減量型（Avoidance/Reduction）vs 移除型（Removal）；2)認證標準—VCS、GS、ACR等；3)Vintage年份；4)來源地區；5)專案規模；6)共同效益類型。", verified: true, chapter: "2.4" },
  { id: "S2-AI400", subject: 2, source: "ai", type: "single", question: "ISO 14064-1盤查報告中，排放量之「保證等級」選擇應考量哪些因素？", options: ["僅成本", "利害關係人需求、法規要求、數據品質及使用目的", "僅法規要求", "僅數據品質"], answer: 1, explanation: "保證等級選擇應綜合考量：1)利害關係人期望（投資人、客戶）；2)法規要求（碳費申報、ETS）；3)數據品質及系統成熟度；4)使用目的（內部管理vs外部報告）；5)成本效益。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI402", subject: 2, source: "ai", type: "single", question: "企業在進行SBT目標設定時，若採用「收斂法」（Convergence Approach），其精神為何？", options: ["所有部門排放收斂至相同水準", "同產業企業之排放強度逐步收斂至共同目標值（如全球行業平均）", "排放量逐年收斂至零", "碳權價格收斂"], answer: 1, explanation: "收斂法（Convergence Approach）係SBT設定方法之一，假設同產業內所有企業之排放強度（如每噸鋼材排放）將逐步收斂至一個共同目標值（如2050年全球行業平均），適用於產業脫碳路徑（SDA）。", verified: true, chapter: "1.3" },
  
  { id: "S2-AI404", subject: 2, source: "ai", type: "single", question: "歐盟Fit for 55政策包中，針對碳定價之主要改革為何？", options: ["取消碳交易", "擴大EU ETS涵蓋範圍、提高減量目標及實施CBAM", "降低碳價", "延後減量目標"], answer: 1, explanation: "Fit for 55政策包包含：1)EU ETS改革—提高年減量因子、擴大涵蓋海運業；2)實施CBAM；3)建立社會氣候基金；4)提高2030年減量目標至55%（較1990年）。", verified: true, chapter: "1.1" },
  { id: "S2-AI405", subject: 2, source: "ai", type: "single", question: "碳足跡計算中，採用「質量平衡法」（Mass Balance Approach）之適用時機為何？", options: ["計算碳權", "當產品含回收材料或生質材料時，核算其中再生/生質碳含量", "計算碳費", "計算碳交易量"], answer: 1, explanation: "質量平衡法（Mass Balance Approach）用於計算產品中回收材料或生質材料之比例，透過追蹤材料投入與產出之質量平衡，合理分配碳排放歸屬，適用於含回收料或生質料之產品碳足跡計算。", verified: true, chapter: "3.1" },
  { id: "S2-AI406", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業推動「綠色包裝」（Green Packaging）之減碳效益為何？", options: ["無減碳效益", "包裝減量、輕量化、使用再生材料及提高回收率，可降低原料開採及廢棄處理碳排放", "僅降低成本", "僅美觀"], answer: 1, explanation: "綠色包裝減碳效益：1)包裝減量直接減少材料使用及碳排放；2)輕量化降低運輸碳排放；3)使用再生材料減少原料開採碳排；4)提高可回收性減少廢棄處理排放；5)使用單一材質促進回收效率。", verified: true, chapter: "3.2" },
  { id: "S2-AI407", subject: 2, source: "ai", type: "single", question: "CDP評分中，企業在「揭露」（Disclosure）等級之主要特徵為何？", options: ["已全面整合氣候治理", "已開始請求供應商提供碳排數據並進行部分盤查揭露", "已設定SBT", "已實施內部碳定價"], answer: 1, explanation: "CDP D級（Disclosure, 揭露等級）企業之特徵：1)開始回應CDP問卷；2)初步盤查並揭露部分碳排放數據；3)可能已請求部分供應商提供數據；4)尚未建立全面之氣候管理流程或設定減量目標。", verified: true, chapter: "1.2" },
  
  { id: "S2-AI409", subject: 2, source: "ai", type: "single", question: "我國溫室氣體排放量申報制度中，排放量計算應使用之排放係數由誰提供？", options: ["企業自行決定", "中央主管機關公告之排放係數或經認可之國際資料庫", "供應商提供", "查驗機構決定"], answer: 1, explanation: "我國溫室氣體排放量計算，應優先採用中央主管機關（環境部）公告之排放係數。若公告係數未涵蓋特定排放源，可使用經中央主管機關認可之國際資料庫（如IPCC、ecoinvent等）之排放係數。", verified: true, chapter: "1.1" },
  { id: "S2-AI410", subject: 2, source: "ai", type: "single", question: "IFRS S2要求之氣候情境分析，企業應使用何種情境？", options: ["無特定要求", "至少使用一種與巴黎協定目標一致之氣候情境（如1.5°C或2°C情境）", "僅使用基線情境", "僅使用高排放情境"], answer: 1, explanation: "IFRS S2要求企業進行氣候情境分析時，應使用至少一種與《巴黎協定》目標一致之情境（如1.5°C或低於2°C情境），並可額外使用其他情境（如高排放情境）進行比較。", verified: true, chapter: "1.2" },
  
  { id: "S2-AI412", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業推動「低碳產品設計」（Low-Carbon Product Design）之原則為何？", options: ["僅降低成本", "減少材料用量、使用低碳材料、延長產品壽命、提高能效及促進回收", "僅使用再生材料", "僅減少包裝"], answer: 1, explanation: "低碳產品設計原則（Ecodesign）：1)材料減量—輕量化、減少過度包裝；2)低碳材料—使用再生材料、生質材料；3)延長壽命—耐久性設計、可維修性；4)能效提升—降低使用階段能耗；5)回收設計—易拆解、單一材質。", verified: true, chapter: "3.2" },
  { id: "S2-AI413", subject: 2, source: "ai", type: "single", question: "企業導入內部碳定價時，碳價水準應設定在何種範圍？", options: ["越低越好", "應參考政府碳費/碳交易價格，並高於企業邊際減碳成本以產生驅動效果", "越高越好", "設定為零"], answer: 1, explanation: "內部碳價設定應：1)參考外部碳價（政府碳費、EU ETS等）；2)高於企業之邊際減碳成本（MACC），以產生減碳投資誘因；3)考量產業特性及競爭力；4)隨時間逐步提高。世界銀行建議內部碳價至少50-100美元/噸。", verified: true, chapter: "2.4" },
  { id: "S2-AI414", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權「合約類型」包含哪些？", options: ["僅現貨合約", "現貨合約、遠期合約、期貨合約、選擇權合約及交換合約", "僅期貨合約", "僅遠期合約"], answer: 1, explanation: "碳權交易合約類型：1)現貨合約—即時交割；2)遠期合約（Forward）—未來特定日期交割；3)期貨合約（Future）—標準化交易所合約；4)選擇權合約（Option）—買入或賣出碳權之權利；5)交換合約（Swap）—現貨與期貨交換。", verified: true, chapter: "2.4" },
  
  { id: "S2-AI416", subject: 2, source: "ai", type: "single", question: "CDP評分中，企業從C級（Awareness）晉升至B級（Management）之主要條件為何？", options: ["揭露排放數據", "採取具體氣候行動、設定減量目標及建構治理機制", "購買碳權", "提交CDP問卷"], answer: 1, explanation: "CDP C級→B級晉升條件：1)從被動揭露轉為主動管理；2)設定量化減量目標（非強度目標需SBT）；3)建構氣候治理機制；4)實施氣候風險評估流程；5)開始供應鏈參與。", verified: true, chapter: "1.2" },
  { id: "S2-AI417", subject: 2, source: "ai", type: "single", question: "我國自願減量專案中，「專案邊界」（Project Boundary）之設定原則為何？", options: ["全國範圍", "界定納入專案之所有排放源、碳匯及減量活動之地理及技術範圍", "僅廠區範圍", "僅製程範圍"], answer: 1, explanation: "專案邊界設定原則：1)地理邊界—專案活動發生之實際位置；2)技術邊界—納入專案之設備、製程及活動；3)排放源邊界—所有可能受專案影響之排放源（含洩漏風險）；4)時間邊界—計入期起迄時間。", verified: true, chapter: "2.1" },
  
  { id: "S2-AI419", subject: 2, source: "ai", type: "single", question: "ISO 14064-3查證流程中，查驗機構進行「風險評估」（Risk Assessment）之目的為何？", options: ["評估財務風險", "識別盤查數據可能產生重大錯誤陳述之風險領域，據以規劃查證程序", "評估市場風險", "評估營運風險"], answer: 1, explanation: "查證風險評估係查驗機構分析盤查報告中各排放類別、數據來源及計算過程可能發生重大錯誤（錯誤陳述）之風險，包括固有風險及控制風險，據以設計查證程序（測試範圍、樣本量等）。", verified: true, chapter: "3.1" },
  { id: "S2-AI420", subject: 2, source: "ai", type: "single", question: "企業在淨零轉型路徑中，處理「難以減排」（Hard-to-abate）部門排放之策略為何？", options: ["放棄減排", "透過技術創新（氫能、CCUS、先進生質能）及碳移除達成深度減排", "僅購買碳權", "延後處理"], answer: 1, explanation: "難以減排部門（如鋼鐵、水泥、石化、重工業）之減排策略：1)氫能（綠氫取代化石氫）；2)CCUS（碳捕獲利用與封存）；3)先進生質能；4)電氣化（電弧爐煉鋼等）；5)循環經濟（廢鋼/廢料再利用）；6)剩餘排放透過碳移除中和。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI422", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查查證中，查驗機構發現重大錯誤陳述（Material Misstatement）時應如何處理？", options: ["忽略錯誤", "要求組織更正；若組織拒絕更正，則於查證聲明中出具保留意見或否定意見", "自行更正", "暫停查證"], answer: 1, explanation: "查驗機構發現重大錯誤陳述時：1)要求組織提出更正計畫及更正措施；2)若組織已更正且查證確認，可出具無保留意見；3)若組織未更正或無法更正，則依其重大性出具保留意見（qualified）或否定意見（adverse）。", verified: true, chapter: "3.1" },
  { id: "S2-AI423", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業推動「廢棄物減量」以降低供應鏈碳排放之策略為何？", options: ["僅分類回收", "源頭減量、產線效率提升、副產品利用及循環經濟模式", "僅減少包裝", "僅減少辦公室廢棄物"], answer: 1, explanation: "供應鏈廢棄物減碳策略：1)源頭減量—減少過度包裝及材料浪費；2)產線效率提升—降低不良率減少廢料；3)副產品利用—將廢料轉化為其他產業原料；4)循環經濟—設計可回收再利用之產品及包裝。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI425", subject: 2, source: "ai", type: "single", question: "SBTi對企業設定短期目標（Near-term Targets）之時間範圍要求為何？", options: ["目標年須在提交後2-5年內", "目標年須在提交後5-10年內", "目標年須在提交後10-15年內", "目標年須在提交後15年以上"], answer: 1, explanation: "SBTi短期目標（Near-term Targets）要求目標年（Target Year）應自目標提交日期起算5至10年內。例如，若2024年提交目標，目標年應在2029年至2034年之間。", verified: true, chapter: "1.3" },
  { id: "S2-AI426", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業如何將「生物多樣性」（Biodiversity）納入碳管理考量？", options: ["無關聯", "供應鏈碳管理應避免對生物多樣性造成負面影響，如避免採購來自毀林地之農產品", "生物多樣性優先於碳管理", "碳管理優先於生物多樣性"], answer: 1, explanation: "供應鏈碳管理應考量生物多樣性：1)避免採購來自毀林或高保護價值區域之原料；2)優先選擇對生物多樣性有益之碳匯專案（如生態造林而非單一樹種造林）；3)推動認證永續原料（如FSC、RSPO）。", verified: true, chapter: "3.2" },
  
  
  { id: "S2-AI429", subject: 2, source: "ai", type: "single", question: "企業在設定SBT時，若範疇三排放占比未達40%，對範疇三目標之要求為何？", options: ["仍須設定範疇三目標", "無須強制設定範疇三目標，但仍鼓勵設定", "禁止設定範疇三目標", "視為不重大"], answer: 1, explanation: "SBTi規定：若範疇三排放占總排放量未達40%，企業無須強制設定範疇三目標，但SBTi仍鼓勵企業自願設定範疇三目標，以展現對供應鏈減碳之承諾。", verified: true, chapter: "1.3" },
  
  { id: "S2-AI431", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權「到期管理」（Expiry Management）之重要性為何？", options: ["碳權無到期日", "碳權有使用期限，到期未使用將失效，需管理使用順序避免損失", "碳權到期可自動展延", "碳權到期可退費"], answer: 1, explanation: "許多碳權有使用期限（即Vintage至使用年限），若未在期限內使用（註銷）將失去價值。到期管理係追蹤各批碳權之使用期限，優先使用即將到期之碳權，並確保碳中和目標之有效達成。", verified: true, chapter: "2.4" },
  { id: "S2-AI432", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查中，如何處理「外包活動」（Outsourced Activities）之排放歸屬？", options: ["不納入盤查", "外包活動之排放歸屬於承包方之範疇一，委託方將其計入範疇三", "歸屬於委託方之範疇一", "歸屬於委託方之範疇二"], answer: 1, explanation: "當企業將部分活動外包時，承包方執行該活動所產生之排放歸屬於承包方之範疇一排放；委託方（品牌企業）則將該外包活動之排放計入其範疇三（Category 1:購買商品與服務）。", verified: true, chapter: "3.1" },
  { id: "S2-AI433", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業應如何設定供應商碳績效之「改善門檻」（Improvement Threshold）？", options: ["統一門檻", "供應商碳績效門檻應依行業別、供應商能力及減碳潛力差異化設定", "由供應商自行設定", "無需門檻"], answer: 1, explanation: "改善門檻設定原則：1)依行業別設定合理之排放強度改善率；2)考量供應商現有碳管理成熟度及技術可行性；3)設定階段性目標（短期/中期/長期）；4)對不同分級供應商設定不同門檻。", verified: true, chapter: "3.2" },
  { id: "S2-AI434", subject: 2, source: "ai", type: "single", question: "GHG Protocol企業標準中，「報告邊界」（Reporting Boundary）之決定步驟為何？", options: ["直接報告所有排放", "先決定組織邊界（股權/控制權法），再決定營運邊界（範疇分類）", "僅決定營運邊界", "僅決定組織邊界"], answer: 1, explanation: "報告邊界設定步驟：1)先選擇組織邊界設定方法（股權比例法或控制權法）以決定哪些子公司/設施納入報告；2)再設定營運邊界，將排放分類為範疇一、二、三。", verified: true, chapter: "3.1" },
  { id: "S2-AI435", subject: 2, source: "ai", type: "single", question: "企業為因應CBAM，應建立何種碳管理制度？", options: ["無需準備", "建立產品層級碳足跡盤查制度、供應鏈碳排放管理機制及CBAM申報流程", "僅建立組織層級盤查", "僅準備財務資料"], answer: 1, explanation: "CBAM因應制度建置：1)產品層級碳足跡盤查（組織盤查為基礎，進一步計算產品碳足跡）；2)供應鏈碳排管理（供應商提供產品級數據）；3)CBAM申報數據準備及流程建立；4)碳減量路徑規劃。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI437", subject: 2, source: "ai", type: "single", question: "IPCC第六次評估報告（AR6）中，若要將全球升溫控制在1.5°C以內，全球須在何時達成淨零CO2排放？", options: ["2030年", "2050年左右", "2070年", "2100年"], answer: 1, explanation: "IPCC AR6報告指出，若要將全球升溫控制在1.5°C以內（無過衝或有限過衝情境），全球須在2050年左右達成淨零CO2排放，並在2050年後實現淨零溫室氣體排放。", verified: true, chapter: "1.2" },
  { id: "S2-AI438", subject: 2, source: "ai", type: "single", question: "碳資產管理中，何謂「碳中和組合」（Carbon Neutral Portfolio）？", options: ["僅持有碳權之組合", "企業持有之碳權組合經由策略配置，使其足以中和企業之碳排放", "不含高碳排資產之組合", "僅持有移除型碳權之組合"], answer: 1, explanation: "碳中和組合係指企業策略性地配置其碳權資產組合（涵蓋不同類型、vintage、認證標準及地區之碳權），使其碳權總量足以中和企業產生之碳排放，並確保碳權品質符合企業碳中和標準。", verified: true, chapter: "2.4" },
  { id: "S2-AI439", subject: 2, source: "ai", type: "single", question: "GHG Protocol中，企業應如何報告「生質源生物性甲烷」（Biogenic Methane）？", options: ["不須報告", "分別報告生質源CH4及化石源CH4排放，使用各自之GWP值", "合併報告", "僅報告化石源CH4"], answer: 1, explanation: "GHG Protocol要求生質源及化石源之甲烷（CH4）排放應分別計算及報告。生質源CH4（如農業、廢棄物處理產生之甲烷）仍須報告，但與化石源CH4（如天然氣洩漏）分別列示。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI441", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，繳納碳費之方式為何？", options: ["按月繳納", "按年結算繳納", "按季繳納", "按週繳納"], answer: 1, explanation: "碳費徵收方式為「按年結算」，企業應於每年規定期限內，申報前一年度之排放量並計算應繳碳費總額，一次繳納。碳費申報及繳納期限由中央主管機關公告。", verified: true, chapter: "1.1" },
  { id: "S2-AI442", subject: 2, source: "ai", type: "single", question: "ISO 14068-1:2023中，碳中和宣告應包含哪些要素？", options: ["僅宣告目標", "宣告主體、涵蓋範圍、目標期限、減量措施、碳權使用及查證資訊", "僅減量措施", "僅碳權使用"], answer: 1, explanation: "ISO 14068-1要求碳中和宣告應包含：1)宣告主體（組織或產品）；2)涵蓋之碳排放範圍；3)碳中和目標期限；4)採行之減量措施；5)使用碳權之類型、數量及來源；6)查證機構及查證結論。", verified: true, chapter: "1.3" },
  { id: "S2-AI443", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業如何處理「碳成本轉嫁」（Carbon Cost Pass-through）風險？", options: ["完全吸收碳成本", "應了解供應鏈碳成本分布，與供應商協商碳成本分攤機制，並評估對產品成本之影響", "全部轉嫁給客戶", "忽略碳成本"], answer: 1, explanation: "碳成本轉嫁風險管理：1)繪製供應鏈碳成本地圖，了解各環節碳成本分布；2)與供應商協商成本分攤機制；3)將碳成本納入產品定價策略；4)透過綠色採購降低整體碳成本；5)評估碳成本對獲利能力之影響。", verified: true, chapter: "3.2" },
  { id: "S2-AI444", subject: 2, source: "ai", type: "single", question: "企業之溫室氣體盤查報告應如何處理「排除項目」（Exclusions）？", options: ["無須說明", "應列出排除之排放源或活動、排除理由及對總排放量之影響評估", "僅列排除項目", "排除項目不影響報告"], answer: 1, explanation: "盤查報告應揭露排除項目之完整資訊：1)排除之排放源或活動說明；2)排除理由（如不重大、數據不可得、不適用）；3)排除排放量之預估及其占總排放量之比例；4)預計納入盤查之時程規劃。", verified: true, chapter: "3.1" },
  { id: "S2-AI445", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，「碳揭露計畫」（Carbon Disclosure Program）對供應商之效益為何？", options: ["增加成本負擔", "提升碳管理能力、增強客戶信任、取得競爭優勢及符合未來法規要求", "無任何效益", "減少訂單"], answer: 1, explanation: "供應商參與碳揭露計畫（如CDP）之效益：1)系統性建立碳管理能力；2)回應品牌客戶要求，維持訂單；3)透過標竿分析發現改善機會；4)提升品牌形象及市場競爭力；5)提前因應碳費及碳交易法規。", verified: true, chapter: "3.2" },
  { id: "S2-AI446", subject: 2, source: "ai", type: "single", question: "SBTi淨零標準中，「價值鏈外減量」（Beyond Value Chain Mitigation, BVCM）之意涵為何？", options: ["價值鏈內減量", "企業除價值鏈減量外，額外投資價值鏈外之氣候行動（如購買碳權），以加速全球淨零", "僅購買碳權", "減少供應商"], answer: 1, explanation: "BVCM係SBTi淨零標準之重要概念：企業除致力於自身價值鏈減量（達到SBT目標）外，應額外投資價值鏈外之氣候行動（如購買高品質碳權），以加速全球達成淨零排放之進程。", verified: true, chapter: "1.3" },
  { id: "S2-AI447", subject: 2, source: "ai", type: "single", question: "碳資產管理中，「碳避險基金」（Carbon Hedge Fund）之投資策略為何？", options: ["僅投資單一碳權", "透過分散投資各類碳權、碳配額及碳衍生性金融商品，獲取碳市場回報並管理風險", "僅投資碳權期貨", "僅投資碳權現貨"], answer: 1, explanation: "碳避險基金透過多元投資策略管理碳市場風險：1)分散投資於不同碳權類型、地區及vintage；2)同時投資碳配額（如EUA）及碳權（如VCU）；3)運用碳衍生性商品進行避險；4)獲取碳市場價格變動之回報。", verified: true, chapter: "2.4" },
  { id: "S2-AI448", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業應如何評估供應商之「低碳技術能力」？", options: ["僅看供應商設備新舊", "評估供應商之能源效率、再生能源使用、碳捕集技術、循環經濟實踐及研發投入", "僅看供應商規模", "僅看供應商成立時間"], answer: 1, explanation: "供應商低碳技術能力評估面向：1)能源效率措施（節能設備、餘熱回收）；2)再生能源使用比例及採購能力；3)低碳生產技術（如電氣化、氫能）；4)碳捕集技術應用；5)循環經濟實踐（廢料再利用、水循環）。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI450", subject: 2, source: "ai", type: "single", question: "臺灣2050淨零排放路徑中，「節能」戰略之主要目標為何？", options: ["減少能源使用量", "提升能源使用效率，在不影響經濟發展下降低能源密集度", "完全停止使用能源", "提高能源價格"], answer: 1, explanation: "節能戰略目標為提升能源效率，包括：1)產業製程效率提升；2)住商建築節能；3)運輸車輛能效提升；4)智慧能源管理系統導入；5)設備效率標準提高，以降低能源密集度（每單位GDP之能源消耗）。", verified: true, chapter: "1.1" },
  { id: "S2-AI451", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業推動「低碳運輸」（Low-Carbon Transportation）之具體措施為何？", options: ["僅更換電動車", "運具電動化、低碳燃料使用、運輸效率提升、路線優化及共同配送", "僅減少運輸次數", "僅使用大眾運輸"], answer: 1, explanation: "低碳運輸措施：1)運具電動化（電動卡車、電動堆高機）；2)低碳燃料（生質柴油、氫能）；3)運輸效率（提高滿載率、降低空車率）；4)路線優化（AI最佳化路線）；5)共同配送（多家企業聯合配送減少車輛數）。", verified: true, chapter: "3.2" },
  { id: "S2-AI452", subject: 2, source: "ai", type: "single", question: "碳權之「品質分級」（Quality Rating）通常由哪些因素決定？", options: ["僅價格", "專案類型（移除型 > 減量型）、認證標準、vintage、外加性及共同效益", "僅認證標準", "僅專案類型"], answer: 1, explanation: "碳權品質分級因素：1)專案類型—移除型（如DAC、造林）優於減量型（如再生能源）；2)認證標準—ICVCM認可標準較高；3)Vintage—新近碳權品質較高；4)外加性驗證；5)永久性風險管理；6)共同效益（SDGs貢獻）。", verified: true, chapter: "2.3" },
  
  { id: "S2-AI454", subject: 2, source: "ai", type: "single", question: "企業在計算範疇三排放時，若供應商提供之排放數據涵蓋範圍不完全，應如何處理？", options: ["忽略該供應商", "使用供應商提供之部分數據，並以次級數據補足缺口，同時揭露數據涵蓋率", "使用行業平均數據代替", "以採購金額比例推估"], answer: 1, explanation: "供應商數據涵蓋不完全時：1)使用供應商已提供之實際數據；2)缺口部分以行業平均排放係數或EEIO模型推估；3)報告中明確揭露初級數據之涵蓋率（實際數據占總排放比例）；4)規劃逐步提高初級數據涵蓋率。", verified: true, chapter: "3.2" },
  { id: "S2-AI455", subject: 2, source: "ai", type: "single", question: "SBTi對企業提交目標後，審查所需之時間通常為何？", options: ["1-2週", "通常需要30-60個工作天（依申請案件複雜度而定）", "半年", "一年"], answer: 1, explanation: "SBTi目標審查時間通常為30-60個工作天（約6-12週），取決於目標複雜度、產業類別及SBTi審查能量。通過審查後，企業須在6個月內公告目標。", verified: true, chapter: "1.3" },
  
  { id: "S2-AI457", subject: 2, source: "ai", type: "single", question: "歐盟ETS第四階段（2021-2030年）之主要改革重點為何？", options: ["維持不變", "提高年減量因子、擴大涵蓋範圍、減少免費配額、實施MSR改革", "降低碳價", "減少涵蓋範圍"], answer: 1, explanation: "EU ETS第四階段改革重點：1)年減量因子提高至2.2%（後至4.3%）；2)擴大涵蓋海運業；3)減少免費配額；4)強化市場穩定機制（MSR）；5)納入建築及道路運輸（ETS 2）；6)配合Fit for 55目標。", verified: true, chapter: "2.3" },
  { id: "S2-AI458", subject: 2, source: "ai", type: "single", question: "產品碳足跡報告中，「解釋性評估」（Interpretation）階段之主要目的為何？", options: ["解釋產品功能", "根據LCI及LCIA結果，識別熱點、評估數據品質及提出改善建議", "解釋產品價格", "解釋市場定位"], answer: 1, explanation: "解釋性評估（Interpretation）係碳足跡/LCA之最終階段，目的為：1)根據LCI及LCIA結果識別碳排放熱點；2)評估數據品質及不確定性；3)進行完整性檢查；4)提出減碳改善建議；5)形成結論與建議。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI460", subject: 2, source: "ai", type: "single", question: "GHG Protocol中，企業應如何處理「碳權」（Carbon Credits）與「碳配額」（Allowances）之會計處理？", options: ["兩者相同", "碳權作為無形資產，碳配額（ETS下）依各國會計準則處理，兩者性質不同", "碳權為庫存", "碳配額為收入"], answer: 1, explanation: "碳權（Carbon Credits/Certificates）通常作為無形資產（Intangible Assets）依IAS 38處理；碳配額（EU Allowances, EUAs）在ETS下之會計處理較複雜，各國作法不一，包括無形資產、政府補助或存貨等處理方式。", verified: true, chapter: "2.4" },
  { id: "S2-AI461", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業對供應商之「資訊請求」（Information Request）應如何設計？", options: ["一次性要求所有數據", "分階段逐步要求，從基本數據開始，逐步提升要求深度及廣度", "不要求數據", "僅要求財務數據"], answer: 1, explanation: "供應商資訊請求設計原則：1)第一階段—要求基本排放量及企業資訊；2)第二階段—要求排放強度及減量目標；3)第三階段—要求範疇三數據及SBT進度；4)逐步增加要求項目，避免一次要求過多造成供應商負擔。", verified: true, chapter: "3.2" },
  { id: "S2-AI462", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，「碳洩漏風險事業」申請調整碳費之程序為何？", options: ["自動適用優惠", "須向中央主管機關提出申請，經會商有關機關認定後，始得調整徵收方式", "向碳費審議會申請", "向經濟部申請"], answer: 1, explanation: "碳洩漏風險事業申請碳費調整程序：1)事業向中央主管機關提出申請；2)中央主管機關會商經濟部等有關機關進行認定；3)經認定為高碳洩漏風險事業者，得酌予減免或調整碳費徵收方式。", verified: true, chapter: "1.1" },
  { id: "S2-AI463", subject: 2, source: "ai", type: "single", question: "碳資產管理中，企業進行「碳權壓力測試」（Carbon Credit Stress Testing）之目的為何？", options: ["測試碳權價格上漲時之收益", "評估在不同情境（碳價波動、政策變化、品質爭議）下碳權組合之風險承受能力", "測試碳權系統功能", "測試交易平台效能"], answer: 1, explanation: "碳權壓力測試係評估碳權組合在極端情境下之風險：1)碳價暴跌情境；2)碳權品質爭議（被撤銷）情境；3)政策變動（碳權不被認可）情境；4)永久性風險（自然碳匯逆轉）情境，以確保碳資產組合之韌性。", verified: true, chapter: "2.4" },
  
  
  { id: "S2-AI466", subject: 2, source: "ai", type: "single", question: "企業在選擇「內部碳定價」之碳價水準時，常用之參考方法為何？", options: ["隨意設定", "邊際減碳成本曲線（MACC）分析、外部碳價參考及利害關係人期望", "僅參考政府碳費", "僅參考同業水準"], answer: 1, explanation: "內部碳價設定之參考方法：1)邊際減碳成本曲線（MACC）—分析企業各項減碳措施之成本效益；2)外部碳價參照—政府碳費、EU ETS價格；3)世界銀行建議價格區間（2025年50-100美元/噸）；4)利害關係人期望（投資人、CDP）。", verified: true, chapter: "2.4" },
  { id: "S2-AI467", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業對供應商之「氣候韌性評估」（Climate Resilience Assessment）主軸為何？", options: ["評估供應商財務韌性", "評估供應商對極端氣候事件之應變能力及供應鏈中斷風險", "評估供應商產品品質", "評估供應商市場韌性"], answer: 1, explanation: "供應商氣候韌性評估重點：1)供應商廠址之氣候風險（洪水、颱風、乾旱、海平面上升）；2)供應商之因應措施（備援產能、保險、應變計畫）；3)供應商供應鏈多樣性（原料來源分散）；4)氣候災害歷史損失及復原能力。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI469", subject: 2, source: "ai", type: "single", question: "ISO 14064-1:2018盤查標準中，對「顯著性」（Significance）之判斷原則為何？", options: ["依排放量絕對值", "依排放量占總排放之比例及利害關係人關注度綜合判斷", "依成本", "依排放源個數"], answer: 1, explanation: "顯著性判斷應綜合考量：1)排放量占總排放之比例（量之顯著性）；2)利害關係人關注程度（質之顯著性）；3)對減碳決策之影響；4)法規要求。具顯著性之排放源應優先納入盤查及管理。", verified: true, chapter: "3.1" },
  { id: "S2-AI470", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業應如何確保供應商碳揭露數據之「時效性」（Timeliness）？", options: ["不要求時效", "設定數據提交截止日期（如每年6月底前提交前一年數據），並要求即時更新重大變動", "隨時提供", "每月提供"], answer: 1, explanation: "確保數據時效性之措施：1)設定明確之數據提交時程（通常每年一次，於固定期限內）；2)要求供應商資料異動（如新增產線、併購、重大減碳措施）時即時更新；3)建立數據提交追蹤及催報機制；4)將數據時效性納入供應商績效考核。", verified: true, chapter: "3.2" },
  
  { id: "S2-AI472", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，企業制定「供應鏈減碳投資計畫」（Decarbonization Investment Plan）之關鍵要素為何？", options: ["僅投資金額", "減碳目標、投資項目、預期效益、資金來源及投資回報評估", "僅投資項目", "僅資金來源"], answer: 1, explanation: "供應鏈減碳投資計畫應包含：1)明確之減碳目標及量化指標；2)具體減碳投資項目（設備更新、再生能源、技術研發等）；3)各項目預期減碳效益（噸CO2e/年）；4)所需資金及資金來源；5)投資回報分析（ROI、回收年限）。", verified: true, chapter: "3.2" },
  { id: "S2-AI473", subject: 2, source: "ai", type: "single", question: "ESRS（歐洲永續報導準則）E1：氣候變遷中，要求揭露之碳排放範疇為何？", options: ["僅範疇一", "範疇一、範疇二及範疇三（若重大）", "僅範疇一及範疇二", "僅範疇三"], answer: 1, explanation: "ESRS E1（氣候變遷）要求企業揭露範疇一、範疇二及範疇三（若重大時）之溫室氣體排放量，且範疇三須依GHG Protocol 15類別分別揭露，並要求揭露排放強度及減量目標。", verified: true, chapter: "1.2" },
  { id: "S2-AI474", subject: 2, source: "ai", type: "single", question: "碳權市場中，何謂「碳權撤銷」（Carbon Credit Cancellation）？", options: ["碳權被盜用", "碳權由碳權註冊機構永久移除，不再用於任何交易或主張（非自願性）", "碳權過期", "碳權價格歸零"], answer: 1, explanation: "碳權撤銷（Cancellation）係由主管機關或註冊機構（非買方自願）將碳權永久移除，原因可能包括：1)碳權經查驗有品質問題；2)雙重計算爭議；3)專案不符合新標準；4)主管機關政策調整。", verified: true, chapter: "2.3" },
  { id: "S2-AI475", subject: 2, source: "ai", type: "single", question: "供應鏈碳排放計算中，企業使用「供應商特定排放係數」（Supplier-specific Emission Factor）相較於「行業平均係數」之優勢為何？", options: ["成本較低", "反映供應商實際生產效率及能源結構，精確度及可追溯性較高", "計算更快速", "數據取得更容易"], answer: 1, explanation: "供應商特定排放係數優勢：1)反映供應商實際狀況（能源效率、燃料組合、電力排放）；2)精確度高；3)供應商減碳努力可在係數中體現；4)可追溯至實際製程；5)支持供應商績效考核及改善。", verified: true, chapter: "3.2" },
  { id: "S2-AI476", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，企業若對碳費核定有不服，應循何種救濟途徑？", options: ["向環境部申訴", "依行政程序法及行政訴訟法提起行政救濟", "向立法院陳情", "向監察院檢舉"], answer: 1, explanation: "企業對碳費核定不服，應依「行政程序法」及「行政訴訟法」之規定，先向原處分機關提起訴願，若對訴願決定不服，再向行政法院提起行政訴訟。", verified: true, chapter: "1.1" },
  
  
  { id: "S2-AI479", subject: 2, source: "ai", type: "single", question: "碳資產管理中，何謂「碳權估值」（Carbon Credit Valuation）之主要方法？", options: ["僅歷史成本法", "市場法（參考交易價格）、收益法（未來現金流量折現）及成本法（重置成本）", "僅重置成本法", "僅收益法"], answer: 1, explanation: "碳權估值主要方法：1)市場法（Market Approach）—參考活絡市場或最近交易價格；2)收益法（Income Approach）—以碳權未來預期收益或節省之碳費折現；3)成本法（Cost Approach）—以重置或替代碳權之成本為基礎。", verified: true, chapter: "2.4" },
  
  { id: "S2-AI481", subject: 2, source: "ai", type: "single", question: "我國「溫室氣體盤查與登錄作業指引」中，盤查數據之「查證」要求為何？", options: ["無須查證", "公告排放源之盤查數據須經中央主管機關認證之查驗機構查證", "僅內部查證", "僅政府審查"], answer: 1, explanation: "依我國溫室氣體盤查管理規定，公告排放源（碳費徵收對象）之排放量盤查數據，須經中央主管機關（環境部）認證合格之查驗機構依ISO 14064-3標準進行查證。", verified: true, chapter: "3.1" },
  { id: "S2-AI482", subject: 2, source: "ai", type: "single", question: "供應鏈碳管理中，品牌企業對供應商進行「碳管理成熟度評估」（Maturity Assessment）之主要構面為何？", options: ["僅排放量", "治理、盤查、目標、行動、揭露及供應鏈管理等構面", "僅減量目標", "僅碳盤查"], answer: 1, explanation: "供應商碳管理成熟度評估構面：1)治理—氣候治理機制及管理階層參與；2)盤查—排放量盤查制度及數據品質；3)目標—減量目標設定（是否為SBT）；4)行動—減碳措施及執行情況；5)揭露—資訊揭露透明度；6)供應鏈管理—供應商自身之供應鏈管理。", verified: true, chapter: "3.2" },
  { id: "S2-AI483", subject: 2, source: "ai", type: "single", question: "COP28 UAE共識中，2030年全球再生能源裝置容量目標為何？", options: ["增加1倍", "增加2倍（較2022年基準）", "增加3倍", "維持不變"], answer: 2, explanation: "COP28 UAE共識中，各國承諾2030年全球再生能源裝置容量增加至3倍（較2022年基準），能源效率改善率提高至2倍，以加速全球能源轉型及減碳。", verified: true, chapter: "1.2" },
  { id: "S2-AI484", subject: 2, source: "ai", type: "single", question: "碳資產管理中，企業決定碳權使用優先順序（Prioritization）之考量因素為何？", options: ["僅價格", "碳權即將到期日、專案類型品質、認證標準及使用目的（碳費抵減vs碳中和）", "僅到期日", "僅使用目的"], answer: 1, explanation: "碳權使用優先順序考量：1)到期日—優先使用即將到期之碳權；2)品質—移除型優於減量型；3)認證標準—符合ICVCM標準者優先；4)使用目的—碳費抵減用國內碳權，碳中和用國際碳權；5)成本效益。", verified: true, chapter: "2.4" },
  
  
  
  { id: "S2-AI488", subject: 2, source: "ai", type: "single", question: "ISO 14064-2:2019 自願減量專案標準中，對監測（Monitoring）之要求為何？", options: ["無須監測", "應制定並執行監測計畫，定期收集專案排放量及減量數據", "僅初始監測", "僅末期監測"], answer: 1, explanation: "ISO 14064-2:2019要求自願減量專案應制定監測計畫（Monitoring Plan），規範監測參數、監測方法、監測頻率及數據記錄方式，並按計畫定期執行監測，以確保減量數據之正確性及可查證性。", verified: true, chapter: "2.1" },
  
  { id: "S2-AI490", subject: 2, source: "ai", type: "single", question: "溫室氣體盤查中，排放量計算結果之「不確定性範圍」應如何表達？", options: ["不須表達", "以±百分比或區間表示（如±10%），並說明其統計信賴水準", "僅以文字描述", "以固定值表示"], answer: 1, explanation: "不確定性範圍通常以百分比（如±15% @ 95%信賴水準）或區間（如10-12噸CO2e）方式表達，並應說明不確定性評估之方法（如蒙地卡羅模擬、誤差傳播法則）及主要不確定性來源。", verified: true, chapter: "3.1" },
  { id: "S2-AI491", subject: 2, source: "ai", type: "single", question: "SBTi中，「價值鏈外減量」（BVCM）與「淨零目標」之關係為何？", options: ["BVCM可替代淨零目標", "BVCM為自願性額外行動，企業仍須先達成價值鏈內減量目標", "BVCM為強制要求", "BVCM取代碳權使用"], answer: 1, explanation: "SBTi淨零標準明確區分：企業須先透過價值鏈內減量（Deep Decarbonization）達成SBT目標，BVCM為自願性額外行動（如購買碳權），用以加速全球減碳，但不能替代自身減量義務。", verified: true, chapter: "1.3" },
  
  
  { id: "S2-AI494", subject: 2, source: "ai", type: "single", question: "碳資產管理中，碳權「品質折扣」（Quality Discount）之概念為何？", options: ["碳權價格折扣", "對較低碳權品質（如高永久性風險）進行數量折扣，即每購買1單位僅計入0.5-0.8單位", "碳權數量折扣", "碳權效期折扣"], answer: 1, explanation: "碳權品質折扣係指因應碳權品質差異（如自然型碳匯之永久性風險），在碳會計上對低品質碳權之減量量予以折扣（如造林碳權每購買1噸僅計0.8噸），以反映其較高之不確定性或逆轉風險。", verified: true, chapter: "2.4" },
  
  { id: "S2-AI496", subject: 2, source: "ai", type: "single", question: "我國氣候變遷因應法中，碳費之法律性質為何？", options: ["稅捐", "規費（特別公課）", "罰金", "捐助"], answer: 1, explanation: "碳費之法律性質屬於「特別公課」（Special Levy）或「規費」性質，非一般稅捐。其特徵為專款專用於氣候變遷相關業務，且與特定之行政給付（排放許可、查驗等）相關聯。", verified: true, chapter: "1.1" },
  { id: "S2-AI497", subject: 2, source: "ai", type: "single", question: "GHG Protocol中，企業報告範疇一、二、三排放時，應使用之「報告單位」為何？", options: ["噸CO2", "公噸CO2e（二氧化碳當量）", "公斤CO2", "噸C（碳）"], answer: 1, explanation: "GHG Protocol要求所有溫室氣體排放量應以「公噸CO2e」（Metric Tons of CO2 Equivalent）為報告單位，即各種溫室氣體乘以其GWP值後加總之二氧化碳當量噸數。", verified: true, chapter: "3.1" },
  
  { id: "S2-AI499", subject: 2, source: "ai", type: "single", question: "我國碳費制度中，自主減量計畫應包含哪些基本內容？", options: ["僅減量目標", "基準年排放量、減量目標、指定削減率、減量措施及時程、監測計畫", "僅減量措施", "僅監測計畫"], answer: 1, explanation: "自主減量計畫應包含：1)基準年排放量及排放清冊；2)減量目標（含指定削減率）；3)減量措施及實施時程；4)預期減量效益；5)監測及查驗計畫；6)替代方案及風險因應措施。", verified: true, chapter: "1.1" },
  { id: "S2-AI500", subject: 2, source: "ai", type: "single", question: "企業在淨零轉型時代，碳管理人員應具備之核心職能為何？", options: ["僅財務分析", "碳盤查與會計、碳市場知識、法規遵循、策略規劃、風險管理及跨部門溝通能力", "僅法規知識", "僅碳盤查能力"], answer: 1, explanation: "碳管理人員核心職能：1)碳盤查（GHG Protocol/ISO 14064）；2)碳市場及碳權知識；3)氣候法規（氣候法、CBAM、碳費）；4)減碳策略規劃（SBT、淨零路徑）；5)碳風險管理；6)永續資訊揭露（TCFD、IFRS S2）；7)跨部門溝通及供應商管理能力。", verified: true, chapter: "2.4" },
  { id: "S2-AI501", subject: 2, source: "ai", type: "single", question: "某投資組合涵蓋三家公司：甲公司碳強度（tCO2e/百萬營收）為200、乙公司為350、丙公司為150。投資權重分別為40%、30%、30%。該組合的加權平均碳強度（WACI）為何？", options: ["230 tCO2e/百萬營收", "233 tCO2e/百萬營收", "250 tCO2e/百萬營收", "175 tCO2e/百萬營收"], answer: 0, explanation: "WACI=∑(投資權重×碳強度)=200×0.40+350×0.30+150×0.30=80+105+45=230 tCO2e/百萬營收。此為PCAF（碳會計金融合作夥伴）及TCFD建議之投資組合碳足跡揭露指標。", verified: true, chapter: "1.2" },
  { id: "S2-AI502", subject: 2, source: "ai", type: "single", question: "依照台灣氣候變遷因應法，碳費費率審議會的組成及決議機制，下列敘述何者正確？", options: ["由中央主管機關遴聘委員，採多數決方式決定費率", "費率由經濟部單獨核定", "費率需經立法院三讀通過", "費率由各縣市政府分別訂定"], answer: 0, explanation: "依氣候變遷因應法，碳費費率由中央主管機關（環境部）遴聘學者專家及民間團體組成碳費費率審議會，採多數決議定後報請行政院核定。選項2錯誤：非經濟部單獨核定。選項3錯誤：行政規則層級，無需立法院三讀。選項4錯誤：全國一致，非各縣市分別訂定。", verified: true, chapter: "1.1" },
  
  { id: "S2-AI504", subject: 2, source: "ai", type: "single", question: "某企業全年用電量15,000 MWh，簽署10年期物理PPA（購電合約），每年購入5,000 MWh再生能源，PPA價格每度2.8元，當地電網平均電價每度3.5元。請問簽署PPA後每年可節省之電費成本為何？", options: ["350萬元", "175萬元", "525萬元", "700萬元"], answer: 0, explanation: "年PPA購電量5,000 MWh=5,000,000 kWh。節省=(電網均價-PPA價格)×購電量=(3.5-2.8)×5,000,000=0.7×5,000,000=3,500,000元=350萬元。此為直接電費節省，不包含再生能源屬性價值及T-REC潛在收入。", verified: true, chapter: "2.4" },
  { id: "S2-AI505", subject: 2, source: "ai", type: "multiple", question: "某金屬加工廠年排放10,000 tCO2e，擬透過碳權購買達成碳中和宣告（PAS 2060:2014）。下列哪些為PAS 2060碳中和宣告的必要條件？", options: ["提交量化溫室氣體盤查報告，符合ISO 14064-1或GHG Protocol", "制定碳管理計畫，包含減量目標與時間表", "購買碳權抵銷100%殘餘排放", "碳中和宣告須經第三方認證機構查證"], answers: [0, 1, 2, 3], explanation: "PAS 2060:2014要求：①合格的溫室氣體盤查（A正確）；②制定碳管理計畫（B正確）；③抵銷所有殘餘排放（C正確）；④須經第三方獨立查證（D正確）。四項均為必要條件。", verified: true, chapter: "2.1" },
  
  
  { id: "S2-AI508", subject: 2, source: "ai", type: "single", question: "碳捕獲與封存(CCS)的三個主要步驟依序為何？", options: ["運輸→捕獲→封存", "捕獲→運輸→封存", "封存→捕獲→運輸", "捕獲→封存→運輸"], answer: 1, explanation: "CCS的三個主要步驟依序為：1)碳捕獲（自排放源或大氣中分離CO₂）、2)運輸（透過管線或船運將CO₂運至封存場址）、3)封存（將CO₂注入深部地質構造進行長期隔離）。", verified: true, chapter: "2.2" },
  { id: "S2-AI509", subject: 2, source: "ai", type: "single", question: "下列何者為燃燒後碳捕獲(Post-combustion Capture)的主要技術？", options: ["化學吸收法（以胺溶液吸收CO₂）", "富氧燃燒法", "化學迴圈燃燒法", "氣化前置分離法"], answer: 0, explanation: "燃燒後碳捕獲是從煙氣中分離CO₂，最成熟的技術為化學吸收法（使用胺類溶劑如MEA吸收CO₂後再加熱釋放）。富氧燃燒、化學迴圈燃燒屬於燃燒前或燃燒過程中的捕獲技術。", verified: true, chapter: "2.2" },
  { id: "S2-AI510", subject: 2, source: "ai", type: "single", question: "直接空氣捕獲(DAC)與傳統CCS的最大差異為何？", options: ["DAC直接從大氣中捕獲CO₂，CCS從排放源捕獲", "DAC成本低於CCS", "DAC技術已被廣泛商業化", "CCS不需要能源投入"], answer: 0, explanation: "DAC（Direct Air Capture）直接從大氣中捕獲CO₂（濃度約420 ppm），而CCS是從發電廠或工業製程等排放源的煙氣中捕獲（濃度可達5-15%）。由於大氣CO₂濃度極低，DAC的能耗與成本遠高於傳統CCS，目前成本約每噸100-300美元。", verified: true, chapter: "2.2" },
  { id: "S2-AI511", subject: 2, source: "ai", type: "single", question: "BECCS（生質能碳捕獲與封存）相較於一般CCS的額外優勢為何？", options: ["成本更低", "可實現能源生產過程中的負排放", "技術更成熟", "不需要地質封存"], answer: 1, explanation: "BECCS（Bioenergy with Carbon Capture and Storage）將生質能發電或製程產生的CO₂捕獲並封存。由於生質能在生長過程中吸收大氣CO₂，再加上CCS的封存效果，BECCS可實現能源生產過程中的「負排放」（即從大氣中淨移除CO₂）。IPCC多數1.5°C情境都高度依賴BECCS。", verified: true, chapter: "2.2" },
  { id: "S2-AI512", subject: 2, source: "ai", type: "multiple", question: "下列哪些屬於自然為基礎的碳匯解決方案(Nature-based Solutions)？", options: ["造林與再造林", "土壤碳匯管理（覆蓋作物、免耕法）", "紅樹林與海草床復育", "直接空氣捕獲(DAC)"], answers: [0, 1, 2], explanation: "自然為基礎的碳匯方案包括：造林與再造林（增加森林碳匯）、土壤碳匯管理（透過覆蓋作物、免耕法、生物炭等增加土壤有機碳）、藍碳生態系復育（紅樹林、海草床、鹽沼）。DAC屬於工程技術型負排放，非自然為基礎方案。", verified: true, chapter: "2.2" },
  { id: "S2-AI513", subject: 2, source: "ai", type: "single", question: "「藍碳」(Blue Carbon)指的是下列哪一種碳匯？", options: ["海洋中的溶解無機碳", "紅樹林、海草床、鹽沼等沿海生態系所固定的碳", "深海沉積物中的有機碳", "浮游植物光合作用固定的碳"], answer: 1, explanation: "藍碳專指紅樹林、海草床、鹽沼等海岸帶生態系所捕獲與儲存的碳。這些生態系雖然面積僅佔全球海洋面積不到0.5%，但其碳儲存速率與單位面積碳儲量遠高於陸域森林。保護與復育藍碳生態系是重要的自然碳匯策略。", verified: true, chapter: "2.2" },
  { id: "S2-AI514", subject: 2, source: "ai", type: "single", question: "全球碳捕獲與封存(CCS)最主要的CO₂封存方式為何？", options: ["海洋封存（注入深海）", "地質封存（注入深部鹽水層或枯竭油氣層）", "礦物碳化封存", "森林碳匯封存"], answer: 1, explanation: "地質封存是目前CCS最主要的封存方式，將CO₂注入深部鹽水層（Deep Saline Aquifers）或枯竭油氣層（Depleted Oil/Gas Reservoirs），深度通常在800-2500公尺以下，透過物理與化學機制將CO₂永久封存於地層中。", verified: true, chapter: "2.2" },
  { id: "S2-AI515", subject: 2, source: "ai", type: "single", question: "IPCC AR6評估報告中，多數1.5°C路徑對負排放技術(CDR)的依賴程度如何？", options: ["完全不依賴CDR", "高度依賴CDR，每年需移除數十億噸CO₂", "僅依賴森林碳匯", "CDR僅作為備選方案"], answer: 1, explanation: "IPCC AR6評估報告顯示，在多數1.5°C與2°C路徑中，碳移除技術(CDR)扮演關鍵角色。到2100年，累積碳移除量需達到數百至數千億噸CO₂。主要CDR技術包括造林、BECCS、DACCS（DAC+CCS）等。", verified: true, chapter: "2.2" },
  { id: "S2-AI516", subject: 2, source: "ai", type: "single", question: "土壤碳匯的主要機制為何？", options: ["土壤微生物將有機質轉化為穩定有機碳", "土壤吸附大氣中的CO₂", "土壤礦物與CO₂進行化學反應", "土壤水分溶解CO₂"], answer: 0, explanation: "土壤碳匯的核心機制是植物殘體與根系分泌物經由土壤微生物作用，轉化為穩定的土壤有機質(Soil Organic Matter, SOM)，以有機碳形式長期儲存於土壤中。農業管理措施如覆蓋作物、有機質添加、減少翻耕等可增加土壤有機碳含量。", verified: true, chapter: "2.2" },
  { id: "S2-AI517", subject: 2, source: "ai", type: "multiple", question: "下列哪些是常見的碳移除(CDR)技術？", options: ["造林與再造林(Afforestation/Reforestation)", "直接空氣捕獲與封存(DACCS)", "生質能碳捕獲與封存(BECCS)", "提高再生能源占比"], answers: [0, 1, 2], explanation: "碳移除(CDR)技術指從大氣中主動移除CO₂的技術與方法，包括：造林/再造林、DACCS（直接空氣捕獲+地質封存）、BECCS（生質能+CCS）、增強風化(Enhanced Weathering)、海洋鹼化、生物炭等。提高再生能源占比屬於減排措施，非碳移除。", verified: true, chapter: "2.2" },
  { id: "S2-AI518", subject: 2, source: "ai", type: "single", question: "台灣推動自然碳匯的主要場域為何？", options: ["工業區綠化", "國有林地造林與紅樹林復育", "都市公園", "屋頂綠化"], answer: 1, explanation: "台灣自然碳匯推動重點在於國有林地造林（增加森林碳匯）、紅樹林復育（增加藍碳碳匯）及農業土壤碳匯管理。農業部已提出森林碳匯、土壤碳匯與海洋碳匯三大自然碳匯推動策略。", verified: true, chapter: "2.2" },
  { id: "S2-AI519", subject: 2, source: "ai", type: "single", question: "增強風化(Enhanced Weathering)作為碳移除技術的原理為何？", options: ["將岩石磨碎撒佈於土地，加速與CO₂的化學反應形成碳酸鹽", "利用風力將CO₂吹入海洋深層", "以高溫將岩石中的碳釋出", "利用植物根系與岩石作用固定碳"], answer: 0, explanation: "增強風化(Enhanced Weathering)是將矽酸鹽礦物（如橄欖石、輝石）磨碎成細粉，撒佈於農田或海岸，加速礦物與大氣CO₂的自然風化反應，將CO₂轉化為穩定的溶解重碳酸鹽或固體碳酸鹽。此技術可同時改善土壤健康。", verified: true, chapter: "2.2" },
  { id: "S2-AI520", subject: 2, source: "ai", type: "single", question: "海洋鹼化(Ocean Alkalinization)增加碳匯的原理為何？", options: ["降低海水酸度使其吸收更多CO₂", "增加海洋浮游植物數量", "提高海水溫度促進CO₂溶解", "將CO₂直接注入海底"], answer: 0, explanation: "海洋鹼化是將鹼性物質（如石灰石、橄欖石）加入海洋，增加海水的鹼度與緩衝能力，使海洋能吸收更多大氣CO₂而不會過度酸化。增加的鹼度將CO₂轉化為穩定的重碳酸鹽(HCO₃⁻)，可長期儲存於海洋中。", verified: true, chapter: "2.2" },
  { id: "S2-AI521", subject: 2, source: "ai", type: "single", question: "生物炭(Biochar)作為碳移除技術的主要優勢為何？", options: ["生產成本極低", "可同時改善土壤品質且碳穩定性高", "不需要任何設備", "碳儲存效果永久不變"], answer: 1, explanation: "生物炭是將生質物在缺氧條件下高溫熱解製成的富碳固體物質。其優勢包括：碳穩定性高（可維持數百年至數千年不分解）；同時改善土壤物理化學性質（增加保水、保肥能力）；可作為土壤改良劑。", verified: true, chapter: "2.2" },
  { id: "S2-AI522", subject: 2, source: "ai", type: "single", question: "目前全球營運中最大的DAC設施使用何種技術？", options: ["Climeworks的固體吸附劑DAC技術", "Carbon Engineering的液態溶劑DAC技術", "Global Thermostat的混合DAC技術", "高溫電化學分離技術"], answer: 0, explanation: "冰島的Climeworks「Orca」及「Mammoth」設施是目前全球最大的營運中DAC設施，使用固體吸附劑（以溫度變化進行吸附/脫附循環）直接從大氣捕獲CO₂，捕獲後的CO₂由冰島Carbfix公司注入玄武岩進行礦物碳化永久封存。", verified: true, chapter: "2.2" },
  { id: "S2-AI523", subject: 2, source: "ai", type: "single", question: "碳封存的「洩漏風險」(Leakage Risk)主要來自何種機制？", options: ["封存層壓力過高導致CO₂經由斷層或裂縫逸散", "CO₂溶解於地下水中被帶出", "封存層的溫度過高", "微生物分解CO₂產生甲烷"], answer: 0, explanation: "地質封存的主要洩漏風險來自封存層壓力升高，使CO₂經由既有斷層、裂縫或廢棄井孔逸散至地表或淺層地下水。完善的封存場址需具備蓋層的低滲透性、地質構造的封閉性、以及長期的監測計畫。", verified: true, chapter: "2.2" },
  { id: "S2-AI524", subject: 2, source: "ai", type: "multiple", question: "下列哪些是影響碳移除(CDR)技術成本的主要因素？", options: ["技術成熟度與規模經濟", "能源價格", "碳定價政策", "地理條件與資源可用性"], answers: [0, 1, 2, 3], explanation: "CDR技術成本受多重因素影響：技術成熟度（DACCS成本最高但目前降幅最快）；規模經濟（大型設施可降低單位成本）；能源價格（多數CDR需大量能源投入）；碳定價政策（較高的碳價可激勵CDR投資）；地理條件（地質儲存容量、太陽能/風能資源等）。以上皆是。", verified: true, chapter: "2.2" },
  { id: "S2-AI525", subject: 2, source: "ai", type: "single", question: "國際能源總署(IEA)淨零路徑中，CCUS在2050年的全球CO₂捕獲量目標約為多少？", options: ["每年1億噸", "每年約76億噸", "每年5,000萬噸", "每年1,000億噸"], answer: 1, explanation: "IEA的Net Zero by 2050路徑中，CCUS的全球捕獲量需從目前的約4,000-5,000萬噸/年大幅提升至2050年的約76億噸/年（7.6 GtCO₂/year），成長超過150倍。", verified: true, chapter: "2.2" },
  { id: "S2-AI526", subject: 2, source: "ai", type: "single", question: "IPCC將各種碳移除技術按照成熟度分類時，下列哪項技術被歸類為「已商業化」等級？", options: ["直接空氣捕獲(DAC)", "造林與再造林", "增強風化", "海洋施肥"], answer: 1, explanation: "IPCC AR6分類中，造林與再造林被歸類為最高成熟度「已商業化(Commercially Available)」等級。BECCS與生物炭歸類為「示範階段(Demonstration)」，DAC與增強風化歸類為「先導/原型階段(Pilot/Prototype)」等級。", verified: true, chapter: "2.2" },
  { id: "S2-AI527", subject: 2, source: "ai", type: "single", question: "碳權專案的「外加性」(Additionally)論證主要目的是為了證明什麼？", options: ["該專案產生的碳權價格具有市場競爭力", "若無碳權收入該專案將不會發生，因此真正實現了額外減排", "該專案採用最先進的減碳技術", "該專案已經獲得政府補助"], answer: 1, explanation: "外加性(Additionally)是碳權專案最基本的篩選標準，旨在證明若無碳權(Certified Emission Reductions)的額外收入，該減排專案將因財務不可行或其他障礙而不會發生。只有具備外加性的專案才能確保碳權代表真正的、額外的減排量。", verified: true, chapter: "2.1" },
  { id: "S2-AI528", subject: 2, source: "ai", type: "single", question: "CDM機制下的tCER與lCER兩類排放減量憑證的主要差異為何？", options: ["tCER為暫時性憑證用於造林專案，lCER為長期憑證用於再生能源專案", "tCER用於非碳匯專案，lCER用於碳匯專案且到期需替換", "tCER有效期5年，lCER有效期20-30年", "tCER與lCER皆為永久性減量憑證"], answer: 2, explanation: "tCER（Temporary CER）及lCER（Long-term CER）是CDM針對造林與再造林(A/R)碳匯專案發行的兩類暫時性減量憑證。tCER有效期至該承諾期結束（約5年），lCER有效期20-30年或至專案結束，到期後均需由新的減量單位替換，因為森林碳匯存在非永久性風險。", verified: true, chapter: "2.1" },
  { id: "S2-AI529", subject: 2, source: "ai", type: "multiple", question: "Verra(VCS)與Gold Standard(GS)兩大自願碳市場標準的主要差異包括哪些？", options: ["VCS涵蓋較多類別的專案方法學，GS較專注於永續發展效益", "GS要求專案必須在SDGs方面有具體貢獻，VCS無此強制要求", "VCS發行的VCUs價格通常高於GS的GSVERs", "GS不允許REDD+類型的森林碳匯專案"], answers: [0, 1, 3], explanation: "Verra VCS是最大的自願碳市場標準，方法學涵蓋範圍廣（包括REDD+等森林碳匯），但對永續發展效益無強制要求。Gold Standard由WWF等NGO發起，要求專案必須證明對SDGs的具體貢獻，但不允許REDD+類型的避免毀林專案。VCUs因REDD+供應量大，價格通常低於GSVERs而非更高。", verified: true, chapter: "2.1" },
  { id: "S2-AI530", subject: 2, source: "ai", type: "single", question: "台灣《溫室氣體減量及管理法》下的「先期專案」與「抵換專案」機制主要差異為何？", options: ["先期專案適用於已發生之自願減量行為，抵換專案須經註冊後執行", "先期專案僅限於能源部門，抵換專案適用所有部門", "先期專案可產生碳權用於交易，抵換專案不可交易", "先期專案不需額外性論證，抵換專案需額外性論證"], answer: 0, explanation: "先期專案(Pre-period Project)針對2005-2015年間已實施的自願減量措施進行認可，屬於回溯性認證；抵換專案(Offset Project)則是需先向主管機關註冊申請後開始執行減量措施，屬於前瞻性專案。兩者均需外加性論證，產生的減量額度均可交易。", verified: true, chapter: "2.1" },
  { id: "S2-AI531", subject: 2, source: "ai", type: "single", question: "碳權的「Vintage」概念指的是什麼？", options: ["碳權的價格等級", "碳權專案產生減排量的年份", "碳權的認證標準版本", "碳權的到期日"], answer: 1, explanation: "Vintage（年份）指的是一噸碳權所對應的溫室氣體減排或移除實際發生的年份。例如一個2022年運轉的風電專案，其2022年發電產生的減排量就是Vintage 2022的碳權。Vintage對於確保碳權的時間附加性及避免雙重計算至關重要。", verified: true, chapter: "2.1" },
  { id: "S2-AI532", subject: 2, source: "ai", type: "single", question: "CDM的Baseline and Monitoring Methodology主要功能為何？", options: ["計算碳權的市場價格", "建立排放基線並監測專案實際減排量", "評估專案對當地經濟的影響", "認證碳權交易平台的可靠性"], answer: 1, explanation: "CDM的基線與監測方法學(Baseline and Monitoring Methodology)提供標準化方式來：1)建立沒有該專案情況下的排放基線(Baseline Scenario)；2)監測專案實際排放量；3)計算基線與實際排放量的差值即為減排量。這是確保碳權準確計算的核心技術文件。", verified: true, chapter: "2.1" },
  { id: "S2-AI533", subject: 2, source: "ai", type: "single", question: "EU ETS第四階段(Phase IV, 2021-2030)的線性減排因子(LRF)數值為何？", options: ["每年1.74%", "每年2.2%", "每年4.3%", "每年2.5%"], answer: 1, explanation: "EU ETS第四階段的線性減排因子(Linear Reduction Factor, LRF)從第二、三階段的1.74%提高至2.2%，意即每年排放總上限減少2.2%。2024年起配合Fit for 55政策，LRF進一步提高至4.3%以加速減排。", verified: true, chapter: "2.3" },
  { id: "S2-AI534", subject: 2, source: "ai", type: "multiple", question: "CORSIA（國際航空碳抵換及減排方案）的相關規定包括哪些？", options: ["2021年起所有國際航班皆需購買碳權抵銷排放", "採用「基準線與成長」模式，超出基準線的排放需購買碳權抵銷", "僅適用於各國自願參與的航段", "允許使用BECCS或DAC等工程碳移除技術產生的碳權"], answers: [1, 2], explanation: "CORSIA(Carbon Offsetting and Reduction Scheme for International Aviation)採用基準線與成長模式，僅要求超出2020年基準線排放量的部分需購買碳權抵銷。第一階段(2024-2026)及第二階段(2027-2035)皆屬自願參與性質。CORSIA對碳權的合格標準包括：不得使用REDD+類型碳權。", verified: true, chapter: "2.3" },
  { id: "S2-AI535", subject: 2, source: "ai", type: "single", question: "ICVCM（自願碳市場誠信委員會）發布的CCP（核心碳原則）中，對碳權品質的核心要求為何？", options: ["碳權價格不得低於某最低價格門檻", "碳權必須通過外加性、永久性、避免雙重計算等10項原則審查", "碳權僅限於自然為基礎的專案", "碳權發行量每年不得超過全球需求"], answer: 1, explanation: "ICVCM(Integrity Council for the Voluntary Carbon Market)發布的CCP(Core Carbon Principles)包含10項核心原則，涵蓋：治理(額外性、第三方驗證等)、排放影響(永久性、避免雙重計算等)、及永續發展(對SDGs貢獻等)三大面向。通過CCP評估標籤的碳權被視為高品質碳權。", verified: true, chapter: "2.3" },
  { id: "S2-AI536", subject: 2, source: "ai", type: "multiple", question: "影響碳權市場價格的主要因素包括哪些？", options: ["碳權的Vintage年份與專案類型", "國際碳定價政策與CORSIA等需求的影響", "碳權認證標準的嚴格程度", "發行碳權國家的政治穩定性"], answers: [0, 1, 2, 3], explanation: "碳權價格受多重因素影響：1)Vintage年份（較新的碳權價格較高）；2)專案類型（工程型如再生能源通常低於自然型如REDD+）；3)認證標準（Gold Standard通常有溢價）；4)需求面政策（如CORSIA合格碳權有較高需求）；5)發行國的政治風險與治理品質。以上皆是。", verified: true, chapter: "2.3" },
  { id: "S2-AI537", subject: 2, source: "ai", type: "single", question: "台灣碳權交易所的主要功能為何？", options: ["僅提供碳權交易撮合平台", "提供碳權交易、碳諮詢及人才培育、國際碳權採購服務", "負責審查碳權專案的額外性", "制定台灣的碳定價政策"], answer: 1, explanation: "台灣碳權交易所（2023年8月成立）由台灣證券交易所出資成立，主要功能包括：1)提供碳權交易撮合平台（已於2023年底啟動國際碳權交易）；2)提供碳諮詢服務與人才培育；3)協助國內企業採購國際碳權。碳權審查則由環境部負責。", verified: true, chapter: "2.3" },
  { id: "S2-AI538", subject: 2, source: "ai", type: "single", question: "EU ETS中的市場穩定儲備(MSR)機制的主要功能為何？", options: ["設定碳權的最低價格", "調節市場流通的配額總量以穩定碳價", "分配免費配額給各會員國", "審查碳抵消專案的合格性"], answer: 1, explanation: "市場穩定儲備(Market Stability Reserve, MSR)是EU ETS的供需調節機制，當市場流通配額總數超過一定門檻時自動吸收多餘配額存入儲備；當配額短缺時釋放配額至市場。MSR自2019年實施後有效支撐了EUA碳價的上漲趨勢。", verified: true, chapter: "2.3" },
  { id: "S2-AI539", subject: 2, source: "ai", type: "single", question: "歐盟碳邊境調整機制(CBAM)中，碳排放的計算基準為何？", options: ["進口國（生產國）的實際排放強度", "歐盟境內同類產品的平均排放強度", "全球同類產品的平均排放強度", "進口國歷史排放數據"], answer: 0, explanation: "CBAM(Carbon Border Adjustment Mechanism)以進口產品的實際碳排放量（由進口國生產者申報）為計算基準。若生產者無法提供可信的實際排放數據，則使用該出口國的默認值（default value）。CBAM要求進口商購買CBAM憑證，價格對應EU ETS碳價。", verified: true, chapter: "2.3" },

  { id: "S2-AI540", subject: 2, source: "ai", type: "single", question: "臺灣碳費制度中，「自願減量專案額度」在碳費扣抵時需適用1.2倍抵換比例。此機制之核心政策目的為何？", options: ["鼓勵企業購買更多碳權以活絡碳交易市場", "反映自願減量額度相較於直接減排之不確定性，確保碳費制度整體環境效益", "增加政府碳費收入以支應氣候變遷調適經費", "符合國際碳市場1.2倍之統一折抵標準"], answer: 1, explanation: "自願減量專案額度適用1.2倍抵換比例，係因該類碳權之減量成效存在較高不確定性（如外加性、永久性、洩漏等風險），相較於企業直接進行減排或使用國內抵換專案額度之環境效益較低。透過1.2倍比例折抵（即每1噸額度僅可抵減0.833噸碳費計費排放量），可確保碳費制度之整體環境完整性，並引導企業優先進行實質減量而非僅購買碳權。", verified: true, chapter: "2.1" },

  { id: "S2-AI541", subject: 2, source: "ai", type: "single", question: "某碳費徵收對象經查獲以不正當方式短報碳費計算資料，依《氣候變遷因應法》第59條，下列何者為其直接面臨之法定處罰？", options: ["處新臺幣20萬元以上200萬元以下罰鍰，並通知限期改善", "按兩倍費率計算應繳費額，並得追繳最近五年內應繳費額加計利息", "處新臺幣10萬元以上100萬元以下罰鍰，並限制或停止交易", "按每公噸超額量處碳市場價格三倍之罰鍰，以每公噸新臺幣1,500元為上限"], answer: 1, explanation: "依《氣候變遷因應法》第59條，以不正當方式短報或漏報碳費計算資料者，按兩倍費率計算應繳費額，並得追繳最近五年內應繳費額加計利息。選項0為不實盤查/登錄之處罰（20-200萬）；選項2為排放/減量額度交易違規之處罰（10-100萬＋停止交易）；選項3為排放額度不足（超排）之處罰（碳價×3倍，上限1,500元/噸）。各類違規行為對應之罰則差異甚大，應精確區分。", verified: true, chapter: "1.1" },

  { id: "S2-AI542", subject: 2, source: "ai", type: "multiple", question: "依《氣候變遷因應法》，下列哪些違規行為之處罰為「新臺幣20萬元以上200萬元以下罰鍰，並得通知限期改善；情節重大者得令其停止操作、停工或停業」？", options: ["企業以不正當方式短報或漏報碳費計算資料", "企業盤查或登錄程序違規", "企業拒絕或妨礙中央主管機關之查核", "企業進行不實之溫室氣體盤查或登錄"], answers: [2, 3], explanation: "依《氣候變遷因應法》罰則規定：不實盤查/登錄（選項3）及拒絕/妨礙查核（選項2）處20-200萬元罰鍰，情節重大得令停工/停業/停交易。選項0短報漏報碳費之罰則為按兩倍費率計算並追繳五年；選項1盤查登錄程序違規則處10-100萬元。各類違規行為之罰鍰額度與後果差異顯著，屬中級考試命題重點。", verified: true, chapter: "1.1" },
];